-- Poems batch 295
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('de1aaec3-8762-4bdd-b48d-4eb66e7942b2','琅邪山','王禹偁','宋','宋诗','song-poetry','','[]','連袤復岧嶢，峰巒架泬寥。',120,'全唐诗/poet.song.3000.json','["連袤復岧嶢，峰巒架泬寥。", "流名自東晉，積翠滿南譙。", "洞碧通仙界，溪明潤藥苗。", "古臺臨海日，絕頂見江潮。", "杉影拏雲暗，泉聲出竹遥。", "廟碑傳漢祖，寺額認唐朝。", "旱歲時霑稼，靈蹤合禁樵。", "詩章因我盛，屏障遣誰描。", "近住人多秀，頻登酒易銷。", "圖經標八絕，灊霍合相饒。"]'),
('f51c6171-0ac1-41d1-b3c2-e082b0ea40c0','爲郡','王禹偁','宋','宋诗','song-poetry','','[]','爲郎爲郡意何闌，羞拂朝纓蓋病顔。',64,'全唐诗/poet.song.3000.json','["爲郎爲郡意何闌，羞拂朝纓蓋病顔。", "賜筆任分雙管赤，梳頭已是二毛斑。", "道孤自合先歸隠，俸薄無由便買山。", "出坐兩衙皆勉强，此心長在水雲間。"]'),
('13a3ded0-13e9-4b0d-818c-4af98735c6ff','自笑','王禹偁','宋','宋诗','song-poetry','','[]','年來失職別金鑾，身世漂淪鬢髮殘。',64,'全唐诗/poet.song.3000.json','["年來失職別金鑾，身世漂淪鬢髮殘。", "貧藉俸錢猶典郡，老爲郎吏是何官。", "開樽暫喜愁腸破，堆案仍勞病眼看。", "自笑不歸田里去，謾將名姓掛朝端。"]'),
('ab048874-0e29-4a97-8d62-4f22e1896672','自問','王禹偁','宋','宋诗','song-poetry','','[]','自問意何如，身窮業有餘。',48,'全唐诗/poet.song.3000.json','["自問意何如，身窮業有餘。", "卷懷君子道，耽味古人書。", "月給非無酒，晨羞亦有魚。", "山頭刺史宅，未替是吾廬。"]'),
('b8f47f85-e366-4ace-9c7f-2c80238ca4e7','夜長','王禹偁','宋','宋诗','song-poetry','','[]','後樓前閤互嚴更，年鬢侵人睡漸輕。',64,'全唐诗/poet.song.3000.json','["後樓前閤互嚴更，年鬢侵人睡漸輕。", "病眼已甘書冊廢，愁腸猶取酒杯傾。", "風摇紙帳燈花碎，月照銅壺漏水清。", "吟盡舊詩猶展轉，百迴移枕未天明。"]'),
('62a61c9c-a934-4a63-90ce-835ed5111545','與嘉祐同游寶應寺','王禹偁','宋','宋诗','song-poetry','','[]','滁陽領郡經三月，寶應遊山始一迴。',64,'全唐诗/poet.song.3000.json','["滁陽領郡經三月，寶應遊山始一迴。", "屐齒免憂巖下折，簿書長苦案頭堆。", "潾潾泉石吟魂健，漠漠烟嵐病眼開。", "盡日引渠尋勝境，讀碑看篆掃蒼苔。"]'),
('2d26fd36-760a-426f-9891-f89823a94ce0','迂儒','王禹偁','宋','宋诗','song-poetry','','[]','自笑是迂儒，誠宜與世疏。',48,'全唐诗/poet.song.3000.json','["自笑是迂儒，誠宜與世疏。", "左遷猶上疏，薄俸亦抄書。", "漠漠花侵眼，蕭蕭髮映梳。", "唯當早休去，幽處卜吾廬。"]'),
('648b126c-c381-4bda-9883-3649b7130591','花鹿','王禹偁','宋','宋诗','song-poetry','','[]','花鹿一何馴，長隨病使君。',48,'全唐诗/poet.song.3000.json','["花鹿一何馴，長隨病使君。", "必教吾在野，當與爾爲羣。", "靜飲清溪水，閑眠碧洞雲。", "猶勝市朝裏，逐衆走紛紛。"]'),
('e583de70-3a18-45d6-907f-39c96bde61eb','今冬','王禹偁','宋','宋诗','song-poetry','','[]','休思官職落青雲，且算今冬養病身。',64,'全唐诗/poet.song.3000.json','["休思官職落青雲，且算今冬養病身。", "白紙糊窗堪聽雪，紅爐著火別藏春。", "旋篘官醖漂浮蟻，時取溪魚削白鱗。", "況是豐年公事少，爲郎爲郡似閑人。"]'),
('7fe46c14-28e1-4c9c-ae95-fd8f4de10701','滁上謫居  其一','王禹偁','宋','宋诗','song-poetry','','[]','跡去金鑾殿，官移玉筍班。',48,'全唐诗/poet.song.3000.json','["跡去金鑾殿，官移玉筍班。", "才高寧免妬，命薄不如閑。", "曉鑑悲華髮，春醪慰病顔。", "爲郎身漸老，自笑不歸山。"]'),
('2bc4c106-33f5-47e9-a44d-4d5923dec849','滁上謫居  其二','王禹偁','宋','宋诗','song-poetry','','[]','跡忝詞林舊，官爲郎署卑。',48,'全唐诗/poet.song.3000.json','["跡忝詞林舊，官爲郎署卑。", "同羣甘鳥獸，苟祿爲妻兒。", "未有一事立，空驚雙鬢衰。", "唯憐文集裏，添得謫官詩。"]'),
('352c7615-50b2-48ca-943b-f300709338ac','滁上謫居  其三','王禹偁','宋','宋诗','song-poetry','','[]','敢歎我命薄，所嗟吾道消。',48,'全唐诗/poet.song.3000.json','["敢歎我命薄，所嗟吾道消。", "謫官淮上老，京信日邊遥。", "巧宦或五鼎，甘貧唯一瓢。", "居然古人事，名跡詎相饒。"]'),
('594e6f5d-aaa8-4aa7-828c-497e4b21bb39','滁上謫居  其四','王禹偁','宋','宋诗','song-poetry','','[]','一日復一日，悠悠任此生。',48,'全唐诗/poet.song.3000.json','["一日復一日，悠悠任此生。", "所悲頻謫宦，不是厭專城。", "有悔皆因祿，無凶未若耕。", "林泉何處好，終卜挂吾纓。"]'),
('69314bdb-9dfb-4ddd-9248-7583c25494d1','戲題二章述滁州官況寄翰林舊同院  其一','王禹偁','宋','宋诗','song-poetry','','[]','要知滁上興如何，養拙偷安幸亦多。',64,'全唐诗/poet.song.3000.json','["要知滁上興如何，養拙偷安幸亦多。", "小郡既無衣襖使，豐年兼有袴襦歌。", "公餘處處携山屐，官醖時時泛海螺。", "病眼白頭唯醉睡，朝廷好事不聞他。"]'),
('7e284092-abf2-46e5-8d09-2fc68bdee4ea','戲題二章述滁州官況寄翰林舊同院  其二','王禹偁','宋','宋诗','song-poetry','','[]','要見滁州謫宦情，信緣隨俗且營營。',64,'全唐诗/poet.song.3000.json','["要見滁州謫宦情，信緣隨俗且營營。", "不誇兩制詞臣貴，多伴三班奉職行。", "樓堞倚空乘月上，樽罍有酒對山傾。", "昇沉得喪何須問，況是浮生已半生。"]'),
('3bd6a811-56c2-407b-948b-72cb6a125411','高閑','王禹偁','宋','宋诗','song-poetry','','[]','謫官滁上欲何爲，唯把高閑度歲時。',64,'全唐诗/poet.song.3000.json','["謫官滁上欲何爲，唯把高閑度歲時。", "費盡俸錢因合藥，忙於公事是吟詩。", "京中吏去慵傳信，江外僧來與撰碑。", "更待吾家婚嫁了，解龜休致未全遲。"]'),
('2c5ca6ae-4dd2-4a58-a3a2-ae80617835a5','臘月','王禹偁','宋','宋诗','song-poetry','','[]','臘月滁州始覺寒，年豐歲暮郡齋閑。',64,'全唐诗/poet.song.3000.json','["臘月滁州始覺寒，年豐歲暮郡齋閑。", "官供好酒何憂雪，天與新詩合看山。", "日照野塘梅欲綻，燒迴荒逕草猶斑。", "吏人散後無公事，門戟森森夕鳥還。"]'),
('fbb2a41e-34f1-4a6f-9382-e193d59b9f37','雪中看梅花因書詩酒之興','王禹偁','宋','宋诗','song-poetry','','[]','冬來滁上興何長，唯把吟情入醉鄉。',64,'全唐诗/poet.song.3000.json','["冬來滁上興何長，唯把吟情入醉鄉。", "雪片引詩勝玉帛，梅花勸酒似嬪嬙。", "凝眸未厭頻頻落，擁鼻還憐細細香。", "謫宦老郎無一物，清貧猶且放懷狂。"]'),
('579607ec-754c-42f5-a676-95ec2a46be97','朝簪','王禹偁','宋','宋诗','song-poetry','','[]','一戴朝簪已十年，半居謫宦半榮遷。',64,'全唐诗/poet.song.3000.json','["一戴朝簪已十年，半居謫宦半榮遷。", "壯心無復思行道，病眼唯堪學坐禪。", "醉謝陶公長欠酒，俸慚吾祖不言錢。", "白頭郎署成何事，見擬休官自種田。"]'),
('bd2a9037-998d-4c1a-8de6-1bf0e55b87fa','賀呂祐之諫議','王禹偁','宋','宋诗','song-poetry','','[]','鳳閣前年陪步武，麟臺昔日是交游。',64,'全唐诗/poet.song.3000.json','["鳳閣前年陪步武，麟臺昔日是交游。", "先歸內署身雖忝，直上高坡命更優。", "玉筍外郎全棄擲，土山果毅免經由。", "却應迴笑滁陽守，官似馮唐半白頭。"]'),
('25ded3a6-3d7b-438a-a741-76de4cc26a51','賀馮起張秉二舍人','王禹偁','宋','宋诗','song-poetry','','[]','八年東觀知深屈，百日南床祇暫經。',64,'全唐诗/poet.song.3000.json','["八年東觀知深屈，百日南床祇暫經。", "春暖並吟紅藥樹，雲開雙見紫微星。", "繡衣脫後休持斧，珠履拋來免過廳。", "應念出官淮水上，被人還笑屈原醒。"]'),
('efe042c0-eb95-4bc2-8f92-1bc3b8596256','送都官梁員外同年之江南轉運','王禹偁','宋','宋诗','song-poetry','','[]','月宮同歲取丹枝，次第飛翔侍玉墀。',64,'全唐诗/poet.song.3000.json','["月宮同歲取丹枝，次第飛翔侍玉墀。", "出職未吟紅藥樹，轉官新入白雲司。", "使權繁重雖無暇，曹局清閑合賦詩。", "不似謫官淮水上，鬢毛衰颯詠江蘺。"]'),
('05b17eaf-ea40-4355-accf-2817bbea954c','有傷','王禹偁','宋','宋诗','song-poetry','','[]','壁上時牌催晝夜，案頭朝報見存亡。',64,'全唐诗/poet.song.3000.json','["壁上時牌催晝夜，案頭朝報見存亡。", "懸車又喪司空相，延閣新薨賈侍郎。", "陶鑄官資經化筆，品題名姓在文場。", "繐帷一慟無由得，徒洒春風淚數行。"]'),
('456f7163-fe6c-41e6-bdac-87a5edb192d3','寄杭州西湖昭慶寺華嚴社主省常上人','王禹偁','宋','宋诗','song-poetry','','["\u897f\u6e56"]','夢幻吾身是偶然，勞生四十又三年。',64,'全唐诗/poet.song.3000.json','["夢幻吾身是偶然，勞生四十又三年。", "任誇西掖吟紅藥，何似東林種白蓮。", "入定雪龕燈焰直，講經霜殿磬聲圓。", "謫官不得餘杭郡，空寄高僧結社篇。"]'),
('a8c5f9f2-2ee5-421f-9200-706b8a45c464','送鄭褒歸閩中','王禹偁','宋','宋诗','song-poetry','','[]','褒也甌閩士，文高行益修。',48,'全唐诗/poet.song.3000.json','["褒也甌閩士，文高行益修。", "干名逢詔罷，歸計逼親憂。", "鷗鳥終相狎，公卿謾欲留。", "刺桐花下宅，蘭蕨奉晨羞。"]'),
('479e5387-a6e9-471b-b0fb-68a3d17ea9ce','贈王巘','王禹偁','宋','宋诗','song-poetry','','[]','舉子竟文賦，風騷委路塵。',48,'全唐诗/poet.song.3000.json','["舉子竟文賦，風騷委路塵。", "吾宗多警句，詩道未無人。", "青眼有誰是，白頭空鑷頻。", "賈生如再召，爲爾指迷津。"]'),
('7362e444-f4d8-4f45-835a-00698c65ee43','病假','王禹偁','宋','宋诗','song-poetry','','[]','小郡雖無事，常時亦有勞。',48,'全唐诗/poet.song.3000.json','["小郡雖無事，常時亦有勞。", "坐衙衫强著，判案筆須操。", "眼病因求假，身閑更覺高。", "何當長似此，歸去老蓬蒿。"]'),
('35e2f311-1672-41f6-b0f7-6ac1ea990c9d','偶題三首  其一','王禹偁','宋','宋诗','song-poetry','','[]','賈誼因才逐，桓譚以讖疏。',24,'全唐诗/poet.song.3000.json','["賈誼因才逐，桓譚以讖疏。", "古今常似此，吾道竟何如。"]'),
('4bb07321-5324-4e5d-aa71-d0124328b7bc','偶題三首  其二','王禹偁','宋','宋诗','song-poetry','','[]','鄭興親未葬，張籍眼多昏。',24,'全唐诗/poet.song.3000.json','["鄭興親未葬，張籍眼多昏。", "何時解印綬，歸去卧山村。"]'),
('b8f1cb24-c9da-4e3d-8c46-92c14cb5e3b2','偶題三首  其三','王禹偁','宋','宋诗','song-poetry','','[]','白頭厭郎署，病眼欲分司。',24,'全唐诗/poet.song.3000.json','["白頭厭郎署，病眼欲分司。", "寸心猶未决，所顧在妻兒。"]'),
('ddc13974-0f2e-4363-a1a1-1c38744c27ba','詩酒','王禹偁','宋','宋诗','song-poetry','','[]','白頭郎吏合歸耕，猶戀君恩典郡城。',64,'全唐诗/poet.song.3000.json','["白頭郎吏合歸耕，猶戀君恩典郡城。", "已覺功名乖素志，祇憑詩酒送浮生。", "剛腸減後微微諷，病眼昏來細細傾。", "樽杓不空編集滿，未能將此換公卿。"]'),
('151042bc-871e-417f-85d3-91eac4abb0e8','司空相公挽歌  其一','王禹偁','宋','宋诗','song-poetry','','[]','全德羣儒服，清名信史書。',48,'全唐诗/poet.song.3000.json','["全德羣儒服，清名信史書。", "何人不調鼎，唯我得懸車。", "蕭相文無害，于公慶有餘。", "三川歸葬地，松檟自扶疏。"]'),
('7ab01f25-e3cc-43b0-88f7-cf75fcef0ea2','司空相公挽歌  其二','王禹偁','宋','宋诗','song-poetry','','[]','執禮身雖退，思賢寵未衰。',48,'全唐诗/poet.song.3000.json','["執禮身雖退，思賢寵未衰。", "垂行三入命，遽逼九原期。", "本末皆書史，功名別樹碑。", "須知文集裏，全似白公詩。"]'),
('c1debc0a-a4d8-43a2-aa13-9a8a6da9ba27','司空相公挽歌  其三','王禹偁','宋','宋诗','song-poetry','','[]','去歲頻宣召，觀燈復賞花。',48,'全唐诗/poet.song.3000.json','["去歲頻宣召，觀燈復賞花。", "健嫌靈壽杖，輕棄富人車。", "列座先台席，溫顔逼翠華。", "而今宅前路，雨破築堤沙。"]'),
('96343bca-be2b-4361-a667-ea4749f2444b','和廬州通判李學士見寄  其一','王禹偁','宋','宋诗','song-poetry','','[]','北門西掖久妨賢，出入丹墀近八年。',64,'全唐诗/poet.song.3000.json','["北門西掖久妨賢，出入丹墀近八年。", "且把一麾淮水上，敢思三接浴堂前。", "將何政術稱循吏，豈有文章號謫仙。", "除却清貧入詩詠，山城坐客冷無氈。"]'),
('f570ed83-87c9-4e61-b1fc-918b0c9a2091','和廬州通判李學士見寄  其二','王禹偁','宋','宋诗','song-poetry','','[]','金鑾失職下蓬瀛，也向淮邊領郡城。',64,'全唐诗/poet.song.3000.json','["金鑾失職下蓬瀛，也向淮邊領郡城。", "堆案簿書爲俗吏，滿樓山色負吟情。", "廬江地近音塵斷，何遜詩來格調清。", "未得樽前一開口，可憐心緒獨摇旌。"]'),
('988afe64-61d1-42aa-a926-00306ad23a34','贈朱嚴','王禹偁','宋','宋诗','song-poetry','','[]','未得科名鬢已衰，年年顦悴在京師。',64,'全唐诗/poet.song.3000.json','["未得科名鬢已衰，年年顦悴在京師。", "妻裝秋卷停燈坐，兒趁朝餐乞米炊。", "尚對交朋賒酒飲，徧看卿相借馿騎。", "誰憐所好還同我，韓柳文章李杜詩。"]'),
('a2db7faa-bacb-400f-ba17-8d0734678b29','戲和壽州曾秘丞黄黄詩','王禹偁','宋','宋诗','song-poetry','','[]','黄黄真是小巫娥，買恐千金價不多。',64,'全唐诗/poet.song.3000.json','["黄黄真是小巫娥，買恐千金價不多。", "別母語嬌空有淚，對人聲顫未成歌。", "産從南國勝桃李，携去東山隠薜蘿。", "滁上老郎無妓女，草玄讀易擬如何。"]'),
('cca8f29d-4681-4150-9b46-8ea0f03e888d','又和曾秘丞見贈  其一','王禹偁','宋','宋诗','song-poetry','','[]','非才誤受帝恩深，報國空存一片心。',128,'全唐诗/poet.song.3000.json','["非才誤受帝恩深，報國空存一片心。", "命薄任從官進退，道孤難與衆浮沉。", "日邊信斷無歸夢，滁上公餘且醉吟。", "勞寄新詩遠相唁，野雲何處望爲霖。", "謬因文字立虛名，寓直金鑾冒寵榮。", "兩度黜官誰是援，二毛侵鬢自堪驚。", "宮花謾役春來夢，山蕨聊供醉後羹。", "身外浮華盡閑物，不將窮達問君平。"]'),
('b95b901b-58e0-43cb-828b-6b184f11da11','又和曾秘丞見贈  其二','王禹偁','宋','宋诗','song-poetry','','[]','篋中經歲鎖朝衣，自覺心閑少夢思。',64,'全唐诗/poet.song.3000.json','["篋中經歲鎖朝衣，自覺心閑少夢思。", "失馬叟言徒喻道，牧豬奴戲任爭棋。", "且持使節安黔首，莫愛恩波沃漏巵。", "況是無功頭已白，此身長恐負明時。"]'),
('7db40feb-a187-4dce-921a-a3b607048262','和朱嚴留別韻','王禹偁','宋','宋诗','song-poetry','','[]','之子有文行，常流竊比難。',144,'全唐诗/poet.song.3000.json','["之子有文行，常流竊比難。", "授毫秋露下，開卷古風寒。", "場屋推盟主，聲詩立將壇。", "論儒輕五霸，議古嫉三桓。", "師仰唯韓愈，才名壓李觀。", "固窮多短褐，憂道即忘餐。", "見訪山圍郡，相逢菊滿欄。", "眼青憐造士，頭白愧郎官。", "罷舉層霄遠，監州勺水盤。", "貧厨兼味少，市醖數杯酸。", "舊業煩君勘，新題爲我刊。", "臨岐留雅什，天馬撼金鑾。"]'),
('3d26f169-3071-4878-a43e-b445b89b8898','賦得紙送朱嚴','王禹偁','宋','宋诗','song-poetry','','[]','潔白又方正，似君心坦平。',48,'全唐诗/poet.song.3000.json','["潔白又方正，似君心坦平。", "空隨文價貴，未免刺毛生。", "客被侵霜薄，山窗映雪明。", "前春懸作榜，應見淡書名。"]'),
('6d8a8bb4-326b-421b-ae15-6eb7a6353713','饒州馬殿院頻寄黑髭藥服數千丸斑白未減作詩以報之','王禹偁','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','兩州迢遞隔長江，寄藥知君念老郎。',64,'全唐诗/poet.song.3000.json','["兩州迢遞隔長江，寄藥知君念老郎。", "妙術遠慚周柱史，衰容爭奈漢馮唐。", "未除凡骨無仙分，欲斷愁根有醉鄉。", "多羨繡衣鬚鬢黑，滿身唯带柏臺霜。"]'),
('96530de9-53d0-4f20-8f27-25bf7d5243d6','歲暮感懷','王禹偁','宋','宋诗','song-poetry','','[]','歲暮山城放逐臣，老從霄漢委泥塵。',64,'全唐诗/poet.song.3000.json','["歲暮山城放逐臣，老從霄漢委泥塵。", "公卿別後全無信，兄弟書來祇說貧。", "眼看青山休未得，鬢垂華髮摘空頻。", "文章氣概成何事，霑惹虛名誤此身。"]'),
('d15628fc-9e62-4543-8e73-7027313e21e1','送鄭南進士歸洪州','王禹偁','宋','宋诗','song-poetry','','[]','霜飄楓葉滿長郊，家指西山舊結茅。',64,'全唐诗/poet.song.3000.json','["霜飄楓葉滿長郊，家指西山舊結茅。", "訪我謫居龍失水，憐君行路鳥焚巢。", "仲尼未免遭儒戲，楊子何煩解客嘲。", "歸去豫章泉石好，不知徐孺與誰交。"]'),
('f530a54a-dcd6-4195-a55e-d1c801c33627','茶園十二韻','王禹偁','宋','宋诗','song-poetry','','[]','勤王修歲貢，晚駕過郊原。',144,'全唐诗/poet.song.3000.json','["勤王修歲貢，晚駕過郊原。", "蔽芾餘千本，青葱共一園。", "芽新撐老葉，土軟迸深根。", "舌小侔黄雀，毛獰摘綠猿。", "出蒸香更別，入焙火微溫。", "採近桐華節，生無穀雨痕。", "緘縢防遠道，進獻趁頭番。", "待破華胥夢，先經閶闔門。", "汲泉鳴玉甃，開宴壓瑶罇。", "茂育知天意，甄收荷主恩。", "沃心同直諫，苦口類嘉言。", "未復金鑾召，年年奉至尊。"]'),
('f9cc9a38-21ff-48dd-a07b-80f52a75d988','送董諫議之任湘潭','王禹偁','宋','宋诗','song-poetry','','[]','依依行色滿帆檣，又借仁風惠遠方。',64,'全唐诗/poet.song.3000.json','["依依行色滿帆檣，又借仁風惠遠方。", "暫去長沙非賈誼，猶虛計相待張蒼。", "檻前波浪瀟湘闊，雨後汀洲橘柚香。", "翰苑放臣知最幸，願聽民訟繼甘棠。"]'),
('1b9735ef-133e-4319-b784-6d5ab7e49372','送江州孫膳部歸闕兼寄承旨侍郎','王禹偁','宋','宋诗','song-poetry','','[]','九江爲郡鬢成霜，淮海相逢共黯傷。',64,'全唐诗/poet.song.3000.json','["九江爲郡鬢成霜，淮海相逢共黯傷。", "放逐翰林同李白，蹉跎郎署是馮唐。", "才名各負詩千首，離別無辭酒一觴。", "歸見鼇頭如借問，爲言棖也減剛腸。"]'),
('0826ded9-6add-44aa-a505-2b9be7f96631','立春前二日雪','王禹偁','宋','宋诗','song-poetry','','[]','一夕滿淮海，莎階曉欲平。',120,'全唐诗/poet.song.3000.json','["一夕滿淮海，莎階曉欲平。", "氣寒知臘在，勢猛共春爭。", "飄泊殘梅妬，龍鍾老檜擎。", "隨風無定態，入竹有繁聲。", "倚檻吟忘倦，援毫畫不成。", "南鄉消瘴癘，東作助農耕。", "片颺鵝毛遠，光翻蝶翅輕。", "任貧添酒債，慵掃慰詩情。", "羣玉峰巒秀，華胥世界清。", "老郎無政術，沉醉卧江城。"]'),
('1bba66cb-10e8-41c1-af0b-74c0a19dd8cc','送嚴判官歸滁州','王禹偁','宋','宋诗','song-poetry','','[]','永陽謫宦鬢成華，唯有賓從最可誇。',64,'全唐诗/poet.song.3000.json','["永陽謫宦鬢成華，唯有賓從最可誇。", "文學東堂進士第，風流南國相公家。", "移官我未歸丹禁，迴棹君今指白沙。", "滁上淹翔雖已久，寺樓山色對瑯邪。"]'),
('746924f7-fcd1-4527-ad42-d9e1d156a6c7','將巡堤堰先寄高郵蔣知軍','王禹偁','宋','宋诗','song-poetry','','[]','二十年前在濮陽，賓筵留我共飛觴。',64,'全唐诗/poet.song.3000.json','["二十年前在濮陽，賓筵留我共飛觴。", "當時進士衣如雪，今日郎官鬢有霜。", "吏役可堪巡堰埭，軍城猶喜接封疆。", "能來界首相期否，堤上依依柳漸黄。"]'),
('0598a58c-e1e7-4471-9dba-8fa414dc9f8a','送閤門秦舍人','王禹偁','宋','宋诗','song-poetry','','[]','郡印我未解，軺軒君不留。',48,'全唐诗/poet.song.3000.json','["郡印我未解，軺軒君不留。", "相逢都幾日，此別又經秋。", "山雪晴猶在，河澌暖漸浮。", "內庭連上閤，早晚共優游。"]'),
('a5c3d6a8-caed-410d-89a5-27eff9c491ed','病起思歸  其一','王禹偁','宋','宋诗','song-poetry','','[]','年來多病轉思山，終日呻吟簿籍間。',64,'全唐诗/poet.song.3000.json','["年來多病轉思山，終日呻吟簿籍間。", "叔夜養生休著論，陶潜難死只因閑。", "又移郡印三年調，未報君恩兩鬢斑。", "安得便歸田里去，松篁泉石掩柴關。"]'),
('693eb4b3-d864-4fd8-b444-92876a4d7461','病起思歸  其二','王禹偁','宋','宋诗','song-poetry','','[]','四十爲郎非不偶，況曾提筆直瀛洲。',64,'全唐诗/poet.song.3000.json','["四十爲郎非不偶，況曾提筆直瀛洲。", "明時遇主誰甘退，白髮侵人自合休。", "夢得蹉跎因出郡，薛能詩什恥監州。", "春來病起思歸甚，未敢飛章達冕旒。"]'),
('457f7316-f74d-48d1-9843-66c7ff126fc5','寒食','王禹偁','宋','宋诗','song-poetry','','[]','寒食江都郡，青旗賣楚醪。',48,'全唐诗/poet.song.3000.json','["寒食江都郡，青旗賣楚醪。", "樓臺藏綠柳，籬落露紅桃。", "妓女穿輕屐，笙歌泛小舠。", "史君慵不出，愁坐讀離騷。"]'),
('8c251425-719b-4dff-b5ef-005d127e0775','酬太常晁丞見寄','王禹偁','宋','宋诗','song-poetry','','[]','當年布素定交情，恨不同爲出谷鶑。',64,'全唐诗/poet.song.3000.json','["當年布素定交情，恨不同爲出谷鶑。", "猶作三丞君最屈，徧尋兩制我知榮。", "湮沉莫厭青衫在，彼此俱嗟白髮生。", "重入玉堂非所望，汶陽田好欲歸耕。"]'),
('f9f6a012-a724-4a75-817f-f6ddef025994','張屯田弄璋三日略不會客戲題短什期以滿月開筵','王禹偁','宋','宋诗','song-poetry','','[]','布素相知二十年，喜君新詠弄璋篇。',64,'全唐诗/poet.song.3000.json','["布素相知二十年，喜君新詠弄璋篇。", "洗兒已過三朝會，屈客應須滿月筵。", "桂子定爲前進士，蘭芽兼是小屯田。", "至時擔酒移厨去，請辦笙歌與管絃。"]'),
('6d279fe7-6b2b-4552-a7f0-482a092f3663','寄秀州馮十八禮丞同年','王禹偁','宋','宋诗','song-poetry','','[]','君從婺女典嘉興，我自滁陽到廣陵。',64,'全唐诗/poet.song.3000.json','["君從婺女典嘉興，我自滁陽到廣陵。", "同被雪霜侵兩鬢，獨嗟官職是三丞。", "郡齋新養華亭鶴，鄉信時逢建業僧。", "願作入朝西道主，只看黄霸詔書徵。"]'),
('dab6c2b2-72c9-4937-bbde-b24205bf3676','送丁謂之再奉使閩中','王禹偁','宋','宋诗','song-poetry','','[]','繡衣直指東南夷，入奏風謠受聖知。',64,'全唐诗/poet.song.3000.json','["繡衣直指東南夷，入奏風謠受聖知。", "持節又從三殿出，演綸還較一年遲。", "朝中謬拜推賢表，江畔空吟惜別詩。", "郡印喧卑文會少，爲君搔首落花時。"]'),
('f64fcbb2-9476-4731-853f-8e5795da73a5','牡丹十六韻','王禹偁','宋','宋诗','song-poetry','','[]','艷絕百花慚，花中合面南。',192,'全唐诗/poet.song.3000.json','["艷絕百花慚，花中合面南。", "賦詩情莫倦，中酒病先甘。", "國色渾無對，天香亦不堪。", "遮須施錦障，戴好上瑶簪。", "苞拆深擎露，枝拖翠出藍。", "半傾留粉蝶，微亞摘宜男。", "鄰妓臨粧妬，胡蜂得蕊貪。", "忽翻晴吹動，濃睡晚烟含。", "話別年經一，相逢月又三。", "遣吾撏白髮，爲爾換新衫。", "池館邀賓看，衙庭放吏參。", "仙娥喧道院，魔女逼禪庵。", "亂折窠難惜，分題韻更探。", "歌歡殊未厭，零落痛曾諳。", "穀雨供湯沐，黄鸝助笑談。", "顔生如見此，未免也醺酣。"]'),
('8124b4f7-1e61-44ce-8a45-c9923c4f5923','朱紅牡丹','王禹偁','宋','宋诗','song-poetry','','[]','渥丹容貌著霓裾，何事僧軒祇一株。',32,'全唐诗/poet.song.3000.json','["渥丹容貌著霓裾，何事僧軒祇一株。", "應是吳宮歌舞罷，西施因醉誤施朱。"]'),
('ad9f0b51-bf09-4224-b901-b6746fccb373','芍藥花開憶牡丹絕句','王禹偁','宋','宋诗','song-poetry','','[]','風雨無情落牡丹，翻階紅藥滿朱欄。',32,'全唐诗/poet.song.3000.json','["風雨無情落牡丹，翻階紅藥滿朱欄。", "明皇幸蜀楊妃死，縱有嬪嬙不喜看。"]'),
('673b5241-af67-4964-9a25-9a10d5864989','海仙花詩  其一','王禹偁','宋','宋诗','song-poetry','','[]','一堆絳雪壓春叢，嫋嫋長條弄嘵風。',32,'全唐诗/poet.song.3000.json','["一堆絳雪壓春叢，嫋嫋長條弄嘵風。", "借問開時何所似，似將繡被覆薰籠。"]'),
('ce9e8714-d093-4695-913f-0cb127d81ac2','海仙花詩  其二','王禹偁','宋','宋诗','song-poetry','','[]','春憎窈窕教無子，天爲妖嬈不與香。',32,'全唐诗/poet.song.3000.json','["春憎窈窕教無子，天爲妖嬈不與香。", "盡日含毫難比興，花中應是衛莊姜。"]'),
('7c850be7-e619-4d7f-8326-3e3ed87b7a85','海仙花詩  其三','王禹偁','宋','宋诗','song-poetry','','[]','何年移植在僧家，一簇柔條綴彩霞。',32,'全唐诗/poet.song.3000.json','["何年移植在僧家，一簇柔條綴彩霞。", "錦带爲名卑且俗，爲君呼作海仙花。"]'),
('fac286a9-fce9-4e7a-a704-b16acaae737c','后土廟瓊花詩    其一','王禹偁','宋','宋诗','song-poetry','','[]','誰移琪樹下仙鄉，二月輕冰八月霜。',32,'全唐诗/poet.song.3000.json','["誰移琪樹下仙鄉，二月輕冰八月霜。", "若使壽陽公主在，自當羞見落梅粧。"]'),
('a22486d2-f4bd-411a-ae29-5d4234860bbf','后土廟瓊花詩    其二','王禹偁','宋','宋诗','song-poetry','','[]','春冰薄薄壓枝柯，分與清香是月娥。',32,'全唐诗/poet.song.3000.json','["春冰薄薄壓枝柯，分與清香是月娥。", "忽似暑天深澗底，老松擎雪白娑婆。"]'),
('f96e4f77-a515-4748-9fab-683c68969a31','櫻桃漸熟牡丹已凋恨不同時輒題二韻','王禹偁','宋','宋诗','song-poetry','','[]','紅芳落盡正無憀，吟遶空枝首重搔。',32,'全唐诗/poet.song.3000.json','["紅芳落盡正無憀，吟遶空枝首重搔。", "最恨東君才思少，不留檀口待櫻桃。"]'),
('6d761b86-0944-4887-ac44-5aec76ae0583','芍藥詩  其一','王禹偁','宋','宋诗','song-poetry','','[]','牡丹落盡正凄凉，紅藥開時醉一場。',64,'全唐诗/poet.song.3000.json','["牡丹落盡正凄凉，紅藥開時醉一場。", "羽客暗傳尸解術，仙家重爇返魂香。", "蜂尋檀口論前事，露濕紅英試曉粧。", "曾忝掖垣真舊物，多情應認紫微郎。"]'),
('4ed8b508-0fb0-4253-86a5-7794545bc137','芍藥詩  其二','王禹偁','宋','宋诗','song-poetry','','[]','東君著意占殘春，得得遲開亦有因。',64,'全唐诗/poet.song.3000.json','["東君著意占殘春，得得遲開亦有因。", "曾與掖垣留故事，又來淮海伴詞臣。", "日燒紅艷排千朵，風遞清香滿四鄰。", "更愛枝頭弄金縷，異時相對掌絲綸。"]'),
('f889cca4-53cf-463c-be2d-20395be8316f','芍藥詩  其三','王禹偁','宋','宋诗','song-poetry','','[]','滿院勻開似赤城，帝鄉齊點上元燈。',64,'全唐诗/poet.song.3000.json','["滿院勻開似赤城，帝鄉齊點上元燈。", "感傷綸閣多情客，珍重維揚好事僧。", "酌處酒杯深蘸甲，折來花朵細含稜。", "老郎爲郡辜朝寄，除却吟詩百不能。"]'),
('0f69899f-26dc-4fb7-8bea-940e40bfdadb','暮春','王禹偁','宋','宋诗','song-poetry','','[]','索寞紅芳又一年，老郎空解惜春殘。',64,'全唐诗/poet.song.3000.json','["索寞紅芳又一年，老郎空解惜春殘。", "纔聞鶑囀誇楊柳，已被蟬聲哭牡丹。", "壯志休磨三尺劍，白頭誰藉兩梁冠。", "酒罇何必勞人勸，且折餘花更盡歡。"]'),
('9c2d3250-0daf-4c84-bc3c-ad64f28d5817','酬高郵知軍蔣殿丞見寄','王禹偁','宋','宋诗','song-poetry','','[]','青雲豈望更翱翔，覽照唯添鬢雪光。',64,'全唐诗/poet.song.3000.json','["青雲豈望更翱翔，覽照唯添鬢雪光。", "爲郡自知無政術，歸田猶擬拜封章。", "且眠錦帳趣蘭省，終掩雲關卧草堂。", "三入承明已過分，有何詞筆敵長楊。"]'),
('ab79e740-5dd8-4c64-9a26-9303bda57f89','又和寄惠藤篋絕句','王禹偁','宋','宋诗','song-poetry','','[]','蠻藤編篋自番禺，錦袋羅囊盡不如。',32,'全唐诗/poet.song.3000.json','["蠻藤編篋自番禺，錦袋羅囊盡不如。", "乞與揚州貯詩草，行春誰怕雨隨車。"]'),
('ccf52dcc-8f85-4d89-98a1-9c01af8c4560','先帝登遐聖君嗣位追惟恩顧涕泣成章','王禹偁','宋','宋诗','song-poetry','','[]','鼎湖髯斷去難攀，九五飛龍已御乾。',64,'全唐诗/poet.song.3000.json','["鼎湖髯斷去難攀，九五飛龍已御乾。", "兩制舊臣生白髮，一番新貴上青天。", "老爲郎吏承縗絰，假作諸侯哭几筵。", "疏賤無由撰哀冊，夢中空負筆如椽。"]'),
('37fec67d-521b-4e34-94de-e09b4baa9adc','登壽寧寺閣','王禹偁','宋','宋诗','song-poetry','','[]','乘興登虛閣，披襟一望間。',48,'全唐诗/poet.song.3000.json','["乘興登虛閣，披襟一望間。", "聖朝新日月，亡國舊江山。", "柱隔晴虹斷，簷喧夕鳥還。", "歸衙不辭晚，吟思白雲閑。"]'),
('5a52c47e-fbb3-45e6-aa22-dc19ba61d857','池上作','王禹偁','宋','宋诗','song-poetry','','[]','未遂滄洲去，池邊弄綠波。',48,'全唐诗/poet.song.3000.json','["未遂滄洲去，池邊弄綠波。", "醉浮船底兀，吟遶履痕多。", "靜照新華髮，沉思舊釣蓑。", "晚凉得幽趣，魚戲上圓荷。"]'),
('85d67477-cf81-4723-ba1f-bc8d58366fe1','和國子柳博士喜晴見贈','王禹偁','宋','宋诗','song-poetry','','[]','霖霪爲害正憂農，昨日陰雲散碧空。',64,'全唐诗/poet.song.3000.json','["霖霪爲害正憂農，昨日陰雲散碧空。", "潑剌退灘魚失水，啁啾高樹鳥知風。", "洗開霽月嬋娟色，放出秋花菡萏紅。", "勞寄新詩曲相賀，由來災異繫三公。"]'),
('85a800c4-570f-4a0f-a571-129f9cf40b0d','公退言懷','王禹偁','宋','宋诗','song-poetry','','[]','吏胥圍繞簿書堆，病眼昏昏素髮垂。',64,'全唐诗/poet.song.3000.json','["吏胥圍繞簿書堆，病眼昏昏素髮垂。", "已覺文章無用處，不歸田里待何時。", "兩衙决事官差我，五日延英詔問誰。", "頼有古人蹤跡在，只應蘧寧是吾師。"]'),
('92be9149-2928-4013-b8ef-a42cc3e9fd8a','公餘對竹','王禹偁','宋','宋诗','song-poetry','','[]','冠褐飄飄乍退公，引吟留坐一叢叢。',64,'全唐诗/poet.song.3000.json','["冠褐飄飄乍退公，引吟留坐一叢叢。", "買添幽景渾無價，洗却繁陰別有風。", "曾任雪欺終古綠，也從桃映暫時紅。", "此君合是吾廬物，會種嬋娟伴釣翁。"]'),
('dd8e6fc7-f200-4d47-bb30-017fe36e0b38','官舍偶題','王禹偁','宋','宋诗','song-poetry','','[]','俸錢隨月盡，公務逐時生。',48,'全唐诗/poet.song.3000.json','["俸錢隨月盡，公務逐時生。", "白髮多悲感，皇華倦送迎。", "奉身無實事，困我爲虛名。", "會向滄浪上，秋風自濯纓。"]'),
('fccbfb8c-916b-429e-aef9-a85729e10918','贈呂通祕丞','王禹偁','宋','宋诗','song-poetry','','[]','聞君公事苦喧卑，紅粟堆邊獨歛眉。',64,'全唐诗/poet.song.3000.json','["聞君公事苦喧卑，紅粟堆邊獨歛眉。", "已入朝行翻掌庾，未如畿尉且吟詩。", "堰頭笑傲同張祜，市裏優游比路隨。", "唯有才名藏不得，山陽留滯肯多時。"]'),
('95fde2ad-e8d9-48a4-b64d-c562e8693351','贈虛己','王禹偁','宋','宋诗','song-poetry','','[]','谿邊幽樹好烟霞，別後春風幾度花。',64,'全唐诗/poet.song.3000.json','["谿邊幽樹好烟霞，別後春風幾度花。", "夢憶一岩紅薜荔，心輕三事紫袈裟。", "禪機悟了身無著，詩句高來鬢有華。", "不遇蘇州韋應物，晝公篇什向誰誇。"]'),
('a928381f-c13c-4748-93fe-62c574fbf910','贈省欽','王禹偁','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','舊隠何年別翠微，瀑泉聲入鎖禪扉。',64,'全唐诗/poet.song.3000.json','["舊隠何年別翠微，瀑泉聲入鎖禪扉。", "御前曾寫八分字，天上特宣三事衣。", "燈照夜庵霜後冷，鼎烹秋菌雨中肥。", "終歸五老峰邊去，杯渡長江一錫飛。"]'),
('397a5795-8a39-459b-b03c-e1dd62669fb1','贈王殿院同年','王禹偁','宋','宋诗','song-poetry','','[]','幾年淮海歎驅馳，美拜初聞入奏時。',64,'全唐诗/poet.song.3000.json','["幾年淮海歎驅馳，美拜初聞入奏時。", "乍作臺官勞馬揖，合爲巡使近龍墀。", "多從此地升三字，莫向朝端說四推。", "縱遇省橋休拗項，郎官班列甚喧卑。"]'),
('8922e543-b80f-42c4-a099-184be5125a32','留別揚府池亭','王禹偁','宋','宋诗','song-poetry','','[]','竹遶亭臺柳拂池，徘徊終戀郡齋西。',32,'全唐诗/poet.song.3000.json','["竹遶亭臺柳拂池，徘徊終戀郡齋西。", "斜陽更上漁舟坐，明日紅塵逐馬蹄。"]'),
('af804386-7eb6-4d36-a7e8-50de05db97f0','池邊菊','王禹偁','宋','宋诗','song-poetry','','[]','綠池遶逕幾千栽，準擬登高泛酒杯。',32,'全唐诗/poet.song.3000.json','["綠池遶逕幾千栽，準擬登高泛酒杯。", "未到重陽歸闕去，金英寂寞爲誰開。"]'),
('bb86ae67-a020-43b0-8bd3-66935ad13f78','揚州道中感事兼簡史館丁學士','王禹偁','宋','宋诗','song-poetry','','[]','淮邊爲郡再相逢，又得同途赴九重。',64,'全唐诗/poet.song.3000.json','["淮邊爲郡再相逢，又得同途赴九重。", "顧我尚騎天廐馬，共君遥想鼎湖龍。", "賈生北望朝文帝，白傅何期哭憲宗。", "携手驛橋殘照裏，斷魂空對隔江峰。"]'),
('1619c011-2c67-42cf-b24d-440d80d86df3','太宗皇帝挽歌  其一','王禹偁','宋','宋诗','song-poetry','','[]','卜世知無極，上仙安可尋。',48,'全唐诗/poet.song.3000.json','["卜世知無極，上仙安可尋。", "祝堯違衆望，傳啟合天心。", "陵柏蕭騷韵，階茅寂寞陰。", "何人開殿閤，塵暗九絃琴。"]'),
('93770924-e317-4e73-8dd4-b47b1396bc79','太宗皇帝挽歌  其二','王禹偁','宋','宋诗','song-poetry','','[]','舜化無偏黨，堯年欠耄期。',48,'全唐诗/poet.song.3000.json','["舜化無偏黨，堯年欠耄期。", "世間人自哭，天上事難知。", "終讓東封禮，遂成南狩悲。", "金鑾舊學士，頭白涕漣洏。"]'),
('50ad06d5-ce0a-4759-9c93-f98c076bcacb','太宗皇帝挽歌  其三','王禹偁','宋','宋诗','song-poetry','','[]','日到虞泉落，天從杞國崩。',48,'全唐诗/poet.song.3000.json','["日到虞泉落，天從杞國崩。", "去年壽寧節，今夕永熙陵。", "薤露悲風起，松阡苦霧凝。", "龍髯攀不及，千古恨難勝。"]'),
('a76ece81-fe96-4889-ae2b-0711bd8bc043','闕下言懷上執政  其一','王禹偁','宋','宋诗','song-poetry','','[]','謬提文筆侍先皇，謫宦歸來遇國喪。',64,'全唐诗/poet.song.3000.json','["謬提文筆侍先皇，謫宦歸來遇國喪。", "仙駕只留燒藥鼎，繐帷猶認諫書囊。", "北辰別見天垂象，西內渾疑海變桑。", "昨日梓宮陪哭臨，淚多唯有老馮唐。"]'),
('5fcb3516-bb7c-4677-8684-2de53517eeb3','闕下言懷上執政  其二','王禹偁','宋','宋诗','song-poetry','','[]','早有虛名達九重，宦途流落漸龍鍾。',64,'全唐诗/poet.song.3000.json','["早有虛名達九重，宦途流落漸龍鍾。", "散爲郎吏同元稹，羞見都人看李邕。", "舊日謬吟紅藥樹，新朝曾獻皂囊封。", "猶期少報君恩了，歸卧山村作老農。"]'),
('7883382c-c497-4182-be52-e0894618ea2c','闕下言懷上執政  其三','王禹偁','宋','宋诗','song-poetry','','[]','誥詞黜責子孫羞，欲雪前冤事已休。',64,'全唐诗/poet.song.3000.json','["誥詞黜責子孫羞，欲雪前冤事已休。", "浴殿失恩成一夢，鼎湖攀駕即千秋。", "道邊任死心終直，澤畔長吟淚暗流。", "虞舜五臣知此事，戲儒應免更監州。"]'),
('e62f32af-9ef8-49e2-a952-9c2d7ddf18af','送邵察院知朗州','王禹偁','宋','宋诗','song-poetry','','[]','郡齋全占五谿雲，就養辭權以孝聞。',64,'全唐诗/poet.song.3000.json','["郡齋全占五谿雲，就養辭權以孝聞。", "重戴舊稱秦御史，高堂新授漢封君。", "板輿爲別經三載，壽酒先斟滿十分。", "我歎今生無此事，賦詩相送淚雰雰。"]'),
('4d06d106-7dd5-4066-a1e8-ca4c66d5b4d6','送直館高正言轉運荆湖','王禹偁','宋','宋诗','song-poetry','','[]','象笏烏紗諫署榮，運輸權重使蠻荆。',64,'全唐诗/poet.song.3000.json','["象笏烏紗諫署榮，運輸權重使蠻荆。", "職分三館圖書貴，地轄重湖水石清。", "貪吏望風潜解印，逋民知惠自歸耕。", "官曹寂寞馮唐老，多羨乘軺澤國行。"]'),
('8c02a40e-a090-4ffd-bc1d-800cdb6139b2','送宋澥處士之長安','王禹偁','宋','宋诗','song-poetry','','[]','簪笏盈門獨紉蘭，卧龍潜在八龍間。',64,'全唐诗/poet.song.3000.json','["簪笏盈門獨紉蘭，卧龍潜在八龍間。", "鴒原任說朝賢貴，鶴氅惟稱處士閑。", "靜按仙經燒大藥，狂挨僧壁畫遥山。", "老郎見作歸休計，分取圭峰並掩關。"]'),
('94f5333e-42e3-47a3-9bd4-b227981d085a','送刑部韓員外同年致仕歸華山','王禹偁','宋','宋诗','song-poetry','','[]','抗表辭烏府，歸山鬢未秋。',216,'全唐诗/poet.song.3000.json','["抗表辭烏府，歸山鬢未秋。", "朝簪還獬豸，塵世謝蜉蝣。", "拂袖人生事，縣車帝命優。", "名光新日曆，官占好詞頭。", "應宿郎曹美，尋仙物景幽。", "繡衣移蕙带，驄馬換耕牛。", "對枕蓮峰翠，當門瀑布流。", "妻閑栽藥草，兒戲雜猿猴。", "買竹憑牙板，疏泉濕鹿裘。", "四推離督責，三院肯淹留。", "接武陶貞白，差肩許遠遊。", "十洲如得侶，萬戶任封侯。", "脫洒因君去，龍鍾使我羞。", "遷鶑情最洽，化鶴術難求。", "掌誥無文彩，謀身足悔尤。", "紫垣頻忝竊，白髮合歸休。", "應璉叨三入，張衡志四愁。", "亦期婚嫁畢，攘袂逐浮丘。"]'),
('bbf435e4-2160-4c2e-a66a-74b631f11776','贈狀元先輩孫僅','王禹偁','宋','宋诗','song-poetry','','[]','病中何事忽開顔，記是詩稱小狀元。',64,'全唐诗/poet.song.3000.json','["病中何事忽開顔，記是詩稱小狀元。", "粉壁乍懸龍虎榜，錦標終屬鶺鴒原。", "青雲隨步登花塔，紅雪飄衣醉杏園。", "還有一條遺恨處，不教英俊在吾門。"]'),
('eb0a68ad-2d52-4461-8bce-de4eae15d656','贈浚儀朱學士','王禹偁','宋','宋诗','song-poetry','','[]','潘岳花陰覆杏壇，門生參謁絳紗寬。',64,'全唐诗/poet.song.3000.json','["潘岳花陰覆杏壇，門生參謁絳紗寬。", "西垣久望神仙侶，北部休誇父母官。", "雨屐送僧莎逕滑，夜棋留客竹齋寒。", "何時儤直來相伴，三入承明興漸闌。"]'),
('9fd6a44d-240d-48ed-b707-caafad12e77b','書懷送田二舍人自吏部郎中出典泰州','王禹偁','宋','宋诗','song-poetry','','[]','共歎蹉跎兩鬢蒼，立朝爲郡是尋常。',64,'全唐诗/poet.song.3000.json','["共歎蹉跎兩鬢蒼，立朝爲郡是尋常。", "重歸謝客中書省，又送山濤吏部郎。", "三入承明身最忝，十年兄事分偏長。", "喜聞辭日留前席，莫算多時住水鄉。"]'),
('90b4b350-7b96-42e4-9c48-4921503a27e5','寒食出城馬上偶作','王禹偁','宋','宋诗','song-poetry','','[]','欲報君親與願違，今年寒食任芳菲。',64,'全唐诗/poet.song.3000.json','["欲報君親與願違，今年寒食任芳菲。", "八音遏密因山後，雙淚滂沱拜墓歸。", "艷冶桃花迎馬笑，輕狂榆莢撲人飛。", "宦途時態更諳盡，猶媿妨賢直紫微。"]'),
('a9b211b0-f085-48c8-b7b3-4cb67782a207','病中書事上集賢錢侍郎  其一','王禹偁','宋','宋诗','song-poetry','','[]','力疾奉期謁，歸來倦送迎。',48,'全唐诗/poet.song.3000.json','["力疾奉期謁，歸來倦送迎。", "老爲儒術誤，瘦愛道裝輕。", "羅藥幽香散，移琴細韻生。", "晨餐漸有味，筍蕨倍關情。"]'),
('5ca25fcc-59be-46da-817b-47e5c1f14902','病中書事上集賢錢侍郎  其二','王禹偁','宋','宋诗','song-poetry','','[]','妻兒慣蔬素，僕馬任龍鍾。',48,'全唐诗/poet.song.3000.json','["妻兒慣蔬素，僕馬任龍鍾。", "一榻渾無物，孤琴對病容。", "風翻簾影亂，旱減井痕重。", "幽寂誰爲伴，扶行頼瘦筇。"]'),
('fdbeb85a-827c-4262-8e0e-185f7dcd8035','病中書事上集賢錢侍郎  其三','王禹偁','宋','宋诗','song-poetry','','[]','食貧當歲旱，朝退百端憂。',48,'全唐诗/poet.song.3000.json','["食貧當歲旱，朝退百端憂。", "典笏逢休假，焚香願有秋。", "病饑渾厭肉，瘦冷未更裘。", "夢見山村興，披蓑釣亂流。"]'),
('4c1c1dab-14a4-43d9-82fc-fee5e24d6ab5','病中書事上集賢錢侍郎  其四','王禹偁','宋','宋诗','song-poetry','','[]','郎署領制誥，十年未上坡。',48,'全唐诗/poet.song.3000.json','["郎署領制誥，十年未上坡。", "馮唐空潦倒，衛綰是誰何。", "猶頼紫垣直，聊遮白髮多。", "歸田未有計，村樹綠婆娑。"]'),
('6d96c977-96c0-4cb7-854e-5f70a77c699a','病中書事上集賢錢侍郎  其五','王禹偁','宋','宋诗','song-poetry','','[]','日日奉朝請，病多仍食貧。',48,'全唐诗/poet.song.3000.json','["日日奉朝請，病多仍食貧。", "揶揄應有鬼，夷俟豈無人。", "鳳閣十年筆，烏紗九陌塵。", "集仙知己在，應爲指迷津。"]'),
('83eb9fe7-d336-41d5-b235-9ab876efad4f','賃宅','王禹偁','宋','宋诗','song-poetry','','[]','老病形容日日衰，十年賃宅住京師。',64,'全唐诗/poet.song.3000.json','["老病形容日日衰，十年賃宅住京師。", "閣棲鳳鳥容三入，巢宿鷦鷯欠一枝。", "壁挂圖書多不久，砌栽蘆葦亦頻移。", "人生榮賤須知分，會買茅庵映槿籬。"]'),
('50be59b9-3a10-46e6-ae0d-670556fc7fb5','青猿','王禹偁','宋','宋诗','song-poetry','','[]','小僕如猿狖，貧家備指呼。',48,'全唐诗/poet.song.3000.json','["小僕如猿狖，貧家備指呼。", "未堪隨馬足，已慣典魚須。", "時洗塵侵硯，閑收雨滴圖。", "歸田如有計，留負酒胡蘆。"]'),
('208c0f0f-3bda-4242-9ba4-42b047d2641b','寓直偶題','王禹偁','宋','宋诗','song-poetry','','[]','兩朝書命媿無才，謾逐詞臣侍玉階。',64,'全唐诗/poet.song.3000.json','["兩朝書命媿無才，謾逐詞臣侍玉階。", "病似相如多避事，拙于方朔少詼諧。", "命奇只合先休退，道在何妨更卷懷。", "白首猶期議封禪，一隨鑾輅見燔柴。"]'),
('8006763b-8346-4e26-8ded-eddb6df97550','頃年謫宦解梁收得令狐補闕毛詩音義其本乃會昌三年所寫數行殘缺後人添之其筆跡乃工部畢侍郎所補也昨因問之乃云亡失多年矣作四韵以還之','王禹偁','宋','宋诗','song-poetry','','[]','謫宦山州自訓童，因求書籍有遭逢。',64,'全唐诗/poet.song.3000.json','["謫宦山州自訓童，因求書籍有遭逢。", "偶收毛鄭古詩義，認得歐虞舊筆蹤。", "南郡携行心不足，西齋送去手親封。", "塵侵烟染尤堪重，年號標題歷武宗。"]'),
('38536fd0-282c-48be-9369-318df19976e9','伏日偶作','王禹偁','宋','宋诗','song-poetry','','[]','移床拖簟就南軒，門掩閑坊半樹蟬。',64,'全唐诗/poet.song.3000.json','["移床拖簟就南軒，門掩閑坊半樹蟬。", "多病形容唯有骨，食貧生計旋無錢。", "掖垣已忝年深直，朝謁終妨日晏眠。", "會解綸闈求郡印，早收餘俸卜歸田。"]'),
('22f2f550-3fb2-40a1-b1f1-1176224226c1','和吏部薛員外見寄','王禹偁','宋','宋诗','song-poetry','','[]','棖也好剛多悔吝，唯憑忠信自書紳。',64,'全唐诗/poet.song.3000.json','["棖也好剛多悔吝，唯憑忠信自書紳。", "嚴陵知退遺榮利，只擬滄浪把釣綸。", "老去趁朝慵待旦，病來求假動經旬。", "西垣興味更諳盡，一片烏紗滿馬塵。"]'),
('a6df4070-3ee3-4c58-87d0-6071e6374e2d','贈密直張諫議','王禹偁','宋','宋诗','song-poetry','','[]','先皇憂蜀輟樞臣，獨冒兵戈出劍門。',64,'全唐诗/poet.song.3000.json','["先皇憂蜀輟樞臣，獨冒兵戈出劍門。", "萬里辭家堪下淚，四年歸闕似還魂。", "弟兄齒序元投分，兒女情親又結婚。", "且喜相逢開口笑，甘陳功業不須論。"]'),
('8f5fcc03-77c4-4a29-94b0-6e465a7f5efe','寄狀元孫學士','王禹偁','宋','宋诗','song-poetry','','[]','久居臺閣多憂畏，欲薦賢才涉比周。',64,'全唐诗/poet.song.3000.json','["久居臺閣多憂畏，欲薦賢才涉比周。", "灰死寸心甘不動，雪侵雙鬢未能休。", "封章事寢空騰謗，制誥詞荒益自羞。", "唯愛君家棣華榜，登科記上並龍頭。"]'),
('d8b62e13-0e83-4e70-964d-d9c6a512336d','送譚殿院之任南陽','王禹偁','宋','宋诗','song-poetry','','[]','大抵人生樂故居，山川況復漢南都。',64,'全唐诗/poet.song.3000.json','["大抵人生樂故居，山川況復漢南都。", "別來墳墓有宿草，歸去田園多綠蕪。", "銀印莫羞雙鬢白，錦衣兼照兩轓朱。", "西垣衰病無憀客，空羨此行歌袴襦。"]'),
('f2fb984d-58a3-473b-a1a8-082352c7b619','送河陽任長官','王禹偁','宋','宋诗','song-poetry','','[]','宰君行李苦蕭疏，妻子龍鍾尚跨馿。',64,'全唐诗/poet.song.3000.json','["宰君行李苦蕭疏，妻子龍鍾尚跨馿。", "醉眼且看花滿縣，愁顔莫望果盈車。", "頭銜新換呼明府，科第元高得校書。", "誰解吟詩送行色，茂陵多病老相如。"]'),
('608d3f3c-7b52-4846-81b8-32e739e69849','和屯田楊郎中同年留別之什','王禹偁','宋','宋诗','song-poetry','','[]','科名長恐辱同年，許國丹誠皎日懸。',64,'全唐诗/poet.song.3000.json','["科名長恐辱同年，許國丹誠皎日懸。", "謬掌斯文雖未喪，欲行吾道即無權。", "謝公留滯蒼苔院，潘岳征行落葉天。", "引重力輕深自媿，强酬詩什益凄然。"]'),
('fdbada62-794d-4271-b239-8a85c1ca502b','送臨清楊可主簿入蜀','王禹偁','宋','宋诗','song-poetry','','[]','脫白去焚黄，遥知祖德光。',48,'全唐诗/poet.song.3000.json','["脫白去焚黄，遥知祖德光。", "墓墳喬木老，襟袖桂枝香。", "迴見梅含雪，歸逢橘飽霜。", "子雲應有宅，爲奠草玄堂。"]'),
('89ec3a34-8ccc-4201-9e91-8be3d9993e80','送淳于中舍懸車侍養','王禹偁','宋','宋诗','song-poetry','','[]','懸車東去謝明朝，擺脫簪纓似一毛。',64,'全唐诗/poet.song.3000.json','["懸車東去謝明朝，擺脫簪纓似一毛。", "望苑官清諧侍養，督郵名賤恥徒勞。", "青宮位在他年起，綵服身歸此日高。", "我媿無親尸厚祿，與君書命淚霑袍。"]'),
('1be2a496-203d-458d-a23f-7975ae510b95','送正言楊學士之任縉雲','王禹偁','宋','宋诗','song-poetry','','[]','弱冠珥朝簪，才堪入翰林。',120,'全唐诗/poet.song.3000.json','["弱冠珥朝簪，才堪入翰林。", "重違君厚遇，聊奉母懽心。", "筆削留惇史，囊裝貯賜金。", "帆張淛河闊，山對括蒼深。", "暫歇趨朝馬，重聞故國禽。", "幽蘭南澗採，壽酒北堂斟。", "務簡慵開閣，家豐不典琴。", "彩衣方侍養，紅藥即供吟。", "我占掖垣久，自驚年鬢侵。", "妨賢兼罔極，相送淚盈襟。"]'),
('e724583c-6e2e-4efa-a190-8e033a696dd5','送第三人朱嚴先輩從事和州','王禹偁','宋','宋诗','song-poetry','','[]','賃船東下歷陽湖，榜眼科名釋褐初。',64,'全唐诗/poet.song.3000.json','["賃船東下歷陽湖，榜眼科名釋褐初。", "賓職不憂無厚俸，郡齋唯喜有藏書。", "伴吟先買秋江鶴，醒酒時烹晚市魚。", "廉使多情應問我，爲言衰病似相如。"]'),
('2dcef4c1-4c56-4bde-acb5-2e870a39a0da','送南陽李太傅  其一','王禹偁','宋','宋诗','song-poetry','','[]','兩朝黄閣預彌綸，又策春坊第一勳。',64,'全唐诗/poet.song.3000.json','["兩朝黄閣預彌綸，又策春坊第一勳。", "僧塔舊題前進士，齋壇新拜上將軍。", "馬銜金勒衝微雪，雁避紅旌入斷雲。", "還似徐州張僕射，御詩相送四方聞。"]'),
('90031d5e-7fd7-4bbf-8aa2-da7bab38eaa1','送南陽李太傅  其二','王禹偁','宋','宋诗','song-poetry','','[]','紅旆飄飄奪曉霞，御筵相送出京華。',64,'全唐诗/poet.song.3000.json','["紅旆飄飄奪曉霞，御筵相送出京華。", "仲尼俎豆真儒者，郤縠詩書屬將家。", "腰下已懸如斗印，門前看見築堤沙。", "先朝學士期牽復，待草南陽入相麻。"]'),
('9f8304dc-fc21-4795-b29f-10edf698526e','壽孫三日','王禹偁','宋','宋诗','song-poetry','','[]','經年病不飲，此日一開樽。',48,'全唐诗/poet.song.3000.json','["經年病不飲，此日一開樽。", "鑑裏休嫌老，懷中已抱孫。", "紅綳裁錦段，香水浴銀盆。", "他日歸田去，相扶入蓽門。"]'),
('80f216b6-f6b8-48a5-afbe-fdd5690e6503','謝宣賜御草書急就章并朱邸舊集歌','王禹偁','宋','宋诗','song-poetry','','[]','臣聞伏羲畫卦朴且淳，蒼頡造字初有文。',394,'全唐诗/poet.song.3000.json','["臣聞伏羲畫卦朴且淳，蒼頡造字初有文。", "大篆小篆八分體，楷隸章草何紛紜。", "因茲八法各有要，遂使六藝區以分。", "其中最難惟草聖，玄妙功夫自天性。", "又聞關雎本王化，四始洋洋風化下。", "比興賦頌六義分，乃有變風兼變雅。", "仲尼刪後屈平作，郢客李陵鬭名價。", "古來詩道難得人，其唱彌高和彌寡。", "如今草聖與雅言，盡在吾皇萬機暇。", "元年十月近乾明，崇文院靜寒霜晴。", "直廬日午讎書罷，閑曳朱衣遶砌行。", "中使傳宣來上界，忙把魚須下階拜。", "寶函鈿軸光陸離，御札文書御製詩。", "折腰搢笏拭雙目，汗流魄駭聊一窺。", "急就章，何縱橫，藍田種玉苗初成。", "雪花灑破煙嵐壁，黑雲漏出天漢星。", "乍似鮫人泣下珠無數，錯落晶熒滿盤貯。", "又似大鯨吞盡滄海波，查牙露出珊瑚樹。", "朱邸集，何清奇，仙風撼動瓊林枝。", "漢皇休道白雲句，穆滿虛吟黄竹詩。", "乍似三春直上伯陽臺，熙熙物華當眼開。", "又似十洲夜伴王母宴，鸞歌鳳吟次第來。", "小臣再拜受一軸，擣紙抄詩抄未足。", "焚香朝向天日看，執簡夜對星辰讀。"]'),
('4b2af929-be0d-4993-a0a1-184e1b762419','應制皇帝親試貢士歌','王禹偁','宋','宋诗','song-poetry','','[]','天王出震寰海清，奎星燦燦昭文明。',160,'全唐诗/poet.song.3000.json','["天王出震寰海清，奎星燦燦昭文明。", "詔令郡國貢多士，大張珠網羅羣英。", "皇情孜孜終不倦，日斜猶御金鑾殿。", "宮柳低籠三月煙，爐香飛入千人硯。", "麻衣皎皎光如雪，一一重瞳親鑒別。", "孤寒得路荷君恩，聚首唯言盡臣節。", "小臣蹤跡本塵泥，登科曾賦御前題。", "屈指方經五六載，如今已上青雲梯。", "位列諫官無一語，自問將何報明主。", "應制非才但淚垂，强作登歌歌舜禹。"]'),
('ac6c2dec-119e-4597-a8aa-2b08e48b90a6','謝政事王侍郎伏日送冰','王禹偁','宋','宋诗','song-poetry','','[]','火雲如山暑雨歇，天地爐烘三伏月。',144,'全唐诗/poet.song.3000.json','["火雲如山暑雨歇，天地爐烘三伏月。", "玉皇教散閬苑冰，斵開北陸瓊瑰窟。", "峨峨貯向瑶花合，分命中官賜黄閤。", "鳳皇池上玉壺盛，溫樹風聲頓蕭颯。", "台恩分與西垣士，綸誥稀疏方假寐。", "卞和抱璞入直廬，從此驚忙不成睡。", "怒蠅休向筆端飛，抵鵲渾疑山下墜。", "寒生毛髮清牙齒，脆若玉芝甘似醴。", "炎風暑氣都不知，空作狂歌謝知己。"]'),
('2615f3fc-f239-404a-b9a7-614ff4b3176b','酬贈田舍人','王禹偁','宋','宋诗','song-poetry','','[]','君不見天上星辰拱環極，忽然隕地變成石。',394,'全唐诗/poet.song.3000.json','["君不見天上星辰拱環極，忽然隕地變成石。", "又不見雲中鷹隼橫高秋，有時搨翼化作鳩。", "人生進退甚類此，左遷右轉誰自由。", "憶昔逢君在鄒魯，翰林丈人東道主。", "一言得意便定交，數日論文暗相許。", "邇來倏忽十餘年，共上赤霄連步武。", "禁中更直承明廬，深喜蒹葭依玉樹。", "兩制惟君最清慎，筆力辭鋒有餘刃。", "方期夜直金鑾坡，誰知共理淮陽郡。", "官銜新換版曹郎，腰佩初懸列侯印。", "西垣三字班列閑，南面百城資望峻。", "且應盡意頒詔條，豈復迴頭顧文陣。", "下車果有謳謠生，賣刀買犢民歸耕。", "黄髮老農鼓腹唱，雪花雙鹿挾輈行。", "棠陰露濃滴朱紱，麥秋風冷吹紅旌。", "行春多暇吟情發，閑作長歌寄同列。", "歌中首寫明君語，指點神仙爲舊侶。", "嚴徐雖合在蓬瀛，邵杜已聞爲父母。", "重來便恐調金鉉，無復區區掌文翰。", "直如經歲未徵黄，道在何勞重嗟嘆。", "入則步蒼苔，詠紅藥，了事舍人孫處約。", "出則張皂蓋，擁朱輪，賢明太守召信臣。", "請君屈指數交友，似此宦名能幾人。", "逢時誰不欲行道，遇主我亦思庇民。"]'),
('58106c27-5d49-416e-817f-cc4c6d169ef4','對雪示嘉祐','王禹偁','宋','宋诗','song-poetry','','[]','去年看雪在商州，使君命我山寺頭。',384,'全唐诗/poet.song.3000.json','["去年看雪在商州，使君命我山寺頭。", "峰巒草樹六百里，饑鼯凍鳥聲啾啾。", "山城窮陋無妓樂，何以銷得騷人愁。", "抱瓶自瀉不待勸，乘興一引連十甌。", "晚歸上馬頗自適，狂吟醉舞夜不休。", "今年看雪在帝里，瑶臺瓊樹佳氣浮。", "朝迴攬轡聊四望，移下五城十二樓。", "樽中有酒翻不飲，鬰鬰不快非怨尤。", "吾兒嬌騃未曉事，問我胡不私獻酬。", "因令把筆寫我意，爲渠吟作雪中謳。", "昔爲副使不理事，待罪且免憂人憂。", "今爲諫官非冗長，拾遺三館俸入優。", "秋來連澍百日雨，禾黍漂溺多不收。", "如今行潦占南畝，農夫失望無來麰。", "爾看門外饑餓者，往往殭殕填渠溝。", "峨冠旅進又旅退，曾無一事裨皇猷。", "俸錢一月數家賦，朝衣一襲幾人裘。", "安邊不學趙充國，富民不作田千秋。", "胡爲碌碌事文筆，歌時頌聖如俳優。", "一家衣食仰在我，縱得飽暖如狗偷。", "况我眼昏頭漸白，安能隠几勤校讎。", "何時提汝歸田去，賣馬可易數隻牛。", "深耕淺種苟自給，藜羹豆粥充饑喉。", "黍畦鋤理學元亮，瓜田澆灌師秦侯。"]'),
('8a81b3cf-6e7b-418b-9715-7774e1b7a900','送姚著作之任宣城','王禹偁','宋','宋诗','song-poetry','','[]','平生聞說宣城郡，水石幽奇人物俊。',384,'全唐诗/poet.song.3000.json','["平生聞說宣城郡，水石幽奇人物俊。", "檻外澄江練不收，窗中遠岫眉初印。", "六朝繁盛至隋唐，才人名士遥相望。", "謝公向此憑熊軾，白傅曾爲鹿鳴客。", "江樓山寺多賦詩，往往題名在僧壁。", "皇家早歲平吳後，翰林賈公爲太守。", "至今清話玉堂中，夸詫江山不離口。", "吾君御極初選藝，東樞貳卿新擢第。", "解褐曾縻佐郡官，首得宣城爲歷試。", "紫微田郎次登科，東樞受代傳廳事。", "第三榜中第二人，今在烏臺爲察視。", "邇來通倅少名流，雲泉竹樹應包羞。", "今春忽命姚著作，學術縱橫才磊落。", "當年雄揖第三名，官路迍邅久漂泊。", "去歲獻文重召試，新恩始上芸香閣。", "未教修史未演綸，宣城奉使聊親民。", "且忻彩服得就養，莫歎朱衣未即真。", "舊遊應有交朋在，此去仍言婚宦新。", "下車布政民休休，高吟淺酌誰獻酬。", "夜深紅燭在何處，綺霞閣通疊嶂樓。", "公權書札燕許詞，未免山僧乞撰碑。", "撰碑書碑即三載，眼看徵詔在丹墀。", "却愁未盡江南興，閑坐蓬瀛揮玉柄。", "黄樞侍臣兩制官，待君同說宣城景。"]'),
('fa524cac-fed6-4b60-9c0e-e6f33420d9c0','送晁監丞赴婺州關市之役','王禹偁','宋','宋诗','song-poetry','','[]','關征市賦縻賢俊，誰愛此官爲吏隠。',262,'全唐诗/poet.song.3000.json','["關征市賦縻賢俊，誰愛此官爲吏隠。", "將作晁丞于役時，婺女星臨海邊郡。", "黄絹辭高位尚卑，白華行潔身猶困。", "會待時來即併伸，也知道在終無悶。", "君不見路隨含笑坐市中，屈身豈愧丹陽尹。", "又不見張生狂醉戀揚州，冬瓜堰下甘肥遁。", "此行况是奉皇華，數丈輕舠載一家。", "携瓶下岸買竹葉，挂席背風穿蓼花。", "霜晴震澤初嘗橘，泉過惠山應試茶。", "虎谿曉雲靈隠雪，錢塘夜潮照湖月。", "密排詩景在途中，旋吟新句教兒童。", "漸近金華見隼旟，五馬來迎使者車。", "應知驥足暫拘絆，八詠樓開頻啟宴。", "醉中官妓乞歌詩，剡谿紙貴抄新詞。", "他年誰獻子虛賦，召入金門五雲路。", "因思元白在江東，不似晁丞今獨步。"]'),
('c31b5020-fe0a-41d9-ba55-e1172a135f92','還揚州許書記家集','王禹偁','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','君不見近代詩家流，胡爲蹇滯多窮愁。',259,'全唐诗/poet.song.3000.json','["君不見近代詩家流，胡爲蹇滯多窮愁。", "孟郊顦顇死逆旅，浪仙斥逐長江頭。", "張生漂泊冬瓜堰，徒云輕薄萬戶侯。", "浩然無成鹿門去，李洞慟哭昭陵休。", "生無風教興王化，死無勳爵貽孫謀。", "可憐詩道日已替，風騷委地何人收。", "高陽許公精六義，獨向聖朝生後嗣。", "因將先集進九重，高步金臺曳珠履。", "祖德光輝聖主知，府尹賢明丞相子。", "廣陵郡大古九州，記室官清外三字。", "遂令天下學詩人，徒羨君家窮四始。", "我來迎侍游江都，玳筵往往陪歡娛。", "遂求家集恣吟諷，海波乾處堆珊瑚。", "因思賈孟數家一何苦，詩鬼嗷嗷餒無主。", "子孫淪沒誰及君，閑倚紅蓮傾淥醑。", "草檄餘閑好賦詩，莫放風情忝爾祖。"]'),
('7d880049-18e6-4222-8ca6-241712195077','酬處才上人','王禹偁','宋','宋诗','song-poetry','','["\u4e5d\u534e\u5c71"]','我聞三代淳且質，華人熙熙誰信佛。',244,'全唐诗/poet.song.3000.json','["我聞三代淳且質，華人熙熙誰信佛。", "茹蔬剃髮在西戎，胡法不敢干華風。", "周家子孫何不肖，奢淫惛亂隳王道。", "秦皇漢帝又雜霸，只以威刑取天下。", "蒼生哀苦不自知，從此中國思蠻夷。", "無端更作金人夢，萬里迎來萬民重。", "爲君爲相猶歸依，嗤嗤聾俗誰敢非。", "若教都似周公時，生民豈肯須披緇。", "可憐嗷嗷避征役，半入金田不耕織。", "君子之道動即窮，亦有賢達藏其中。", "上人來自九華山，叩門遺我瓊瑶編。", "錚錚五軸餘百篇，定交仍以書爲先。", "書中不說經，文中不言佛，有心直欲興文物。", "感師自遠來相親，爲師畫卦成同人。", "出門無咎非羣分，袈裟墨綬何足云。"]'),
('690c8ce1-92a7-4c72-9f55-5ce678202b12','和張校書吳縣廳前冬日雙開牡丹歌','王禹偁','宋','宋诗','song-poetry','','[]','君不見年年三月千叢媚，紫爛紅繁誇勝異。',165,'全唐诗/poet.song.3000.json','["君不見年年三月千叢媚，紫爛紅繁誇勝異。", "尋常人戴滿頭歸，醉折狂分不爲貴。", "枝閑葉盡根空培，人情皆待明年開。", "化工自有呼魂術，霜前喚下瓊瑶臺。", "王母親將金粉傅，麻姑齊借霓裳來。", "主人蓋是神仙才，不然此物胡爲而來哉。", "二姬勸酒誰引滿，長洲懶吏先舉杯。", "多感同年與攀折，吟詩欲謝難輕發。", "青宮校書方遁跡，代我作歌如錦拆。", "他年吾輩功業成，與君共作騎鯨客。"]'),
('acf64e61-84e5-4c54-a8e2-7c1a8a11306d','和馮中允爐邊偶作','王禹偁','宋','宋诗','song-poetry','','[]','誰爲東君掌青律，故將春日連人日。',304,'全唐诗/poet.song.3000.json','["誰爲東君掌青律，故將春日連人日。", "春日雨絲暖融融，人日雪花寒慄慄。", "雨雪寒暖苦不同，可比交情去就中。", "仲咸擁爐發歌詠，古風激破澆漓風。", "人情離合古來有，召公初亦疑周公。", "汾陽臨淮本讎隙，一旦分兵若親戚。", "四公翻覆人不譏，各各操心爲邦國。", "此外譸張多爲己，反掌背面如千里。", "張耳陳餘不忍言，魏其武安何足齒。", "我愛中庸君子心，心與人交淡如水。", "別有人間勢利徒，一去一就隨榮枯。", "西漢董賢方佞倖，孔光迎拜卑如奴。", "是時楊雄在東觀，投閣欲死無人扶。", "有唐力士夫人死，朝士執喪如喪妣。", "是時李白放江邊，憔悴無人供酒錢。", "小人之性何所似，真如蜂蝶并螻蟻。", "尋春逐臭苟朝昏，豈顧松篁與蘭茝。", "重君誓心一何極，澗底松兮陵上柏。", "澗松陵柏有朽時，我約君心無改易。"]'),
('ae7c90ef-68fc-4fb1-a7e8-be06c27cbc65','賦得南山行送馮中允之辛谷冶按獄','王禹偁','宋','宋诗','song-poetry','','[]','商山三月花如火，草樹青葱雨初過。',256,'全唐诗/poet.song.3000.json','["商山三月花如火，草樹青葱雨初過。", "柳條漸軟蝶雙飛，桑葉尚多蠶一卧。", "薄情野水流不迴，無力春雲慵欲墮。", "團團榆莢是誰拋，漠漠游絲向人嚲。", "可憐花木間嵐光，花前正好飛觥觴。", "馮君夙駕一何速，捧檄銀坑按辛谷。", "轉輸昨日又移文，小甿訴牒何紛紜。", "見說南山六百里，跙盡馬蹄摧屐齒。", "是何屈于不知己，衝斗太阿教補履。", "龍無尺水且蟠泥，驥困鹽車但垂耳。", "片言折獄亦胡爲，必也無訟方君子。", "吾徒事業本稽古，得行其志當刑措。", "畫衣畫地免煩苛，抵璧捐金返淳素。", "未行此道且營營，營營爲祿聊代耕。", "殘春小別不足念，爲君高唱南山行。", "南山一月期迴首，莫訴臨歧數巵酒。"]'),
('12e91105-ec2c-470d-8a95-dbd2bae8f687','烏啄瘡馿歌','王禹偁','宋','宋诗','song-poetry','','[]','商山老烏何慘酷，喙長于釘利于鏃。',176,'全唐诗/poet.song.3000.json','["商山老烏何慘酷，喙長于釘利于鏃。", "拾蟲啄卵從爾爲，安得殘吾負瘡畜。", "我從去歲謫商於，行李惟存一蹇馿。", "來登秦嶺又巉嶺，爲我馱背百卷書。", "穿皮露脊痕連腹，半年治療將平復。", "老烏昨日忽下來，啄破舊瘡取新肉。", "馿號僕叫烏已飛，劘嘴整毛坐吾屋。", "我馿我僕奈爾何，悔不挾彈更張羅。", "頼是商山多鷙鳥，便問鄰家借秋鷂。", "鐵爾拳兮鈎爾爪，折烏頸兮食烏腦。", "豈唯取爾饑腸飽，亦與瘡馿復讎了。"]'),
('e786c3bb-783e-44b5-b565-d8e254d9102a','酬安祕丞歌詩集','王禹偁','宋','宋诗','song-poetry','','[]','我聞天有二十八箇星，降生下界爲英靈。',311,'全唐诗/poet.song.3000.json','["我聞天有二十八箇星，降生下界爲英靈。", "東方曼倩蕭相國，至今留得終天名。", "又聞地有三十六所洞，洞中多聚神仙衆。", "神仙負過遭譴謫，謫來人世爲辭客。", "李白王維并杜甫，詩顛酒狂振寰宇。", "今來相去千百年，寥落乾坤闃無睹。", "皇天何不生奇人，庸兒蠢夫空紛紛。", "夜眠朝走不覺老，飯囊酒甕奚足云。", "陶丘忽見安祕書，星精仙骨真有餘。", "月中曾折最高桂，趁出玉兔驚蟾蜍。", "示我歌詩百餘首，筆鋒閃閃摩星斗。", "乍似碧落長拖萬丈虹，飲竭四海波瀾空。", "又似赤晴乾撒一陣雹，打折瓊林枝倒卓。", "夜來夢見李長吉，叩頭再拜須來乞。", "自言失却照海珠，至今黑坐驪龍窟。", "方知安侯不是星辰類，即是神仙輩。", "不然又爭得標格峻邁，文辭顛怪。", "有時醉起一長噫，八極風清鬼神駭。", "他年却入蓬萊宮，休使麻姑更爬背。"]'),
('eabdf25a-3051-4971-83c8-073812235060','酬安祕丞見贈長歌','王禹偁','宋','宋诗','song-poetry','','[]','我聞進士登科換凡骨，信知不是風塵物。',386,'全唐诗/poet.song.3000.json','["我聞進士登科換凡骨，信知不是風塵物。", "貢籍由來數百年，直疑空却神仙窟。", "其間最貴龍虎榜，乘時得路爲卿相。", "一從巢寇犯闕來，梁氏禮闈還草創。", "莊宗明宗雖膺命，晉朝漢朝俱不永。", "其中縱得神仙材，太平不見哀之哉。", "上玄應恐天地閑，安仙又謫來人寰。", "二十把筆疏辭源，黄河傾落崑崙山。", "有周道衰猶歎鳳，天公留得歸皇宋。", "天水夕郎掌貢時，禹門萬仞連雲聳。", "不是真龍不能過，嗔波怒浪澆雷火。", "是歲北極七箇星，一時下降爲門生。", "安仙堂堂冠其首，六星煌煌願隨後。", "騶虞賦就鏗金石，丹水詩成摛錦繡。", "玉皇殿前受恩渥，一時命入芙蓉幕。", "獨得歸州近巫峽，十二晴峰長在睫。", "郡齋狂醉復狂吟，書盡巴東一川葉。", "邇來遊宦五六年，吳山越水供新編。", "還同白傅蘇杭日，歌詩落筆人爭傳。", "去年始上芸香閣，出典陶丘滯鋒鍔。", "阮籍營中浮蟻馨，亞夫門外垂楊弱。", "驥足雖知暫縻絆，樽前未始長嗟歎。", "只應會得老聃言，大器本來成較晚。", "吾君正是興文教，不日徵歸掌綸誥。"]'),
('f918897b-6ac8-4467-ab85-dad500cfdaba','拍板謠','王禹偁','宋','宋诗','song-poetry','','[]','麻姑親採扶桑木，鏤脆排焦其數六。',216,'全唐诗/poet.song.3000.json','["麻姑親採扶桑木，鏤脆排焦其數六。", "雙成捧立王母前，曾按瑶池白雲曲。", "幾時流落來人間，梨園部中齊管絃。", "管絃才動我能應，知音審樂功何全。", "吳宮女兒手如筍，執向玳筵爲樂準。", "數聲慢，仙人屐齒下雲棧。", "老狐臘月渡黄河，緩步輕輕踏冰片。", "數聲急，空江雹打漁翁笠。", "鮫人泣對水精盤，滿把珠璣連瀉入。", "劃然一聲送曲徹，由基射透七重札。", "金罍冷落闃無聞，隴頭凍把泉聲絕。", "律呂與我數自齊，絲竹望我爲宗師。", "總驅節奏在術內，歌舞之人無我欺。", "所以唐相牛僧孺，爲文命之爲樂句。"]'),
('01adaa8b-d1d3-4b99-8717-a45796d75161','對酒吟','王禹偁','宋','宋诗','song-poetry','','[]','勸君莫把青銅照，一瞬浮生何足道。',160,'全唐诗/poet.song.3000.json','["勸君莫把青銅照，一瞬浮生何足道。", "麻姑又採東海桑，閬苑宮中養蠶老。", "任是唐虞與姬孔，蕭蕭寒草埋孤冢。", "我恐自古賢愚骨，疊過北邙高突兀。", "少年對酒且爲娛，幾日樽前垂白髮。", "安得滄溟盡爲酒，滔滔傾入愁人口。", "從他一醉千百年，六轡蒼龍任奔走。", "男兒得志升青雲，須教利澤施于民。", "窮來高枕卧白屋，蕙带藜羹還自足。", "功名富貴不由人，休學唐衢放聲哭。"]'),
('ff5c8cb9-fd2a-4630-ab83-731e57b322e7','戰城南','王禹偁','宋','宋诗','song-poetry','','[]','邊城草樹春無花，秦骸漢骨埋黄沙。',204,'全唐诗/poet.song.3000.json','["邊城草樹春無花，秦骸漢骨埋黄沙。", "陣雲凝著不肯散，胡雛夜夜空吹笳。", "我聞秦築萬里城，疊屍壘土愁雲平。", "又聞漢發五道兵，祁連澤北誇橫行。", "破除璽綬因胡亥，始知禍起蕭牆內。", "耗蠹中原過太半，黄金買酎諸侯叛。", "直饒侵到木葉山，爭似垂衣施廟算。", "大漠由來生醜虜，見日設拜尊中土。", "自古控御全在仁，何必窮兵兼黷武。", "戰城南，年來春草何纖纖。", "窮荒近日恩信霑，寒巖凍岫青如藍。", "方知中國有聖人，塞垣自爾除妖氛。", "河湟父老何忻忻，受降城外重耕耘。"]'),
('b5dc111d-660a-47e7-8b86-828c20e4f272','苦熱行','王禹偁','宋','宋诗','song-poetry','','[]','六龍銜火燒寰宇，魏王冰井如湯煮。',96,'全唐诗/poet.song.3000.json','["六龍銜火燒寰宇，魏王冰井如湯煮。", "松枝桂葉凝若癡，喘殺谿頭嘯風虎。", "北溟鎔却萬丈冰，千斤凍鼠忙如蒸。", "我聞胡土長飛雪，此時日曬地皮裂。", "仙芝瑶草不敢茁，湘川竹焦琅玕折。", "西郊雲好雨不垂，堆青疊碧徒爾爲。"]'),
('1dda594d-3485-414a-b275-4f9c12d16935','瑞蓮歌','王禹偁','宋','宋诗','song-poetry','','[]','江城五月江雨晴，荷花到處紅交橫。',208,'全唐诗/poet.song.3000.json','["江城五月江雨晴，荷花到處紅交橫。", "宋家池上瑞蓮生，嫋嫋出叢抽一莖。", "莖端菡萏開兩朵，忽似娥皇將女英。", "九疑望斷蒼梧暮，低頭並照湘波清。", "花落蓮成碧於卵，瑟瑟塵輕熨人眼。", "蕭郎弄玉合巹時，一齊覆下瑠璃盞。", "草木效靈載圖史，守臣盡可聞天子。", "吾君有詔抑祥瑞，異獸珍禽不爲貴。", "瑞蓮無路達冕旒，也隨衆卉老池頭。", "吏民歸美賀郡守，敢貪天功爲己有。", "古來善政數杜詩，桑無附枝麥兩歧。", "瑞蓮信美産茲土，起予謾作閑歌辭。", "年年更願再熟稻，倉箱免使吾民饑。"]'),
('17b20fa9-0db3-4703-b0ac-18b93526c3c2','筵上狂歌送侍棋衣襖天使','王禹偁','宋','宋诗','song-poetry','','[]','昔事先皇叨近侍，北門西掖清華地。',384,'全唐诗/poet.song.3000.json','["昔事先皇叨近侍，北門西掖清華地。", "太宗多材復多藝，萬機餘暇翻棋勢。", "對面千里爲第一，獨飛天蛾爲第二。", "第三海底取明珠，三陣堂堂皆御製。", "中使宣來示近臣，天機祕密通鬼神。", "乃知棋法同軍法，既誡貪心又嫌怯。", "唯宜靜勝守封疆，不樂窮兵用戈甲。", "先皇三勢有深旨，豈獨一枰而已矣。", "當時受賜感君恩，藏於篋笥傳子孫。", "至道年中出滁上，失脚青雲空悵望。", "移典維揚日望還，軒轅鼎成飛上天。", "龍髯忽斷攀不得，舊朝衣上淚潺湲。", "吾皇曲念先朝物，徵歸再掌西垣筆。", "悲凉忽見紅藥開，哭臨空隨梓宮出。", "去年領郡得齊安，山州僻陋在江干。", "黄民誰識舊學士，白頭猶作老郎官。", "昨日江邊天使到，隨例霑恩著衣襖。", "皇華本是江南客，久侍先皇對棋弈。", "筵中偶說當年事，三勢分明皆記得。", "我從失職別上臺，御書深鎖不將來。", "遥想棋圖在私室，天香散盡空塵埃。", "今日因君聊話及，翻作停杯向隅泣。", "人生不易逢聖朝，君恩未報雙鬢凋。", "金鑾殿花春灼灼，永熙陵樹夜蕭蕭。"]'),
('2f453bb4-b508-433e-a161-22fa36da797c','還楊遂蜀中集','王禹偁','宋','宋诗','song-poetry','','[]','上玄茫昧胡爲乎，施設吾道生吾徒。',336,'全唐诗/poet.song.3000.json','["上玄茫昧胡爲乎，施設吾道生吾徒。", "否多泰少是天意，生有述作死不虛。", "聖人憂患方演易，賢者窮愁始著書。", "盡令富貴陷逸樂，蠢蠢戢戢如鷄豬。", "泯然無物作時瑞，誰識鳳皇與騶虞。", "經史子集燦今古，粉繪帝道張皇謨。", "一言可采即不朽，名姓長與日月俱。", "乃知天心厚我輩，窮辱不足形悲吁。", "夫君擢秀在江左，國小而逼何區區。", "科名始得值兵火，金陵坐見成丘墟。", "歸朝纔得一贊善，黜降重爲縣大夫。", "彰明僻遠在蜀道，又遇妖賊攻成都。", "徒行抱印入隴氐，乞食夷落何崎嶇。", "歸來朝責作主簿，朱衣暗澹鬢毛疏。", "昨朝投我蜀中作，錚然一集如瓊琚。", "杜甫奔竄吟不輟，庾信悲哀情有餘。", "我逢聖代自多難，謾誇三入承明廬。", "近令編綴小畜集，謫官詩什何紛如。", "才名官職不兩立，真宰折刻分毫銖。", "郎官疏遠既未貴，縣吏禮數不足拘。", "相逢且說文章樂，爲君酌酒焚枯魚。"]'),
('7c6dced9-127b-47bf-bda4-36886652233f','啄木歌','王禹偁','宋','宋诗','song-poetry','','[]','淮南啄木大如鴉，頂似仙鶴堆丹砂。',64,'全唐诗/poet.song.3000.json','["淮南啄木大如鴉，頂似仙鶴堆丹砂。", "嘴長數寸勁如鐵，丁丁亂鑿乾枯查。", "黄柑紅桃多有蠹，受命鳳皇須破柱。", "何當更與繡衣裳，羽族橫飛作持斧。"]'),
('5667c112-501c-4481-a11e-e7ef72730712','秋鶑歌','王禹偁','宋','宋诗','song-poetry','','[]','淮南八月尚有鶑，關關無異來時聲。',48,'全唐诗/poet.song.3000.json','["淮南八月尚有鶑，關關無異來時聲。", "東風擡舉如篁舌，何事經秋猶未絕。", "饑鸞病鶴亦能鳴，鳳鳥不聽何處說。"]'),
('953a3b5d-ec5b-4dec-a656-ef543a9c7e68','江豚歌','王禹偁','宋','宋诗','song-poetry','','[]','江豚江豚爾何物，吐浪噴波身突兀。',64,'全唐诗/poet.song.3000.json','["江豚江豚爾何物，吐浪噴波身突兀。", "依憑風水恣豩豪，吞啗魚蝦頗肥腯。", "肉腥骨硬難登俎，雖有網羅嫌不取。", "江雲漠漠江雨來，天意爲霖不干汝。"]'),
('df1bf920-890d-42aa-bbcb-1dcf55a64b9c','宮漏出花遲詩','王禹偁','宋','宋诗','song-poetry','','[]','丹禁遲遲漏，深宮灼灼花。',72,'全唐诗/poet.song.3000.json','["丹禁遲遲漏，深宮灼灼花。", "繁枝開正滿，清韻出何賒。", "靜拂紅英密，微穿翠葉斜。", "依稀驚宿蝶，冷落動晨鴉。", "細逐香離檻，輕翻露滴沙。", "願當直仙署，鈴索共交加。"]'),
('56ceccd3-7efa-4b9d-9bab-e1df293daae8','春晚綠野秀詩','王禹偁','宋','宋诗','song-poetry','','[]','雨過川原上，凝眸送晚春。',72,'全唐诗/poet.song.3000.json','["雨過川原上，凝眸送晚春。", "韶光銷欲盡，野色望來新。", "天末迷藍嶂，江湄亂麴塵。", "重楊難認影，幽鷺莫藏身。", "遠接天開幕，晴和草展茵。", "明時四郊靜，凌亂踏青人。"]'),
('7579f251-5ec2-4646-83dc-83be2a04bc89','四時和爲玉燭詩','王禹偁','宋','宋诗','song-poetry','','[]','堯舜欽天日，羲和正曆時。',72,'全唐诗/poet.song.3000.json','["堯舜欽天日，羲和正曆時。", "銅渾列辰象，玉燭照華夷。", "真宰潛能秉，飛廉詎可吹。", "祥光長赫矣，佳號得溫其。", "銜處非龍首，燃來豈鳳脂。", "皇明方比盛，鑑物自無私。"]'),
('9bf25856-31b6-42c1-ae4c-b883b402b215','五老化流星詩','王禹偁','宋','宋诗','song-poetry','','[]','五老知符命，皤然共效靈。',72,'全唐诗/poet.song.3000.json','["五老知符命，皤然共效靈。", "遊河方告瑞，入昴忽爲星。", "接武傳歌詠，翻身上杳冥。", "來同聚井數，去作種榆形。", "鶴髮光難認，龍圖兆可聽。", "至今依列宿，高印遠天青。"]'),
('0d3f51d3-18a3-47d8-94e9-1b45a3d8c341','東風解凍詩','王禹偁','宋','宋诗','song-poetry','','[]','習習氣初通，峨峨勢自融。',72,'全唐诗/poet.song.3000.json','["習習氣初通，峨峨勢自融。", "淥波歸舊水，寒片漾和風。", "暖想千溪綻，吹疑一夜空。", "鷺翹休映白，魚躍乍翻紅。", "繒裂方塘上，瓊流巨壑中。", "漪漣還浩渺，須頼濟川功。"]'),
('2ba5e580-4227-4a81-9371-c6dffb90f628','笙磬同音詩','王禹偁','宋','宋诗','song-poetry','','[]','鼓簧名本異，拊石意何同。',72,'全唐诗/poet.song.3000.json','["鼓簧名本異，拊石意何同。", "吹擊雖殊致，聲音忽暗通。", "誰將嶰谷韻，潛合泗濱風。", "莫問補天主，休尋入海工。", "鳳鳴應不辨，獸舞自難窮。", "古樂何人會，須知政在中。"]'),
('f0c1301b-1969-43ab-8e74-f2689c06a2e4','乾明節觀羣臣上壽觴詩','王禹偁','宋','宋诗','song-poetry','','[]','甲觀正儲祥，羣臣獻壽觴。',72,'全唐诗/poet.song.3000.json','["甲觀正儲祥，羣臣獻壽觴。", "捧登金殿穩，深照赭袍光。", "環珮和仙樂，衣冠惹御香。", "玄天共悠久，碧海比靈長。", "葵藿心無異，鴛鴻翅有行。", "何當隨近侍，同此祝無疆。"]'),
('12233df8-7420-4f14-be70-72cb21e84d09','甘露降太一宮詩','王禹偁','宋','宋诗','song-poetry','','[]','甘露靄長空，垂休太一宮。',72,'全唐诗/poet.song.3000.json','["甘露靄長空，垂休太一宮。", "瑞光經日在，聖德與天通。", "如醴沾衣白，凝脂間葉紅。", "淋漓滴層漢，顧眄駭重瞳。", "五色名難比，三危味莫同。", "祗應書信史，千古仰玄功。"]'),
('8c64f215-4f8a-4457-b444-7c927ac65494','送交代劉斐裁之大夫','王禹偁','宋','宋诗','song-poetry','','[]','祖孫相望百年間，萬石遺風庶可攀。',64,'全唐诗/poet.song.3000.json','["祖孫相望百年間，萬石遺風庶可攀。", "新詠袴襦傳□巷，舊栽桃李滿淮山。", "林泉豈易留君住，魚鳥真□□我閑。", "好縱齋航天上去，郎闈卿寺有虛班。"]'),
('019b1f51-ee48-4d1f-9606-575944e32163','病起至幽谷二首  其一','王禹偁','宋','宋诗','song-poetry','','[]','□□漳濱幾晦明，起扶藜杖試閑行。',64,'全唐诗/poet.song.3000.json','["□□漳濱幾晦明，起扶藜杖試閑行。", "清泉□□□□□，□□□□□可驚。", "萬壑松聲□□□，□□□□□□□。", "□□□起滄洲趣，便欲投簪此濯纓。"]'),
('153a6a0b-5787-41ce-83af-cb0f60875409','病起至幽谷二首  其二','王禹偁','宋','宋诗','song-poetry','','[]','□□□□□□家，中有流泉一道斜。',64,'全唐诗/poet.song.3000.json','["□□□□□□家，中有流泉一道斜。", "列壑攢峰□□窕，茂林修竹翠交加。", "雨侵怪石苔生暈，水滿平田稻放花。", "乘興偶來心更適，歸時燈火欲棲鴉。"]'),
('3835eada-4ecf-4c60-addc-4ae139d79174','次韻許推官行縣道中紀事','王禹偁','宋','宋诗','song-poetry','','[]','禾頭低映黍頭昂，處處溝塍水面凉。',64,'全唐诗/poet.song.3000.json','["禾頭低映黍頭昂，處處溝塍水面凉。", "村路扶携無凍餒，里門嬉戲有丁黄。", "雞豚入市溪魚美，梨棗登盤社酒香。", "歲樂田家風景好，待君模寫奏明光。"]'),
('7adaefb2-f67b-4d1b-9f17-b4e0c9d528de','闕題','王禹偁','宋','宋诗','song-poetry','','[]','□□□□□□□，□□□□□□□。',64,'全唐诗/poet.song.3000.json','["□□□□□□□，□□□□□□□。", "□□□□带嫩芽，不是貳車無此興。", "此□□□□□□，□□□□□□□。", "□□□□□□□，□□□□□□□。"]'),
('2cc0e053-e53d-4135-96f2-f6d8a638dbdb','正月盡偶題','王禹偁','宋','宋诗','song-poetry','','[]','一歲春光九十日，三分已是一分休。',64,'全唐诗/poet.song.3000.json','["一歲春光九十日，三分已是一分休。", "何曾快見花燒眼，只解潛催雪滿頭。", "莫問窮通求季主，自齊生死學莊周。", "終須擺脫人間事，高逐冥鴻狎海鷗。"]'),
('19e19532-9925-484e-85d6-490d3f5989a9','眼疾','王禹偁','宋','宋诗','song-poetry','','[]','古人功業甘無分，往聖詩書合有緣。',32,'全唐诗/poet.song.3000.json','["古人功業甘無分，往聖詩書合有緣。", "何事病來花滿眼，祇將簡策枕頭眠。"]'),
('e3c2246a-42b9-4385-a937-758019cc810c','望熊耳山','王禹偁','宋','宋诗','song-poetry','','[]','謫居多與俗爲鄰，熊耳當門入望頻。',32,'全唐诗/poet.song.3000.json','["謫居多與俗爲鄰，熊耳當門入望頻。", "感謝雙峰對雙眼，也勝逢見等閑人。"]'),
('3e8f03d6-18ae-47ed-9b1f-0916379752c0','闕題  其一','王禹偁','宋','宋诗','song-poetry','','[]','□□□□□□□，□□□□□□□。',32,'全唐诗/poet.song.3000.json','["□□□□□□□，□□□□□□□。", "□□□□□□□，□負穠華一句無。"]'),
('b4fba2cc-5f2a-4c14-9198-a26bca478b77','闕題  其二','王禹偁','宋','宋诗','song-poetry','','[]','不知鳴玉谿山下，何似仙娥水石間。',32,'全唐诗/poet.song.3000.json','["不知鳴玉谿山下，何似仙娥水石間。", "免被尋常桃李妬，自開自落隠商山。"]'),
('c87691d5-9185-4c20-9524-8861701b8dc1','和仲咸除知郡後雨中戲作見贈','王禹偁','宋','宋诗','song-poetry','','[]','明代何人爲薦雄，專城猶與衆人同。',64,'全唐诗/poet.song.3000.json','["明代何人爲薦雄，專城猶與衆人同。", "徒聞清政如黄霸，尚借緋衫似白公。", "我有金章知是忝，君無銀榼信爲窮。", "不須厭見隨車雨，歲晚當期五穀豐。"]'),
('21bca2f0-f684-441e-b02c-d4b4abf17140','又和仲咸謔成口號以代優人之句','王禹偁','宋','宋诗','song-poetry','','[]','就轉專城喜氣舒，開筵應待雨晴初。',64,'全唐诗/poet.song.3000.json','["就轉專城喜氣舒，開筵應待雨晴初。", "又淹駮正春坊筆，爲重循良刺史車。", "事簡郡齋唯撿藥，夜長鈴閤只看書。", "好傾官醖招閑客，籬畔金英尚有餘。"]'),
('b1726a67-ab31-4f6b-ba3d-f8af3ea3480e','移入官舍偶題四韻呈仲咸','王禹偁','宋','宋诗','song-poetry','','[]','賃舍喧卑謫宦情，同年邀我住公庭。',64,'全唐诗/poet.song.3000.json','["賃舍喧卑謫宦情，同年邀我住公庭。", "不離鍊藥煎茶屋，便坐吟詩看雪廳。", "苔逕乍行侵屐綠，竹窗初卧滿床青。", "使君公署雖宏敞，未見南山翠似屏。"]'),
('2824fa2f-37e7-4eca-a277-693712e2ff5d','仲咸借予海魚圖觀罷有詩因和','王禹偁','宋','宋诗','song-poetry','','[]','偶費霜縑與綵毫，海魚圖畫滿波濤。',64,'全唐诗/poet.song.3000.json','["偶費霜縑與綵毫，海魚圖畫滿波濤。", "搘床難死慚龜殻，把酒狂歌憶蟹螯。", "鯧蚱脚多垂似带，鋸鯊齒密利如刀。", "何當一一窮真僞，須把千尋鐵網撈。"]'),
('41e50430-dde4-4127-b0ca-04c096572701','贈商洛龐主簿','王禹偁','宋','宋诗','song-poetry','','[]','織女溪前貧主簿，仙娥峰下舊詞臣。',64,'全唐诗/poet.song.3000.json','["織女溪前貧主簿，仙娥峰下舊詞臣。", "久棲枳棘方思替，謾带貂蟬不是真。", "六里青山雲簇簇，一條丹水石嶙嶙。", "秋來魂夢應相似，同是帝城東畔人。"]'),
('bf8177b0-10e6-457a-a159-e22e6de89d8e','商州進士張齊說將赴春闈以詩別馮中允馮君酬和予亦次韻繼之','王禹偁','宋','宋诗','song-poetry','','[]','風雪騎馿去入關，試期難伴貳車閑。',64,'全唐诗/poet.song.3000.json','["風雪騎馿去入關，試期難伴貳車閑。", "桃花好躍三門浪，芝草休尋六里山。", "錫宴待吟春爛漫，舊房從鎖石孱顔。", "明年得意歸來日，不見麻衣泣玉班。"]'),
('cee02c94-948b-4fe9-86dc-d35b1e0c35a2','再賦一章用伸贈別','王禹偁','宋','宋诗','song-poetry','','[]','七榜御前搜俊造，商州終未識遷鶑。',64,'全唐诗/poet.song.3000.json','["七榜御前搜俊造，商州終未識遷鶑。", "可憐白屋孤寒士，更住深山寂寞城。", "獨跨蹇馿雲外去，仍携稚子雪中行。", "散官不敢將書薦，空解吟詩說姓名。"]'),
('bddd391a-2024-43e4-a876-5c4880a6b583','仲咸見予一百六十韻賦詩相贈因以四韻答之','王禹偁','宋','宋诗','song-poetry','','[]','勞將詩什比兵權，兵數雖多氣不全。',64,'全唐诗/poet.song.3000.json','["勞將詩什比兵權，兵數雖多氣不全。", "烏合師徒空百萬，虎賁精銳只三千。", "揚鑣正突漁陽騎，避箭甘回赤壁船。", "若許英雄君與操，更當劘勵整櫜鞬。"]'),
('28159209-c98b-4669-a2b8-f3373a508765','次韻和仲咸感懷貽道友  其一','王禹偁','宋','宋诗','song-poetry','','[]','莫問窮通事若何，遇花逢酒且狂歌。',64,'全唐诗/poet.song.3000.json','["莫問窮通事若何，遇花逢酒且狂歌。", "人情易逐炎凉改，官路難防陷穽多。", "只合收心拋世網，不須推命說天羅。", "如今玉石休分別，免被無辜刖卞和。"]'),
('bffcebca-c9e1-4c8c-9ed7-d4e26fbcbd69','次韻和仲咸感懷貽道友  其二','王禹偁','宋','宋诗','song-poetry','','[]','好齊生死與窮通，古往今來事略同。',64,'全唐诗/poet.song.3000.json','["好齊生死與窮通，古往今來事略同。", "軒后謾留燒藥鼎，漢皇虛築望仙宮。", "鑑中容鬢看看老，夢裏榮枯旋旋空。", "不逐冥鴻天外去，可憐燋爛撲燈蟲。"]'),
('49c31db2-af9d-42d6-b42d-fd194b01a0bd','次韻和仲咸對雪散吟三十韻','王禹偁','宋','宋诗','song-poetry','','[]','靜對春天雪，時烹月俸茶。',288,'全唐诗/poet.song.3000.json','["靜對春天雪，時烹月俸茶。", "久閑便澹薄，漸老厭諠譁。", "徙倚終朝看，溟濛向曉加。", "應同頭上髮，復亂眼中花。", "光暝侵燈暗，聲繁拂竹斜。", "東風吹片片，北戶積些些。", "最豁三農望，勻淹百草芽。", "潤勝天上露，媚掩日邊霞。", "史筆應先紀，豐年的不賒。", "舞縈農叟袂，飄逐使君車。", "善政商於郡，優閑副使家。", "酒錢隨分有，詩筆且須誇。", "岸灑泉聲好，園滋薺色嘉。", "無心思北闕，有興讀南華。", "地隠商於洛，山綿楚與巴。", "拖腸甘似鼠，畫足不爭蛇。", "有病如原憲，無才敵景差。", "由來叩寂寞，全勝事驕奢。", "世態誠堪笑，前賢亦可嗟。", "絳侯憎賈誼，白傅怨王涯。", "宣室終前席，潯陽暫種畬。", "升沉常自得，消息一何佳。", "自顧曾傷翼，甘同不食瓜。", "但全螻蟻命，敢鬭虎狼牙。"]'),
('2d238237-91d1-4ff4-a900-aa6408265570','春日','王禹偁','宋','宋诗','song-poetry','','[]','門冷官閑似死灰，人言今日是春來。',32,'全唐诗/poet.song.3000.json','["門冷官閑似死灰，人言今日是春來。", "猶殘舊賜銀幡勝，且向山州當酒杯。"]'),
('386e3a94-4587-44be-841a-2b944a99aeae','問四皓','王禹偁','宋','宋诗','song-poetry','','[]','四塚纍纍豈是仙，避秦安漢道空全。',32,'全唐诗/poet.song.3000.json','["四塚纍纍豈是仙，避秦安漢道空全。", "紫芝探處應辛苦，何似腰金食萬錢。"]'),
('0ae6881d-e266-40c4-ba23-357d652f4c2d','代答','王禹偁','宋','宋诗','song-poetry','','[]','何必驂鸞上五雲，由來吾道貴全身。',32,'全唐诗/poet.song.3000.json','["何必驂鸞上五雲，由來吾道貴全身。", "君看白日沖霄者，多是偷桃竊藥人。"]'),
('ee713bd7-adb1-4332-be44-af4dd0ae6eb7','和仲咸杏花三絕句  其一','王禹偁','宋','宋诗','song-poetry','','[]','莫道商山節候遲，曉來簾外半空枝。',32,'全唐诗/poet.song.3000.json','["莫道商山節候遲，曉來簾外半空枝。", "明朝落盡無蜂蝶，冷暖人情我最知。"]'),
('a7efc457-11c0-4a54-977b-3a519cacd9b7','和仲咸杏花三絕句  其二','王禹偁','宋','宋诗','song-poetry','','[]','階前已見三分落，枝上都無十日繁。',32,'全唐诗/poet.song.3000.json','["階前已見三分落，枝上都無十日繁。", "誰伴多情王副使，吟詩傾酒與招魂。"]'),
('043b8aa2-4d93-460e-b47e-41cd93e78b64','和仲咸杏花三絕句  其三','王禹偁','宋','宋诗','song-poetry','','[]','老去對花多感嘆，春來耽酒少康寧。',32,'全唐诗/poet.song.3000.json','["老去對花多感嘆，春來耽酒少康寧。", "也知此事終無益，免被漁人笑獨醒。"]'),
('8c001419-e376-4eb5-a6f9-dd3a15ec32f9','知州廳杏花昨日爛漫錄事院今日零落唯副使公署未開戲題二韻','王禹偁','宋','宋诗','song-poetry','','[]','知州宅畔繁如雪，錄事廳前落似梅。',32,'全唐诗/poet.song.3000.json','["知州宅畔繁如雪，錄事廳前落似梅。", "副使官閑花亦冷，至今未有一枝開。"]'),
('e9d4e300-1a5c-48a2-95a4-8c69c67f58f4','海棠木瓜二絕句 海棠贈木瓜','王禹偁','宋','宋诗','song-poetry','','[]','我向商山占斷春，風流還似錦江濱。',32,'全唐诗/poet.song.3000.json','["我向商山占斷春，風流還似錦江濱。", "羣花自合知羞耻，莫對西施更學顰。"]'),
('1d38dece-4c40-40e4-a6ca-a102052e2c8e','海棠木瓜二絕句 木瓜答海棠','王禹偁','宋','宋诗','song-poetry','','[]','莫誇顔色鬭扶疏，穠艷繁香總是虛。',32,'全唐诗/poet.song.3000.json','["莫誇顔色鬭扶疏，穠艷繁香總是虛。", "看取衛風詩什裏，只因投我得瓊琚。"]'),
('bcc6f192-98ad-4ea6-86c4-627234572a3e','仲咸以予編成商於唱和集以二十韻詩相贈依韻和之','王禹偁','宋','宋诗','song-poetry','','[]','詩戰雖非敵，吟多偶自編。',240,'全唐诗/poet.song.3000.json','["詩戰雖非敵，吟多偶自編。", "齊强侵北鄙，許敗守東偏。", "猶恨多虛日，何妨且繫年。", "龍媒難趁逐，駑駕頼驅牽。", "拙句傳非夢，雄詞縱自天。", "一嘲花灼灼，再詠雁翩翩。", "白雪終無繼，洪崖謾拍肩。", "驂鸞元在漢，墮鼠不成仙。", "硎發鋒鋩利，衡誠勢力懸。", "石因良玉潤，褧借錦衣鮮。", "糠籺豪家笑，鉶羹古味全。", "虎鹽宜燕享，猴棘謾雕鎸。", "我筆非江氏，君才比孟堅。", "豈勞開蒨旆，早合步花磚。", "重甚連城璧，精於萬選錢。", "西江聞祖德，南國許名賢。", "夜閣調琴月，秋堂煮茗煙。", "淡交輕勢利，孤達鄙榮遷。", "媚挹懷珠水，幽聽噴玉泉。", "謫居叨屬和，都志命迍邅。"]'),
('2f5960d6-fd01-4a6e-b600-c09db5aef3e9','仲咸以一秋苦雨兩日忽晴以四韻見寄因次原韻兼紓客情','王禹偁','宋','宋诗','song-poetry','','[]','愁霖百日思低迷，昨夜星辰似舊時。',64,'全唐诗/poet.song.3000.json','["愁霖百日思低迷，昨夜星辰似舊時。", "稼穡已傷憂客計，津梁全壞怯歸期。", "丹河浪減沙痕漲，錦嶺霜晴月影遲。", "喜霽未遑抽賦筆，勞君先惠碧雲詩。"]'),
('057028be-71bd-4b78-9470-908df2e99d26','唱和暫停霖淫復作因書四韻呈仲咸兼簡宋從事','王禹偁','宋','宋诗','song-poetry','','[]','山雲漠漠雨霏霏，正是騷人唱和時。',64,'全唐诗/poet.song.3000.json','["山雲漠漠雨霏霏，正是騷人唱和時。", "謫宦慚無賈生賦，愁霖合有謝公詩。", "已妨步月塵凝榭，恐誤登高菊滿籬。", "且喜賓筵得同道，不爲篇什欲何爲。"]'),
('645257ae-ba6a-4a2b-9e8b-52c214aaf55a','次韻和仲咸送池秀才西遊','王禹偁','宋','宋诗','song-poetry','','[]','夏課詩成又旅遊，離離秦樹葉驚秋。',64,'全唐诗/poet.song.3000.json','["夏課詩成又旅遊，離離秦樹葉驚秋。", "青霄路在何難到，白雪才高豈易酬。", "幾處讀碑尋野逕，共誰沽酒上高樓。", "商於遷客曾如此，繫滯空思十二旒。"]'),
('8272b474-c23e-43af-a117-30ee34b211fd','與方演寺丞覓盆池','王禹偁','宋','宋诗','song-poetry','','[]','謫宦門牆冷似村，看山廳下露莎繁。',32,'全唐诗/poet.song.3000.json','["謫宦門牆冷似村，看山廳下露莎繁。", "涵星泳月無池沼，請致泓澄數斛盆。"]'),
('ea2eb102-302e-4c56-8424-afa8502abcc7','仲咸因春遊商山下得三怪石輦致郡齋甚有幽趣序其始末題六十韻見示依韻和之','王禹偁','宋','宋诗','song-poetry','','[]','詠盡千峰雪，吟行六里春。',288,'全唐诗/poet.song.3000.json','["詠盡千峰雪，吟行六里春。", "布多成暇政，方稱好閑身。", "物得商山下，形如震澤根。", "初期穀城叟，乍遇魏榆神。", "固異它山石，還同似玉珉。", "繞看猶汩沒，斲見漸輪囷。", "草擁才抽甲，煙封幾得辛。", "綠藏苔漠漠，青亂葉蓁蓁。", "蛟蜃渾疑活，琳琅勢逼真。", "杖敲清有韻，衣拂瑩無塵。", "起似生徐甲，扶如醉伯倫。", "知吾憐磊落，移爾出荒榛。", "留滯誠爲久，遭逢蓋有因。", "勝携墮鵲印，喜過駭鷄玲。", "齊列幽齋畔，休藏古澗濱。", "未邀耽酒客，先對抱琴人。", "带蘚形雖瘦，穿交氣已振。", "自非懷峭絕，安得免沉淪。", "月影無雲夕，煙姿有雪辰。", "參差光互動，高下勢相均。", "接待同嘉士，搜求等雋民。", "蒼茫勞拂拭，感遇似陶鈞。", "撫惜情如舊，裝添景自新。", "窗風聲淅淅，簷鳥語欣欣。"]'),
('770173f4-27c6-4bd9-b854-788247689c37','酬仲咸雪霽春融偶題見寄之什','王禹偁','宋','宋诗','song-poetry','','[]','瓊華消散暖風來，多費陽春白雪才。',64,'全唐诗/poet.song.3000.json','["瓊華消散暖風來，多費陽春白雪才。", "守道也知心下樂，流年爭奈鬢邊催。", "君愁離別煙花好，我待量移翅羽開。", "漸老分飛更堪惜，海棠凋盡始應回。"]'),
('9aae5e70-e8fd-4d73-9415-3183c43185d2','和安邑劉宰君見贈','王禹偁','宋','宋诗','song-poetry','','[]','數年侍從立丹墀，掌誥長慚格調卑。',64,'全唐诗/poet.song.3000.json','["數年侍從立丹墀，掌誥長慚格調卑。", "左宦久勞青瑣夢，歸山猶負白雲期。", "一生得喪唯憑道，千古聲名合在詩。", "深謝多才遺佳句，此身休退是何時。"]'),
('4ccbd18b-b856-49cb-b398-3f9b95e16e2e','朗上人見訪復謁不遇留刺而還有詩見謝依韻和答','王禹偁','宋','宋诗','song-poetry','','[]','湯休訪我我重尋，獨叩松關絕好音。',64,'全唐诗/poet.song.3000.json','["湯休訪我我重尋，獨叩松關絕好音。", "滿袖塵埃回俗步，一鑪香火隔禪林。", "偶留刺字情非淺，忽枉詩章思更深。", "猶喜謫官無吏役，往來從此伴閑吟。"]'),
('ddbe8ffd-5d6b-47fb-b282-c9bb8c5e02f9','次韻和朗公見贈','王禹偁','宋','宋诗','song-poetry','','[]','朗公垂老尚吟詩，曾泛三湘看九疑。',64,'全唐诗/poet.song.3000.json','["朗公垂老尚吟詩，曾泛三湘看九疑。", "欲問勞生心擾擾，强酬佳句思遲遲。", "紅塵策馬殊無味，碧嶂携僧自合宜。", "共待中條山有雪，寺樓吟盡更同誰。"]'),
('a77a0574-82d2-42de-a433-5e1665b8dbb4','鹽池十八韻','王禹偁','宋','宋诗','song-poetry','','[]','極望似江沱，漫漫起素波。',216,'全唐诗/poet.song.3000.json','["極望似江沱，漫漫起素波。", "兩池泉不竭，萬古利還多。", "場吏輸年額，畦丁奉月課。", "收時車併載，種處地先磨。", "碎顆珠淩亂，乾聲玉切瑳。", "岸平開雪苑，渠滲坼銀河。", "衆鵠齊翔舞，群羊自寢訛。", "本源皆潟滷，異端亦鹹鹺。", "沫訝浮鷗鷺，津堪漬蚌螺。", "煮勞輕渤澥，煎苦笑牂牁。", "雨打重歸水，菴盛更覆蓑。", "盬風吹作片，烈日曬成垛。", "海末知難及，蕃青的不過。", "惠人餐罔闕，均□賦無頗。", "涿鹿城雖近，蚩尤血若何。", "有時紅爛漫，是處白嵯峨。", "潤下終資國，靈長任酌蠡。", "江梅須待我，金鼎始能和。"]'),
('bf3f394a-1271-42d2-8583-e1ed4ff35d5f','賃宅','王禹偁','宋','宋诗','song-poetry','','[]','萍流匏繫任行藏，惟指無何是我鄉。',64,'全唐诗/poet.song.3000.json','["萍流匏繫任行藏，惟指無何是我鄉。", "左宦只拋紅藥案，僦居猶住玉泉坊。", "白公渭北眠村舍，杜甫瀼西賃草堂。", "未有吾廬莫惆悵，古來賢達盡茫茫。"]'),
('da171ef7-81a7-463e-bfe6-ddc014b778ef','題滁州懷嵩樓','王禹偁','宋','宋诗','song-poetry','','[]','昔是優賢地，今爲省過州。',24,'全唐诗/poet.song.3000.json','["昔是優賢地，今爲省過州。", "非賢亦非過，醉卧懷嵩樓。"]'),
('8309720e-8d37-4a71-8a56-a5b1da12fa3e','次韻和史館丁學士赴闕書懷見示','王禹偁','宋','宋诗','song-poetry','','[]','清夜哀吟敵曉鷄，行藏無玷白於圭。',64,'全唐诗/poet.song.3000.json','["清夜哀吟敵曉鷄，行藏無玷白於圭。", "陽春寡和人傳郢，肉味都忘子在齊。", "絕俗文章終遠大，循資班列暫卑棲。", "看君更刷鸞皇翼，一舉方知燕雀低。"]'),
('ddbec5ce-e119-4911-8b72-33839f2d36d3','次韻和丁學士途中偶作','王禹偁','宋','宋诗','song-poetry','','[]','淮海豐登接帝畿，家家耕破舊荒陂。',64,'全唐诗/poet.song.3000.json','["淮海豐登接帝畿，家家耕破舊荒陂。", "乳牛引犢精神健，野叟携孫鬢髮衰。", "河市妓翻輕蒨袖，社筵人插小紅旗。", "憑誰畫取村田樂，盡使憂民聖主知。"]'),
('53e10c62-0223-46c2-9f86-b38345d5ecd4','出守黄州上史館相公','王禹偁','宋','宋诗','song-poetry','','[]','出入西垣與內廷，十年四度直承明。',64,'全唐诗/poet.song.3000.json','["出入西垣與內廷，十年四度直承明。", "又爲太守黄州去，依舊郎官白髮生。", "貧有妻賢須薄祿，老無田宅可歸耕。", "未甘便葬江魚腹，敢向台階請罪名。"]'),
('92b0bec9-0d3b-47e9-926e-541e4752f673','栽木芙蓉','王禹偁','宋','宋诗','song-poetry','','[]','憶在長洲縣，手植芙蓉花。',264,'全唐诗/poet.song.3000.json','["憶在長洲縣，手植芙蓉花。", "春栽秋成樹，枝葉青婆娑。", "八月寒露下，朵朵開紅葩。", "輕團蜀江錦，碎剪赤城霞。", "香侵賓朋坐，艷拂人吏衙。", "凌霜伴松菊，滿地如桑麻。", "歲寒萬木脫，斫筍留根查。", "春雷一聲動，又長新枝柯。", "良因地脈宜，豈在人力多。", "今來帝城裏，賃宅如蜂窠。", "階前栽數根，換土擁新沙。", "澆溉汲御溝，蓋覆堆野莎。", "經春不出土，入夏方有芽。", "窮秋竟憔悴，花小尤不嘉。", "地氣移物性，自念良可嗟。", "還同山野人，强爲簪組加。", "妨賢將致誚，薄俸未充家。", "所以多病身，少年雙鬢華。", "紫微雖云貴，白髮將奈何。", "會當求山郡，卧理尋煙蘿。", "奉親冀豐足，委身任蹉跎。", "終焉太平世，散地恣狂歌。"]'),
('3bc316d2-3ff5-41d7-b837-fbdc69f218ce','聽羅評事話太湖洞庭之景因賦十韻','王禹偁','宋','宋诗','song-poetry','','["\u592a\u6e56", "\u6d1e\u5ead\u6e56"]','思純十日水鄉游，歸見同年說不休。',160,'全唐诗/poet.song.3000.json','["思純十日水鄉游，歸見同年說不休。", "湖闊盡疑吞澤國，洞深皆道徹宣州。", "杉松自宿千年鶴，橘柚堪輕萬戶侯。", "銷夏古灣長積雪，隔帆危柱幾經秋。", "離離魚網垂村巷，漠漠茶煙出寺樓。", "雲葉擁僧迎墨綬，浪花和鷺裹仙舟。", "傳書往事人難問，鍊藥池空水自流。", "明月峰高欺少室，桃花塢好似瀛洲。", "許渾有句君應笑，張祜無詩我不愁。", "直擬如今拋印去，雨蓑風艇狎羣鷗。"]'),
('a94d1367-be10-47a5-a9ce-720a7de8689e','登秦嶺','王禹偁','宋','宋诗','song-poetry','','[]','巉巖石上候肩舁，因想前賢似坦途。',64,'全唐诗/poet.song.3000.json','["巉巖石上候肩舁，因想前賢似坦途。", "韓愈謫官憂瘴癘，樂天左宦白髭鬚。", "商於郡僻何人到，秦嶺峰高我僕痡。", "且詠詩章自開解，任從霄漢落泥塗。"]'),
('a6bae70b-b69d-441b-9acf-e2b6d7cd4d32','贈种放處士','王禹偁','宋','宋诗','song-poetry','','[]','媒雉不誘鳳，由鹿不致麟。',288,'全唐诗/poet.song.3000.json','["媒雉不誘鳳，由鹿不致麟。", "終南有嘉士，天子不得臣。", "板輿入窮谷，同隠之推親。", "種木山之阿，採蘭澗之濱。", "務本不務末，求力不求人。", "至孝在盡歡，飲水猶欣欣。", "富貴不以道，列鼎奚足云。", "行是有餘力，稽古且學文。", "稽古不爲祿，學問非飾身。", "立言復垂教，楊孟時有倫。", "我生落世網，碌碌隨搢紳。", "直躬多齬齟，左官苦漂淪。", "妻孥困斗粟，親老無重茵。", "入山非隠遁，去國頗悲辛。", "猶顧貳車祿，縻縶丹河濱。", "羨君脫覊鞅，生計在水雲。", "羨君遺榮利，居處絕囂塵。", "躬耕方肯食，恐蠹力穡民。", "學優終不仕，孰爲觀國賓。", "去去謝桂籍，行行避薄輪。", "巢由自高尚，堯舜徒聖神。", "况我蜉蝣輩，敢希鸞鳳羣。", "猶期不遠復，一問迷途津。", "他年解郡職，願許我爲鄰。"]'),
('20ec191a-77f7-49a9-89c7-b37f603a42a3','寄鄆城蕭處士','王禹偁','宋','宋诗','song-poetry','','[]','收藏家譜恐人尋，雨笠煙蓑自稱心。',64,'全唐诗/poet.song.3000.json','["收藏家譜恐人尋，雨笠煙蓑自稱心。", "夜踏月華三逕小，曉耕秋色一犂深。", "庭園縱窄猶栽藥，活計雖貧不賣琴。", "應笑區區未名客，九衢塵土滿衣襟。"]'),
('d88ace20-557c-428c-baff-4a1ca92b64db','寄潘閬處士','王禹偁','宋','宋诗','song-poetry','','[]','爛醉狂歌出上都，秋風時節憶鱸魚。',64,'全唐诗/poet.song.3000.json','["爛醉狂歌出上都，秋風時節憶鱸魚。", "江城賣藥長將鶴，古寺看碑不下馿。", "一片野心雲出岫，幾莖吟髮雪侵梳。", "算應冷笑文場客，歲歲求人薦子虛。"]'),
('047df94a-21e0-4b79-a0f2-87523f098c0d','寄汶陽田告處士','王禹偁','宋','宋诗','song-poetry','','[]','汶水年來漲綠波，先生居此興如何。',64,'全唐诗/poet.song.3000.json','["汶水年來漲綠波，先生居此興如何。", "門連別浦閑垂餌，宅枕平沙好種莎。", "治水共誰言鯀禹，著書空自繼丘軻。", "可憐垂白無人問，却伴漁翁著釣蓑。"]'),
('b8a3c78a-6810-44f1-b026-083516ed0078','贈郝處士','王禹偁','宋','宋诗','song-poetry','','[]','盡見閑人話息機，唯君的箇厭輕肥。',64,'全唐诗/poet.song.3000.json','["盡見閑人話息機，唯君的箇厭輕肥。", "盤中藥菜真僧舍，篋裏烟霞舊道衣。", "江渚鷗鷳情已狎，洛陽櫻筍夢應稀。", "縣齋喜與書齋近，公暇何妨扣竹扉。"]'),
('4887a9c7-2a69-4f63-9323-5edbac8efddf','贈孫何丁謂','王禹偁','宋','宋诗','song-poetry','','[]','三百年來文不振，直從韓柳到孫丁。',32,'全唐诗/poet.song.3000.json','["三百年來文不振，直從韓柳到孫丁。", "如今便可令修史，二子文章似六經。"]'),
('efc1ab1b-e4cc-4131-91d2-8b1f6ee72e6f','詠白蓮','王禹偁','宋','宋诗','song-poetry','','[]','昨夜三更後，姮娥墮玉簪。',24,'全唐诗/poet.song.3000.json','["昨夜三更後，姮娥墮玉簪。", "馮夷不敢受，捧出碧波心。"]'),
('67f8322b-ed75-4576-a1c8-ed1c31caa1dc','詠石榴花','王禹偁','宋','宋诗','song-poetry','','[]','王母庭中親見栽，張騫偷得下天來。',32,'全唐诗/poet.song.3000.json','["王母庭中親見栽，張騫偷得下天來。", "誰家巧婦殘針線，一撮生紅熨不開。"]'),
('4d08dc36-350a-4904-b8b4-625cd59d5ae4','錫宴清明日','王禹偁','宋','宋诗','song-poetry','','[]','宴罷回來日欲斜，平康坊裏那人家。',32,'全唐诗/poet.song.3000.json','["宴罷回來日欲斜，平康坊裏那人家。", "幾多紅袖迎門笑，爭乞釵頭利市花。"]'),
('8c9a73bd-9c64-4f66-a4e8-1722bdc17c03','磨詩','王禹偁','宋','宋诗','song-poetry','','[]','但存心裏正，無愁眼下遲。',24,'全唐诗/poet.song.3000.json','["但存心裏正，無愁眼下遲。", "若人輕著力，便是轉身時。"]'),
('40169c77-72a8-4416-9e89-7f9b3972b9a7','洞庭山','王禹偁','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','吳山無此秀，乘暇一遊之。',48,'全唐诗/poet.song.3000.json','["吳山無此秀，乘暇一遊之。", "萬頃湖光裏，千家橘熟時。", "平看月上早，遠覽鳥歸遲。", "近古誰真賞，白雲應得知。"]'),
('e9ebfbe8-c69a-473e-8271-8db341d5d222','詩一首','王禹偁','宋','宋诗','song-poetry','','[]','徒勞官職在天涯，一望家園一淚垂。',32,'全唐诗/poet.song.3000.json','["徒勞官職在天涯，一望家園一淚垂。", "不是虎丘多勝概，拂衣歸去已多時。"]'),
('dfeb04c0-4e4f-4630-81aa-ac6c99450113','松江亭  其一','王禹偁','宋','宋诗','song-poetry','','[]','登臨陡覺挹塵埃，時有清風颯滿懷。',64,'全唐诗/poet.song.3000.json','["登臨陡覺挹塵埃，時有清風颯滿懷。", "螮蝀一條連古岸，玻璃萬頃自天來。", "寒光浩渺輕煙闊，綠玉參差遠岫排。", "南指閩山猶萬里，遠人歸興正無涯。"]'),
('c26fbead-db97-47b8-a3a1-dc8657b4f486','松江亭  其二','王禹偁','宋','宋诗','song-poetry','','[]','中郎亭樹據江鄉，雅稱詩翁賦醉章。',64,'全唐诗/poet.song.3000.json','["中郎亭樹據江鄉，雅稱詩翁賦醉章。", "蒓菜鱸魚好時節，晚風斜日舊煙光。", "一杯有味功名小，萬事無心歲月長。", "安得便拋塵網去，釣舟閑倚畫欄旁。"]'),
('b2b1fc25-a391-4811-974a-673487591ec8','長洲種牡丹','王禹偁','宋','宋诗','song-poetry','','[]','偶學豪家種牡丹，數枝擎露出朱欄。',32,'全唐诗/poet.song.3000.json','["偶學豪家種牡丹，數枝擎露出朱欄。", "晚來低面開檀口，似笑窮愁病長官。"]'),
('3ebcdd48-cc81-43e4-b9f3-f2bf3e97d00b','長洲遣興  其一','王禹偁','宋','宋诗','song-poetry','','[]','七十浮生已半生，徒勞何日見功名。',64,'全唐诗/poet.song.3000.json','["七十浮生已半生，徒勞何日見功名。", "折腰米賤堪羞死，負郭田荒好力耕。", "庭鶴慣侵孤坐影，鄰雞應信夜吟聲。", "年來更待賢良詔，咫尺松江未濯纓。"]'),
('5851d924-f550-45e5-a159-9fd79c180c54','長洲遣興  其二','王禹偁','宋','宋诗','song-poetry','','[]','妻兒莫笑甑中塵，只患功名不患貧。',64,'全唐诗/poet.song.3000.json','["妻兒莫笑甑中塵，只患功名不患貧。", "自覺有文行古道，可能無位泰生民。", "烟村舊業勞歸夢，雪屋孤燈照病身。", "投老綠袍未休去，九重天子用平人。"]'),
('03a86985-b634-4620-9ddc-4ce05bc15046','詩一首','王禹偁','宋','宋诗','song-poetry','','[]','盡怪吳蘇地，瓊花冷不銷。',120,'全唐诗/poet.song.3000.json','["盡怪吳蘇地，瓊花冷不銷。", "時賢臨水國，天氣似中朝。", "密逐江雲墮，輕隨海吹飄。", "影沉松塢亂，片響葦蓬焦。", "粉拂龍頭舫，繒鋪雁齒橋。", "煮茶收歲計，宜稻採民謠。", "拔笋芽先出，欺梅蕊自凋。", "誰言未盈尺，猶稱不封條。", "郡守齊黄霸，明君邁帝堯。", "縣官惜歌詠，翻恐笑漁樵。"]'),
('61bb2cb3-100f-4920-a611-d341446c8db2','憶舊游寄致仕了倩寺丞','王禹偁','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','橋映家家柳，涇通處處蓮。',48,'全唐诗/poet.song.3000.json','["橋映家家柳，涇通處處蓮。", "海山微出地，湖水遠同天。", "草沒潮泥上，沙明蟹火然。", "應隨白太守，十隻洞庭船。"]'),
('34d6c30e-292e-4659-9bce-0170486475b5','清明感事  其一','王禹偁','宋','宋诗','song-poetry','','["\u6e05\u660e\u8282", "\u6e05\u660e", "\u751f\u6d3b", "\u51c4\u82e6"]','無花無酒過清明，興味蕭然似野僧。',32,'全唐诗/poet.song.3000.json','["無花無酒過清明，興味蕭然似野僧。", "昨夜鄰家乞新火，曉窗分與讀書燈。"]'),
('a9b0e3fd-a0fd-46a2-9d80-ca205bdf3e3a','清明感事  其二','王禹偁','宋','宋诗','song-poetry','','[]','日轉鞦韆影漸斜，忍聞絃管在鄰家。',32,'全唐诗/poet.song.3000.json','["日轉鞦韆影漸斜，忍聞絃管在鄰家。", "兒童不慣貧滋味，剛拾榆錢索買花。"]'),
('86b390fd-c300-4db4-8307-67929a527f80','清明感事  其三','王禹偁','宋','宋诗','song-poetry','','[]','榆錢零落麥開芒，魂斷南軒蝶影雙。',32,'全唐诗/poet.song.3000.json','["榆錢零落麥開芒，魂斷南軒蝶影雙。", "多謝東風相管顧，解將花片入書窗。"]'),
('d40dac76-99cc-40cf-b776-ff5ab93e944d','中秋月','王禹偁','宋','宋诗','song-poetry','','[]','明可鑑秋毫，供吟屬我曹。',48,'全唐诗/poet.song.3000.json','["明可鑑秋毫，供吟屬我曹。", "隔年方得見，終夕敢辭勞。", "冷向天心白，清臨露掌高。", "霜臺相照處，寒色滿藍袍。"]'),
('847c6f81-af5a-4aed-816a-9d6459532d57','谷簾水','王禹偁','宋','宋诗','song-poetry','','[]','瀉從千仞石，寄逐九江船。',36,'全唐诗/poet.song.3000.json','["瀉從千仞石，寄逐九江船。", "迢遞康王谷，塵埃陸羽篇。", "何當結茅屋，長在水簾前。"]'),
('32e57049-4241-4568-832e-cf20d43e2876','送牛學士知潤州','王禹偁','宋','宋诗','song-poetry','','[]','詔從書殿理江干，江外生民識諫官。',64,'全唐诗/poet.song.3000.json','["詔從書殿理江干，江外生民識諫官。", "京口浪花迎棹白，海門山色入樓寒。", "茅君仙洞披圖見，張祜詩牌拂蘚看。", "他日政成無一事，好吟新句寄長安。"]'),
('0ef8d211-2fc7-4a5d-aa71-9f8a93838635','新月','王禹偁','宋','宋诗','song-poetry','','[]','禁鼓樓頭第一敲，彎彎新月上林梢。',32,'全唐诗/poet.song.3000.json','["禁鼓樓頭第一敲，彎彎新月上林梢。", "誰家寶鏡新磨出，玉匣參差蓋未交。"]'),
('0b485eb7-5455-4608-8eb4-2eedac5a5935','詩一首','王禹偁','宋','宋诗','song-poetry','','[]','一路翠煙垂柳驛，滿川紅雨落花村。',32,'全唐诗/poet.song.3000.json','["一路翠煙垂柳驛，滿川紅雨落花村。", "雲隨釣艇歸漁浦，潮送沙鷗入店門。"]'),
('b44f0041-8b69-4e78-9411-26a2f66b9bf1','伍子胥廟','王禹偁','宋','宋诗','song-poetry','','[]','朝驅下越坂，夕飲當吳門。',156,'全唐诗/poet.song.3000.json','["朝驅下越坂，夕飲當吳門。", "停車訪古蹟，靄靄林煙昏。", "青山海上來，勢若游龍奔。", "星臨斗牛卷，氣與東南吞。", "九折排怒濤，壯哉天地根。", "落日見海色，長風卷浮雲。", "山椒戴遺祠，興廢今猶存。", "殘香弔木客，倒樹哀清猿。", "我來久沉抱，重此英烈魂。", "嗟吁屬鏤鋒，冥爾國士冤。", "峨峨姑蘇臺，榛棘晚露繁。", "深居麋鹿游，此事誰能論。", "因之毛髮豎，落葉秋紛紛。"]'),
('b98c665b-e6cd-4e94-8d74-dcb1590b78b1','官成武主簿作五首  其一','王禹偁','宋','宋诗','song-poetry','','[]','釋褐來成武，始知爲政難。',48,'全唐诗/poet.song.3000.json','["釋褐來成武，始知爲政難。", "每簽逃戶狀，羞作字人宦。", "冷砌莓苔遍，荒城草木寒。", "宦情銷已矣，時夢釣魚灘。"]'),
('5886556f-0b80-4e45-9778-546da6c2f965','官成武主簿作五首  其二','王禹偁','宋','宋诗','song-poetry','','[]','釋褐來成武，徒勞自感傷。',48,'全唐诗/poet.song.3000.json','["釋褐來成武，徒勞自感傷。", "位卑松在澗，俸薄葉經霜。", "逕擁寒莎綠，門橫古木蒼。", "冠纓塵已滿，未敢濯滄浪。"]'),
('15f67069-4718-48ca-9327-19e81698e197','官成武主簿作五首  其三','王禹偁','宋','宋诗','song-poetry','','[]','釋褐來成武，經春自愧多。',48,'全唐诗/poet.song.3000.json','["釋褐來成武，經春自愧多。", "晨炊猶接續，時雨未滂沱。", "拂榻驚巢燕，陳書起蟄蛾。", "惠民無政術，尸祿竟如何。"]'),
('8897000d-9029-49fe-bf18-cf779eb8d884','官成武主簿作五首  其四','王禹偁','宋','宋诗','song-poetry','','[]','釋褐來成武，閒思應舉時。',48,'全唐诗/poet.song.3000.json','["釋褐來成武，閒思應舉時。", "投人天下遍，瘦馬雪中騎。", "秋卷何年中，春愁到處隨。", "如今名已遂，爭敢話官卑。"]'),
('7888e116-9b1c-420f-9e86-7134505fc03f','官成武主簿作五首  其五','王禹偁','宋','宋诗','song-poetry','','[]','釋褐來成武，携家別故鄉。',48,'全唐诗/poet.song.3000.json','["釋褐來成武，携家別故鄉。", "北堂微祿及，南畝舊田荒。", "籬菊飛秋蝶，庭莎叫夜螿。", "無人慰孤寂，窗月自淒凉。"]'),
('30e485ed-30cf-4111-bb03-d2572d5887a4','詩一首','王禹偁','宋','宋诗','song-poetry','','[]','蘭清時雨和甘棠，石壁洄瀾映塔光。',64,'全唐诗/poet.song.3000.json','["蘭清時雨和甘棠，石壁洄瀾映塔光。", "陸羽茶泉金鼎冷，右軍墨沼兔毫香。", "龍潭徹底明秋月，鳳頂當空背夕陽。", "乘得綠楊春曉興，玉臺井畔泛霞觴。"]'),
('bd3c3587-de86-4d36-b3c3-587b0f4026a0','句  其一','王禹偁','宋','宋诗','song-poetry','','[]','帝憐守土舊時臣，添賜春光入酒尊。',16,'全唐诗/poet.song.3000.json','["帝憐守土舊時臣，添賜春光入酒尊。"]'),
('e57151ba-136a-4587-9974-949e821b41be','句  其二','王禹偁','宋','宋诗','song-poetry','','[]','牀頭只有黄州印，鑑裏看成白髮翁。',16,'全唐诗/poet.song.3000.json','["牀頭只有黄州印，鑑裏看成白髮翁。"]'),
('30664d64-1a91-448b-8090-ea29e5f968bd','句  其三','王禹偁','宋','宋诗','song-poetry','','[]','詩情不負齊安郡，杜牧當年與我齊。',16,'全唐诗/poet.song.3000.json','["詩情不負齊安郡，杜牧當年與我齊。"]'),
('26453eee-085c-4e7a-8a36-7dcd316eeed4','句  其四','王禹偁','宋','宋诗','song-poetry','','[]','山州過夏如山寺，銷盡機塵見道心。',16,'全唐诗/poet.song.3000.json','["山州過夏如山寺，銷盡機塵見道心。"]'),
('f4debc0a-22de-4327-92c8-ed21103a8fbd','句  其五','王禹偁','宋','宋诗','song-poetry','','[]','學士舊班雲捧日，使君新政雨隨車。',16,'全唐诗/poet.song.3000.json','["學士舊班雲捧日，使君新政雨隨車。"]'),
('62ce1072-b9ef-4b5d-9dfb-1babaadfeb0d','句  其六','王禹偁','宋','宋诗','song-poetry','','[]','二月探供三月酒，今年未得去年錢。',16,'全唐诗/poet.song.3000.json','["二月探供三月酒，今年未得去年錢。"]'),
('25d57aa1-b611-49a7-8a50-d8f2166e9552','句  其七','王禹偁','宋','宋诗','song-poetry','','[]','草屨布裘輕紫綬，角冠紗帽換朝簪。',16,'全唐诗/poet.song.3000.json','["草屨布裘輕紫綬，角冠紗帽換朝簪。"]'),
('138d7994-25b2-4b69-badd-f80af5b39ae7','句  其八','王禹偁','宋','宋诗','song-poetry','','[]','武昌官柳見毫釐，八字山遥細似眉。',16,'全唐诗/poet.song.3000.json','["武昌官柳見毫釐，八字山遥細似眉。"]'),
('a0802d86-88b9-4a72-9277-590df98e77f6','句  其九','王禹偁','宋','宋诗','song-poetry','','[]','佳人方素面，對鏡理新妝。',12,'全唐诗/poet.song.3000.json','["佳人方素面，對鏡理新妝。"]'),
('00414cb3-f68a-4c0e-8b61-e74db1b0ec5c','句  其一○','王禹偁','宋','宋诗','song-poetry','','[]','風雨江城暮。',6,'全唐诗/poet.song.3000.json','["風雨江城暮。"]'),
('2c01abf4-9d4b-43af-b0c2-cca87ae3ee57','句  其一一','王禹偁','宋','宋诗','song-poetry','','[]','一回酒渴思吞海。',8,'全唐诗/poet.song.3000.json','["一回酒渴思吞海。"]'),
('89521543-5505-43fa-90c5-6ac05a7279c7','句  其一二','王禹偁','宋','宋诗','song-poetry','','[]','春回積雪殊冰裏，香動荒山野水濱。',32,'全唐诗/poet.song.3000.json','["春回積雪殊冰裏，香動荒山野水濱。", "带月一枝斜弄影，背風千片遠隨人。"]'),
('64f74611-1feb-4138-97ea-4888234d4fc5','句  其一三','王禹偁','宋','宋诗','song-poetry','','[]','飄飄粉翅和梅艷，細細香鬚伴柳絲。',16,'全唐诗/poet.song.3000.json','["飄飄粉翅和梅艷，細細香鬚伴柳絲。"]'),
