('dae7c5d3-c455-4a45-abd1-13019f700045','句  其三○','王禹偁','宋','宋诗','song-poetry','','[]','惟有南宮竇員外，爲予垂淚閤門前。',16,'全唐诗/poet.song.3000.json','["惟有南宮竇員外，爲予垂淚閤門前。"]'),
('8e333c70-d5ad-4e0d-a566-e72d3028442e','上杜世昌相公','郭輿','宋','宋诗','song-poetry','','[]','恩浹台端禮數寬，不煩鵷筍裛宵寒。',64,'全唐诗/poet.song.3000.json','["恩浹台端禮數寬，不煩鵷筍裛宵寒。", "即看裾珮趨蹌緩，翻識樞衡斡運難。", "劍履光迎鰲禁紫，絲綸色炫鳳池丹。", "好將寅亮酬天貺，早致亨衢五緯安。"]'),
('ef60cd99-c7a2-4c51-85c9-89d223e3a81e','贈王元之出知黄州','郭輿','宋','宋诗','song-poetry','','[]','楊花飛雪奈愁何，且爲湘纍賦九歌。',64,'全唐诗/poet.song.3000.json','["楊花飛雪奈愁何，且爲湘纍賦九歌。", "芳草不堪春鵙早，荒林癋復夜猿多。", "風煙經眼憐新隔，魑魅窺人喜乍過。", "月落橫江天柱杳，雲山寥寂想鳴珂。"]'),
('77444e13-06f8-45bf-87e0-3e73911e623d','句','朱嚴','宋','宋诗','song-poetry','','[]','寓直有誰同騎省，立班獨自戴貂冠。',16,'全唐诗/poet.song.3000.json','["寓直有誰同騎省，立班獨自戴貂冠。"]'),
('c08f6f3c-5b84-45ec-b767-077ce31367af','句','濟州太守','宋','宋诗','song-poetry','','[]','鸚鵡能言爭似鳳。',8,'全唐诗/poet.song.3000.json','["鸚鵡能言爭似鳳。"]'),
('c311a237-ea4a-4f1b-aa0c-449f8a3e2441','句','楊遂','宋','宋诗','song-poetry','','[]','願侯輯百福，長與民爲霖。',12,'全唐诗/poet.song.3000.json','["願侯輯百福，長與民爲霖。"]'),
('5a4f54a0-3107-47c5-a252-a60977c9fb5a','屬疾','崔遵度','宋','宋诗','song-poetry','','[]','李白羹初美，相如渴漸瘳。',96,'全唐诗/poet.song.3000.json','["李白羹初美，相如渴漸瘳。", "八磚非性懶，三昧減心憂。", "筆宛多批鳳，詞鋒勝解牛。", "舊山疑鶴怨，畏日想雲愁。", "廣內勞揮翰，通中羨枕流。", "使星方屢降，客轄未容投。", "好奏倪寬議，何須莊舄謳。", "朝衣熏歇不，侍史待仙洲。"]'),
('b7bae7a8-7d1b-41f7-aae1-fd344dd2dcf2','送張無夢歸天台山','戚綸','宋','宋诗','song-poetry','','[]','應悔名高藏不得，朝天翻喜放身歸。',64,'全唐诗/poet.song.3000.json','["應悔名高藏不得，朝天翻喜放身歸。", "知時多順時人話，混俗猶披俗士衣。", "有伴指期玄鶴老，無心高羨白雲飛。", "赤城此去全忘慮，笑我塵勞未息機。"]'),
('a428c725-4c69-4a85-b8e3-deefff4b8b06','諭民','戚綸','宋','宋诗','song-poetry','','[]','文契多欺歲月深，便將疆界漸相侵。',32,'全唐诗/poet.song.3000.json','["文契多欺歲月深，便將疆界漸相侵。", "官中驗出虛兼實，枷鎖鞭笞痛不禁。"]'),
('3dd0b97f-fdd0-49ca-b5e7-5f72bc3bcc02','送何水部蒙出牧袁州','戚綸','宋','宋诗','song-poetry','','[]','連翩作牧藹嘉聲，重疊光華是此行。',128,'全唐诗/poet.song.3000.json','["連翩作牧藹嘉聲，重疊光華是此行。", "畫隼前驅男子貴，錦衣當晝故鄉榮。", "虎溪駐目曾遊熟，采石維舟舊吏迎。", "來暮謳謠應載路，遲留桑梓肯忘情。", "郡樓擁翠峰巒合，井邑交光竹樹明。", "醇酎豈知千日醉，溫泉常見四時清。", "下車不問山河改，布政先期獄訟平。", "何日紫宸偏顧矚，聖君留意在編氓。"]'),
('35f9b23a-5ebf-4613-9bd1-7393ccbaa730','秋日同知州潘贊善朝陽巖閑望歸郡中書事','郭昭符','宋','宋诗','song-poetry','','[]','白帝呼龍駕雲旌，西上金天調玉燭。',236,'全唐诗/poet.song.3000.json','["白帝呼龍駕雲旌，西上金天調玉燭。", "九嶷聳黛凝不乾，二水飛藍健相續。", "紫黄詔換魚須竹，皂蓋朱衫來作牧。", "波神一夜收風湍，列缺先秋靜林麓。", "曾巖照水明朝旭，□□衝崖擁奇木。", "山閣吟煙薄暮鐘，酒旗拂雨臨溪屋。", "放歌身外光景促，短續人間片時綠。", "金刀莫□□□□，□□長嘯□□祿。", "梨梅漿酸□才熟，□□新味□□□。", "□笋樵素絲□明，□□□□□青玉。", "□情去日無羈束，逸思凉飄繞煙谷。", "言涉淥水紗裳輕，朱鞅追風桃花速。", "回看山下多麋鹿，浩歎□□□鴻鵠。", "□來刁斗轉分明，永夜公堂守幽獨。", "□□□□□□□，□金液。"]'),
('8a76ab4d-91bd-4f86-882f-63b6254584fd','齊山','楊緘','宋','宋诗','song-poetry','','[]','池陽佳致說齊山，分暇邀朋喜暫攀。',32,'全唐诗/poet.song.3000.json','["池陽佳致說齊山，分暇邀朋喜暫攀。", "浮世謾同流水急，野僧長伴白雲閑。"]'),
('f93fdff7-756f-4f78-a0d0-1bf7659f005d','句','楊緘','宋','宋诗','song-poetry','','[]','一從天上遺金籍，長向人間作畫屏。',16,'全唐诗/poet.song.3000.json','["一從天上遺金籍，長向人間作畫屏。"]'),
('953700f7-05d7-4696-8f9c-2adbdbfd0dca','左掖即事','郭昭度','宋','宋诗','song-poetry','','[]','遲日下金殿，香雲藹玉爐。',24,'全唐诗/poet.song.3000.json','["遲日下金殿，香雲藹玉爐。", "苑花迷晚蝶，宮樹集寒烏。"]'),
('0861ab3a-2075-4088-99f6-039c1b0e9a04','春日奉和馬景山','郭昭度','宋','宋诗','song-poetry','','[]','春來無事不芳辰，尊酒流連動涉旬。',64,'全唐诗/poet.song.3000.json','["春來無事不芳辰，尊酒流連動涉旬。", "三徑每從羊仲賞，諸侯誰念馬卿貧。", "藏名祇許漁樵識，混迹從教鹿豕親。", "老去心情常在埜，摩娑雙眼看垂綸。"]'),
('da4821fd-f6ad-4dc8-9dbc-08dc7706d543','齊山','董儼','宋','宋诗','song-poetry','','[]','千里遠木籠秋浦，萬里澄江浸落暉。',32,'全唐诗/poet.song.3000.json','["千里遠木籠秋浦，萬里澄江浸落暉。", "醉恨春深輸杜牧，滿頭無菊戴將歸。"]'),
('07715296-2442-48f7-b9c8-6b5a6c256f38','句','董儼','宋','宋诗','song-poetry','','[]','白雲深處訪禪扉，一簇樓臺鎖翠微。',16,'全唐诗/poet.song.3000.json','["白雲深處訪禪扉，一簇樓臺鎖翠微。"]'),
('61acf881-9a53-4df3-9b19-56de977eaf8d','錦江遣興','郭載','宋','宋诗','song-poetry','','[]','雲水微茫爽氣浮，錦江如带可憐秋。',64,'全唐诗/poet.song.3000.json','["雲水微茫爽氣浮，錦江如带可憐秋。", "瀠洄霧縠時迷雁，瀲灧霞光不見鷗。", "晴雨一川皆好景，烟花三月總牽愁。", "風波滿地乾坤闊，吟望長安垂白頭。"]'),
('e665937a-df3c-4795-940c-fbe60f3b94aa','送僧歸天寧萬年禪院','梁鼎','宋','宋诗','song-poetry','','[]','談空玉殿君恩厚，歸興蘭舟澤國賒。',64,'全唐诗/poet.song.3000.json','["談空玉殿君恩厚，歸興蘭舟澤國賒。", "禪室冷思滄海雪，吟樓晴憶赤城霞。", "經吳屐滑當梅雨，到寺衣香近桂花。", "深愧塵纓未能去，石橋前瀑共嘗茶。"]'),
('e5870eb1-644a-419b-a76e-4bef77fdaf51','題仙都山','梁鼎','宋','宋诗','song-poetry','','[]','黄帝升天台，高名壯斗牛。',72,'全唐诗/poet.song.3000.json','["黄帝升天台，高名壯斗牛。", "孤根斜照水，寒色不知秋。", "藐與羣峰並，圓如一笋抽。", "曉妨殘月下，晴礙落星流。", "危定勝崑閬，登應見沃洲。", "愛深無盡處，目極更遲留。"]'),
('332f7a0b-1269-47b1-8364-6b62d65aa2e2','瀟湘感事','种放','宋','宋诗','song-poetry','','[]','離離江草與江花，往事洲邊歎復嗟。',64,'全唐诗/poet.song.3000.json','["離離江草與江花，往事洲邊歎復嗟。", "漢傅有才終去國，楚臣無罪亦沈沙。", "淒凉野浦寒飛雁，牢落汀祠晚聚鴉。", "無限清忠沉浪底，滔滔千頃屬漁家。"]'),
('cc6b7d43-9246-448c-9f70-da049d5f7b0a','寄懷','种放','宋','宋诗','song-poetry','','[]','予生背時性孤僻，自信已道輕浮名。',64,'全唐诗/poet.song.3000.json','["予生背時性孤僻，自信已道輕浮名。", "中途失計被簪紱，目睹榮辱心潛驚。", "雖從鵷鸞共班序，常恐青蠅微有聲。", "清風滿壑石田在，終謝吾君甘退耕。"]'),
('4134f261-bde1-4fe8-bbdb-f0e80790b103','寄二華隠者','种放','宋','宋诗','song-poetry','','[]','我本厭虛名，致身天子庭。',48,'全唐诗/poet.song.3000.json','["我本厭虛名，致身天子庭。", "不終高尚事，有媿少微星。", "北闕空追悔，西山羨獨醒。", "秋風舊期約，何日去冥冥。"]'),
('8a4d8bdc-0409-48a6-bbf7-daa0062e9b2d','無題','种放','宋','宋诗','song-poetry','','[]','樓臺縹緲路岐傍，共說祈真白玉堂。',64,'全唐诗/poet.song.3000.json','["樓臺縹緲路岐傍，共說祈真白玉堂。", "株樹風高低絳節，靈臺香冷醮虛皇。", "名傳六合何昭晰，事隔三清限渺茫。", "欲識當年漢家意，竹宮梧殿更淒凉。"]'),
('7bcfcbee-43cf-4c0d-86e1-244faf3d61fa','夏日山居','种放','宋','宋诗','song-poetry','','[]','陰陰林木靜，寂寂無人境。',48,'全唐诗/poet.song.3000.json','["陰陰林木靜，寂寂無人境。", "紅綻紫葳香，嵐沈玉膏冷。", "看雲時獨坐，慎事常中省。", "何客馭風來，新篁動疏影。"]'),
('6d188f50-dad1-47f7-bc3d-24a4675e904b','諭蒙','种放','宋','宋诗','song-poetry','','[]','大盈卑百瀆，自成浮天潯。',72,'全唐诗/poet.song.3000.json','["大盈卑百瀆，自成浮天潯。", "崇丘下累塊，竟爲蔽日深。", "王者在謙小，夙惟堯禹心。", "拜言尊賢仁，慎德棄珠金。", "自滿九族散，匪驕百善尋。", "炳茲夏商鑒，滅國因夸淫。"]'),
('2e05e607-4231-449f-8eb2-1f95558e9df4','酬陳齊民見寄','种放','宋','宋诗','song-poetry','','[]','竹扉常晝掩，幽僻置身安。',48,'全唐诗/poet.song.3000.json','["竹扉常晝掩，幽僻置身安。", "自委漁樵分，因思出處難。", "周庭方設燎，漢將尚封壇。", "莫問漁樵意，人寰事萬端。"]'),
('e5c6eb2a-eb43-4aab-b78d-8c64ec33c6e9','酴醿','种放','宋','宋诗','song-poetry','','[]','生成從火令，顔色占中央。',36,'全唐诗/poet.song.3000.json','["生成從火令，顔色占中央。", "綠葉排圜翠，青苞蓄異香。", "叢陰周曲幹，纖刺比鋒芒。"]'),
('43f10cb9-a3e1-40f4-a9a8-34cc49501503','詠桃','种放','宋','宋诗','song-poetry','','[]','習習香薰薄薄烟，杏遲梅早不同妍。',32,'全唐诗/poet.song.3000.json','["習習香薰薄薄烟，杏遲梅早不同妍。", "山齋盡日無鸞□，只與幽人伴醉眠。"]'),
('e43259c1-70c8-4bf1-a033-f4187cdbd2e6','句  其一','种放','宋','宋诗','song-poetry','','[]','綠萼紅葩晚態新，風流如陣戰愁人。',16,'全唐诗/poet.song.3000.json','["綠萼紅葩晚態新，風流如陣戰愁人。"]'),
('a8aa5d5c-8916-49f7-a937-554a088f2a51','句  其二','种放','宋','宋诗','song-poetry','','[]','胡雛負恩信，聖主恥干戈。',12,'全唐诗/poet.song.3000.json','["胡雛負恩信，聖主恥干戈。"]'),
('8f4476a6-b0d2-4c00-9c7e-4ca8bebb1ea4','句  其三','种放','宋','宋诗','song-poetry','','[]','雖有明時約。',6,'全唐诗/poet.song.3000.json','["雖有明時約。"]'),
('9bb929ec-3666-4d48-9204-09c3851625dd','句  其四','种放','宋','宋诗','song-poetry','','[]','東君若要分流品。',8,'全唐诗/poet.song.3000.json','["東君若要分流品。"]'),
('ef2e4248-a8a4-4957-883a-383a062d523b','凝真宮','張無夢','宋','宋诗','song-poetry','','[]','五雲深鎖洞門深，躡屐攀蘿特地尋。',64,'全唐诗/poet.song.3000.json','["五雲深鎖洞門深，躡屐攀蘿特地尋。", "烟靄不藏塵外路，神仙遺下水中金。", "喜游汗漫華胥宅，重憶崆峒至道心。", "不得方平同一醉，紅霞零落我罇琴。"]'),
('95f1f1d9-6dfb-4abc-aab5-f9bd7d7b5cdb','桐柏崇道觀','張無夢','宋','宋诗','song-poetry','','[]','桐柏觀周匝，千峰累翠螺。',48,'全唐诗/poet.song.3000.json','["桐柏觀周匝，千峰累翠螺。", "地高陰氣少，天近日光多。", "三井雲雷起，一壇鸞鶴過。", "誰言紫微後，無客繼仙科。"]'),
('cf3f0e12-46b9-4ed5-8564-2eea068cf1e8','福聖觀','張無夢','宋','宋诗','song-poetry','','[]','台山卜隠十餘秋，曾伴仙翁處處游。',64,'全唐诗/poet.song.3000.json','["台山卜隠十餘秋，曾伴仙翁處處游。", "瀑布長流天上雪，翠屏高倚洞前樓。", "雲堆華頂尋飈馭，月滿靈谿狎海鷗。", "此地重歸別得路，赤城玉府透瀛洲。"]'),
('69b013b8-ddf2-4e80-b3ed-4493f136f042','天台福聖觀','張無夢','宋','宋诗','song-poetry','','[]','天台瀑布落青天，觀在天台瀑布邊。',64,'全唐诗/poet.song.3000.json','["天台瀑布落青天，觀在天台瀑布邊。", "道士祇今燒藥處，仙翁曾是種芝田。", "龍居古洞遺殘雨，鶴出高巢點破煙。", "暫別靈溪遊五嶽，不知重到又何年。"]'),
('396e36a0-3c7a-4fd0-8f26-2fc657fe3c79','句','張無夢','宋','宋诗','song-poetry','','[]','壺中一粒長生藥，待與蘇州太守分。',16,'全唐诗/poet.song.3000.json','["壺中一粒長生藥，待與蘇州太守分。"]'),
('327d9b2c-37b7-450f-b6c9-c3f3fda03d2f','題潭州壽寧觀','劉玄英','宋','宋诗','song-poetry','','[]','醉走白雲來，倒提銅尾秉。',120,'全唐诗/poet.song.3000.json','["醉走白雲來，倒提銅尾秉。", "引箇碧眼奴，擔著獨壺癭。", "自言秦世事，家住葛洪井。", "不讀黄庭經，豈燒龍虎鼎。", "獨立都市中，不受俗人請。", "欲携霹靂琴，去上芙蓉頂。", "吳牛買十箇，溪田耕半頃。", "種秫釀白醪，總是仙家境。", "醉卧松蔭下，閑過白雲嶺。", "要去即便去，直入秋霞影。"]'),
('8cdb3afc-5e8d-41e9-87ba-9d56cf2c59ec','句','劉玄英','宋','宋诗','song-poetry','','[]','拋離火宅三千指，屏去門兵十萬家。',16,'全唐诗/poet.song.3000.json','["拋離火宅三千指，屏去門兵十萬家。"]'),
('554d5da0-3d5b-44ac-ae02-473685875922','送張無夢歸天台  其一','查道','宋','宋诗','song-poetry','','[]','天台峻極橫海濱，金庭紫洞多真人。',128,'全唐诗/poet.song.3000.json','["天台峻極橫海濱，金庭紫洞多真人。", "先生舍道心照鄰，上有羲軒爲逸民。", "玉韞深山珠在水，圓折如虹難自晦。", "萬乘知名欲見之，來謁西清頻召對。", "亭亭孤雲本無心，琅琅仙骨時所欽。", "牢讓賜金兼好爵，俄辭堯闕復丘林。", "事載緹紬誠可貴，跡寄煙霞愈無累。", "還同麟鳳遇皇明，暫出巖扃作祥瑞。"]'),
('cf2560e4-97a3-49eb-9889-001fd8371272','送張無夢歸天台  其二','查道','宋','宋诗','song-poetry','','[]','台嶽幽人興不凡，携筇相別欵柴關。',64,'全唐诗/poet.song.3000.json','["台嶽幽人興不凡，携筇相別欵柴關。", "高情共樂皇風遠，真氣潛通浩劫間。", "綠綺靜聞沉俗格，榴花深引漬童顔。", "再聽玄旨知何日，時望片雲歸故山。"]'),
('2480bba0-eca3-4e2f-8bd2-201eed2eabd6','登岱','查道','宋','宋诗','song-poetry','','[]','凌空疊嶂絕凡埃，青帝高居絳節開。',64,'全唐诗/poet.song.3000.json','["凌空疊嶂絕凡埃，青帝高居絳節開。", "捧出海天紅日近，迓將蓬島碧霞來。", "石閭閃爍迎陽洞，玉簡光華封禪臺。", "一自祥符禋祀後，太平頂上最崔巍。"]'),
('974549cb-d8e6-4576-ab41-6b7349b151dd','句','查道','宋','宋诗','song-poetry','','[]','白銅鞮側花迷塢，解佩江邊柳拂青。',16,'全唐诗/poet.song.3000.json','["白銅鞮側花迷塢，解佩江邊柳拂青。"]'),
('1dfbd52e-def8-45bf-acaf-7e8ec72dbd42','題仙都山','陳若拙','宋','宋诗','song-poetry','','[]','發地便擎天，根盤數畝煙。',48,'全唐诗/poet.song.3000.json','["發地便擎天，根盤數畝煙。", "化工成突兀，轍迹似雕鎸。", "峭拔殊無倚，孤高衆莫肩。", "軒轅從此去，知復幾千年。"]'),
('fbeea33d-272f-40af-932e-84eae6870360','送張無夢歸天台山','馬知節','宋','宋诗','song-poetry','','[]','暫至朝真主，卻思歸舊峰。',48,'全唐诗/poet.song.3000.json','["暫至朝真主，卻思歸舊峰。", "只依三事布，唯有一枝筇。", "月上當孤室，風生自古松。", "陰功從此滿，何處覓遺蹤。"]'),
('8459299b-01e7-4e71-bb45-73ebbbab20ba','書蘇州廳壁','孫冕','宋','宋诗','song-poetry','','[]','人生七十爲鬼鄰，已覺風光屬別人。',64,'全唐诗/poet.song.3000.json','["人生七十爲鬼鄰，已覺風光屬別人。", "莫待朝廷差致仕，早謀泉石養閑身。", "去年河北曾逢李，今日淮西又見陳。", "寄語姑蘇孫刺史，也須抖擻老精神。"]'),
('e0124fe8-7f34-42e4-960d-5a07beb4f6ca','送新知永州陳祕丞瞻赴任','孫冕','宋','宋诗','song-poetry','','[]','桂林南面近徵黄，又愛江鄉出帝鄉。',64,'全唐诗/poet.song.3000.json','["桂林南面近徵黄，又愛江鄉出帝鄉。", "新命不辭提郡印，舊山重喜過衡陽。", "樓臺滿眼瀟湘色，道路迎風橘柚香。", "知有太平經濟術，政閑時節好飛章。"]'),
('96a80ed6-c9d4-4bba-84c9-8fafd6ba1477','句  其一','孫冕','宋','宋诗','song-poetry','','[]','可憐遐地産，常化燎原火。',12,'全唐诗/poet.song.3000.json','["可憐遐地産，常化燎原火。"]'),
('ea2f0073-0d9f-4f11-903d-419aefcdf34f','句  其二','孫冕','宋','宋诗','song-poetry','','[]','水劍還難問，梅梁亦可疑。',12,'全唐诗/poet.song.3000.json','["水劍還難問，梅梁亦可疑。"]'),
('3b562bec-99aa-4b1b-bf62-23a17c2d49c3','十詠圖 太守馬大卿會六老於南園','張維','宋','宋诗','song-poetry','','[]','賢侯美化行南國，華髮欣欣奉宴娛。',64,'全唐诗/poet.song.3000.json','["賢侯美化行南國，華髮欣欣奉宴娛。", "政績已聞同水薤，恩輝遂喜及桑榆。", "休言身外榮名好，但恐人間此會無。", "他日定知傳好事，丹青寧羨洛中圖。"]'),
('a3bece13-a0f3-428f-a119-c92b48e47408','十詠圖 庭鶴','張維','宋','宋诗','song-poetry','','[]','戢翼盤桓傍小庭，不無清夜夢烟汀。',64,'全唐诗/poet.song.3000.json','["戢翼盤桓傍小庭，不無清夜夢烟汀。", "靜翹月色一團素，閑啄苔錢數點青。", "終日稻粱聊自足，滿前雞鶩漫相形。", "已隨秋意歸詩筆，更與幽棲上畫屏。"]'),
('a114e009-6e80-4209-969f-35cd78b1615a','十詠圖 玉蝴蝶花','張維','宋','宋诗','song-poetry','','[]','雪朵中間蓓蕾齊，驟開尤覺繡工遲。',64,'全唐诗/poet.song.3000.json','["雪朵中間蓓蕾齊，驟開尤覺繡工遲。", "品高多說瓊花似，曲妙誰將玉笛吹。", "散舞不休零晚樹，團飛無定撼風枝。", "漆園如有須爲夢，若在藍田種更宜。"]'),
('8979905c-427d-41f5-b34f-ae4919306998','十詠圖 孤帆','張維','宋','宋诗','song-poetry','','[]','江心雲破處，遥見去帆孤。',48,'全唐诗/poet.song.3000.json','["江心雲破處，遥見去帆孤。", "浪闊疑升漢，風高若泛湖。", "依微過遠嶼，彷佛落荒蕪。", "莫問乘舟客，利名同一途。"]'),
('6f3b87bf-4619-4a21-b975-d0d725b73c48','十詠圖 宿清江小舍','張維','宋','宋诗','song-poetry','','[]','菰葉青青綠荇齊。',8,'全唐诗/poet.song.3000.json','["菰葉青青綠荇齊。"]'),
('d3591321-6f86-4437-8c2e-b87f2e6522c2','十詠圖 歸燕','張維','宋','宋诗','song-poetry','','[]','社燕秋歸何處鄉，羣雛齊老稻青黄。',64,'全唐诗/poet.song.3000.json','["社燕秋歸何處鄉，羣雛齊老稻青黄。", "猶能時暫棲庭樹，漸覺稀疏度苑牆。", "已任風庭下簾幕，却隨烟艇過瀟湘。", "前春認得安巢所，應免差池揀杏梁。"]'),
('18312c20-85bb-4af3-a671-e7ae69a0e965','十詠圖 聞砧','張維','宋','宋诗','song-poetry','','[]','遥野空林砧杵聲，淺沙棲雁自相鳴。',64,'全唐诗/poet.song.3000.json','["遥野空林砧杵聲，淺沙棲雁自相鳴。", "西風送響暝色靜，久客感秋愁思生。", "何處征人移塞帳，即時新月落江城。", "不知今夜搗衣曲，欲寫秋閨多少情。"]'),
('3118cf24-4092-4e8e-b9d9-1999b954b649','十詠圖 宿後陳莊','張維','宋','宋诗','song-poetry','','[]','臘凍初開苕水清，烟村遠郭漫吟行。',64,'全唐诗/poet.song.3000.json','["臘凍初開苕水清，烟村遠郭漫吟行。", "灘頭斜日鳬鷖隊，枕上西風鼓角聲。", "一棹寒燈隨夜釣，滿犁膏雨趁春耕。", "誰言五福仍須富，九十年餘樂太平。"]'),
('14444661-0f88-461a-b216-f1d40a0aef6d','十詠圖 送丁遜秀才赴舉','張維','宋','宋诗','song-poetry','','[]','鵬去天池鳳翼隨，風雲高處約先飛。',32,'全唐诗/poet.song.3000.json','["鵬去天池鳳翼隨，風雲高處約先飛。", "青袍賜宴出關近，带取瓊林春色歸。"]'),
('26cab086-8061-49a8-9d3e-4b6dc9be246e','十詠圖 貧女','張維','宋','宋诗','song-poetry','','[]','蒿簪掠鬢布裁衣，水鑑雖明亦嬾窺。',64,'全唐诗/poet.song.3000.json','["蒿簪掠鬢布裁衣，水鑑雖明亦嬾窺。", "數畝秋禾滿家食，一機官帛幾梭絲。", "物爲貴寶天應與，花有秋香春不知。", "多少年來豪族女，總教時樣畫蛾眉。"]'),
('cd96f225-f871-477c-806e-c0214a41f025','次經略舍人韻','張維','宋','宋诗','song-poetry','','["\u897f\u6e56"]','列岫凌虛滃翠嵐，龍泓澄澈七星涵。',32,'全唐诗/poet.song.3000.json','["列岫凌虛滃翠嵐，龍泓澄澈七星涵。", "巖瞻好向西湖著，飛去何妨自嶺南。"]'),
('9af5f2d7-87aa-4703-98f6-4f11b3ff4367','和劉穎','張維','宋','宋诗','song-poetry','','[]','不賢那得似長城，偶向潢池盜弄兵。',64,'全唐诗/poet.song.3000.json','["不賢那得似長城，偶向潢池盜弄兵。", "靜沼何妨無事飲，幽尋聊記所居名。", "千山倒影湖新復，兩洞潛珍景旋生。", "紀事還須武陵筆，亭成唯擬看題榮。"]'),
('e6a8994a-eb68-4899-8c54-201824f2d1b5','題張公洞','張維','宋','宋诗','song-poetry','','[]','年來行樂與民同，探穴追蹤太史公。',64,'全唐诗/poet.song.3000.json','["年來行樂與民同，探穴追蹤太史公。", "幽洞初開名易著，蒼崖新刻句難工。", "風驅俗駕松扉外，雲鎖仙丹石室中。", "付與山僧司管鑰，勿教勝地草蒙茸。"]'),
('609c12da-ecb4-45af-beed-a05b7e126e8e','題朝陽巖','陳瞻','宋','宋诗','song-poetry','','[]','巖面郡樓前，巖崖瀑布懸。',48,'全唐诗/poet.song.3000.json','["巖面郡樓前，巖崖瀑布懸。", "曉光分海日，碧影轉江天。", "向暖盤棲鶴，迎寒簇釣船。", "次山題紅處，千古與人傳。"]'),
('5eea60fc-0ced-4d73-bdb9-5e6a01cc066f','游虎丘','崔端','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','入寺山光峭倚天，劍池寒色鎖危巔。',64,'全唐诗/poet.song.3000.json','["入寺山光峭倚天，劍池寒色鎖危巔。", "蒼苔自老生公石，新茗誰烹陸羽泉。", "樓閣下窺溟海浪，松篁遥接洞庭烟。", "二難選勝真奇絕，留得芳名萬古傳。"]'),
('e3e92200-99d9-4530-858e-840e2389ac82','送陳瞻知永州','李防','宋','宋诗','song-poetry','','[]','昔年同醉杏園春，別後花枝幾度新。',64,'全唐诗/poet.song.3000.json','["昔年同醉杏園春，別後花枝幾度新。", "彼此宦遊疏翰墨，等閑交面起絲綸。", "榮親未必須萊子，晝錦何嘗只買臣。", "布政莫爲三載計，清朝臺閣整搜人。"]'),
('636150c1-1dac-4dbd-8112-d2c4a3820d22','槿花','劉隲','宋','宋诗','song-poetry','','[]','虢國妝初罷，高堂夢始迴。',48,'全唐诗/poet.song.3000.json','["虢國妝初罷，高堂夢始迴。", "霓裳猶未解，繡被已成堆。", "赤帝宮簾卷，華陽洞戶開。", "神僊有良會，清唱在瑶臺。"]'),
('521a60d7-fbd8-4f34-a5ec-34cc78df12ce','代意','劉隲','宋','宋诗','song-poetry','','[]','路隔仙源不可尋，紫牆霜戟夜沉沉。',64,'全唐诗/poet.song.3000.json','["路隔仙源不可尋，紫牆霜戟夜沉沉。", "緘情謾託傳書雁，換笑空餘取酒金。", "翡翠巢成珠樹密，驪龍睡起玉淵深。", "新知自樂生離苦，年少情多豈易禁。"]'),
('56fca368-5d6e-43d4-81cb-6b452adcc223','漢武','劉隲','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','高挹方諸薦水倉，醮壇時見燭神光。',64,'全唐诗/poet.song.3000.json','["高挹方諸薦水倉，醮壇時見燭神光。", "日邊甲帳雖虛設，汾上樓船不可忘。", "盤槩碧霄甘露白，鼎遷幽壤瑞雲黄。", "東巡岱嶽探金策，倒指寧聞壽數長。"]'),
('adf66013-d1d3-40a3-8a59-c3c2a1edb306','館中新蟬','劉隲','宋','宋诗','song-poetry','','[]','摇落何須宋玉悲，齊亭遺恨莫霑衣。',64,'全唐诗/poet.song.3000.json','["摇落何須宋玉悲，齊亭遺恨莫霑衣。", "池中菡萏香全減，井上梧桐葉乍飛。", "風促箏聲隨斷續，日移磚影自光輝。", "宜秋門外饒芳樹，結駟那堪送客歸。"]'),
('ef562e61-86e0-4785-aee7-590d9e778b01','舊將','劉隲','宋','宋诗','song-poetry','','[]','彊弩當年討不庭，功成身退炳丹青。',64,'全唐诗/poet.song.3000.json','["彊弩當年討不庭，功成身退炳丹青。", "囊沙澤畔知兵法，聚米山前識陣形。", "驥老未甘秋伏櫪，劍閒猶覺夜衝星。", "分茅錫土傳家牒，鐘鼎還須爲勒銘。"]'),
('dcbd58be-27f9-4531-bc6d-89ea073e753a','送新知永州陳秘丞瞻赴任','劉隲','宋','宋诗','song-poetry','','[]','秋風清緊雁初飛，半醉摇鞭出帝畿。',64,'全唐诗/poet.song.3000.json','["秋風清緊雁初飛，半醉摇鞭出帝畿。", "名郡又分紅旆去，故鄉重見錦衣歸。", "剖符雖暫宣皇澤，視草終須直紫微。", "從此南軒多倚望，好詩芳信莫教稀。"]'),
('ad2039b0-659a-4a98-9ed1-6f3cae3a3f97','次韻虞舜廟懷古','劉隲','宋','宋诗','song-poetry','','[]','詩人如不頌，誰識太平心。',60,'全唐诗/poet.song.3000.json','["詩人如不頌，誰識太平心。", "石老碑文古，庭荒蟻穴深。", "白雲生絕壑，斑竹鎖疏林。", "行客自南北，青山共古今。", "登臨尋勝蹟，望望日西沉。"]'),
('cfacdbb0-df36-459a-b15f-f0b0262b99e4','題義門胡氏華林書院','劉隲','宋','宋诗','song-poetry','','[]','徐孺亭邊水石連，高名頻見野僧傳。',160,'全唐诗/poet.song.3000.json','["徐孺亭邊水石連，高名頻見野僧傳。", "篋中書滿思安世，樓上詩成憶仲宣。", "已說爛柯忘意遠，定知焦尾用心專。", "寒溪乘興雲迎棹，秋夜娛賓月照筵。", "曲檻靜宜開木筆，短牆幽稱聚苔錢。", "廷評官小無餘俸，致仕身閑得盡眠。", "梅少也須饒越嶽，竹多寧肯讓湘川。", "樽前白玉杯常在，腰底黄金带未懸。", "清露暖空滋菊圃，紫雲垂蔭養芝田。", "仍聞旌表門閭後，朝士褒稱過百篇。"]'),
('a5c05847-9fc7-4985-92a4-caf14aab1f88','題鼎州甘泉寺','范諷','宋','宋诗','song-poetry','','[]','平仲酌泉回北望，謂之禮佛向南行。',32,'全唐诗/poet.song.3000.json','["平仲酌泉回北望，謂之禮佛向南行。", "煙嵐翠鎖門前路，轉使高僧厭寵榮。"]'),
('687c8c63-a66f-4ecf-87ac-d24c51ff89b3','句','范諷','宋','宋诗','song-poetry','','[]','惟有南山與君眼，相逢不改舊時情。',16,'全唐诗/poet.song.3000.json','["惟有南山與君眼，相逢不改舊時情。"]'),
('828ff877-ecc4-422e-99f8-32f657ed851a','自詠','李少和','宋','宋诗','song-poetry','','[]','寶珠探妙得真宗，五色分明煥太空。',32,'全唐诗/poet.song.3000.json','["寶珠探妙得真宗，五色分明煥太空。", "解下連環竟超越，鬰羅深處宴鴻濛。"]'),
('4ee12a74-6665-4444-a022-09bb8e0b53db','題義門胡氏華林書院','張素','宋','宋诗','song-poetry','','[]','聖主臨朝重義門，紫泥旌表不優恩。',64,'全唐诗/poet.song.3000.json','["聖主臨朝重義門，紫泥旌表不優恩。", "廣延墨客收經籍，已見丹朱及子孫。", "池沼宴時花滿檻，煙霞吟處酒盈樽。", "清閑官秩清閑景，千戶侯封未足倫。"]'),
('5382d6e2-c326-457f-a4da-adc3678bf06a','次令衿遊玉壺高詠十絕 風雷大作','席羲叟','宋','宋诗','song-poetry','','[]','坐聽風雷起空谷，俄看四面野雲生。',32,'全唐诗/poet.song.3000.json','["坐聽風雷起空谷，俄看四面野雲生。", "道人不作英雄氣，可笑當年失箸驚。"]'),
('72ea05f6-cc4d-42cd-aee1-f6d034bdf70a','次令衿遊玉壺高詠十絕 獨坐','席羲叟','宋','宋诗','song-poetry','','[]','几檻虛明不著埃，忘機鷗鳥自飛來。',32,'全唐诗/poet.song.3000.json','["几檻虛明不著埃，忘機鷗鳥自飛來。", "北窗高卧羲皇世，九陌紅塵安在哉。"]'),
('709e8d58-825b-4a14-a0bf-ed9a14ca7994','次令衿遊玉壺高詠十絕 處處可人','席羲叟','宋','宋诗','song-poetry','','[]','陂塘五月迎秋爽，脩竹成陰一逕開。',32,'全唐诗/poet.song.3000.json','["陂塘五月迎秋爽，脩竹成陰一逕開。", "俗客自應慚到此，幽深雅稱杖藜來。"]'),
('d824e710-6fcd-4bef-bb91-e5ec7f7e4a62','次令衿遊玉壺高詠十絕 解衣磐','席羲叟','宋','宋诗','song-poetry','','[]','林宗烏幘任欹傾，緩带荷風拂面清。',32,'全唐诗/poet.song.3000.json','["林宗烏幘任欹傾，緩带荷風拂面清。", "城市輪蹄鬧如織，飄然從此便登瀛。"]'),
('e58c0720-8c12-4ef5-b8db-9bb6b9a4226a','次令衿遊玉壺高詠十絕 小雨垂簾就寢','席羲叟','宋','宋诗','song-poetry','','[]','篆香如霧細縈簾，始信壺中別有天。',32,'全唐诗/poet.song.3000.json','["篆香如霧細縈簾，始信壺中別有天。", "客舍黄粱今熟否，邯鄲無夢夢遊仙。"]'),
('26da89c7-ad8f-4740-bf82-04a6256b5e50','次令衿遊玉壺高詠十絕 凭欄看花','席羲叟','宋','宋诗','song-poetry','','[]','湖光空闊水天秋，翠蓋紅衣永日留。',32,'全唐诗/poet.song.3000.json','["湖光空闊水天秋，翠蓋紅衣永日留。", "惟有詩情磨不盡，碧雲吟就喜湯休。"]'),
('45e5a130-9b55-4f9e-839a-a10688953341','次令衿遊玉壺高詠十絕 欲歸甫留','席羲叟','宋','宋诗','song-poetry','','[]','度塹昏鴉接翅稀，斷霞相映霧山微。',32,'全唐诗/poet.song.3000.json','["度塹昏鴉接翅稀，斷霞相映霧山微。", "騶車不用飛青蓋，試作山翁倒載歸。"]'),
('91f8e7db-c04a-4dfb-b5ba-361a1d284edb','次令衿遊玉壺高詠十絕 滿園秋香','席羲叟','宋','宋诗','song-poetry','','[]','黄金勻揉萬英開，步遶清芬過砌臺。',32,'全唐诗/poet.song.3000.json','["黄金勻揉萬英開，步遶清芬過砌臺。", "一笑欣然超鼻觀，知公曾到月中來。"]'),
('ea2a5711-8359-4ff1-9e9f-47bcb83ee766','次令衿遊玉壺高詠十絕 久病便覺清快','席羲叟','宋','宋诗','song-poetry','','[]','內熟先從一念收，浩然勿藥更何求。',32,'全唐诗/poet.song.3000.json','["內熟先從一念收，浩然勿藥更何求。", "西山故自朝來爽，政不驚人語不休。"]'),
('d0363108-4f6b-4f94-904b-07a4cdc98352','次令衿遊玉壺高詠十絕 對換','席羲叟','宋','宋诗','song-poetry','','[]','絕景頻因警句誇，莫傳俚耳便紛挐。',32,'全唐诗/poet.song.3000.json','["絕景頻因警句誇，莫傳俚耳便紛挐。", "須知味道耽巖穴，志意難將富貴加。"]'),
('5b241b48-d4a6-46ea-ae50-69bfaaec55cc','句','姚鍄','宋','宋诗','song-poetry','','[]','花枝冷濺昭陽雨，釣綫斜牽太液風。',16,'全唐诗/poet.song.3000.json','["花枝冷濺昭陽雨，釣綫斜牽太液風。"]'),
('830edb89-d404-4078-a161-177df76de959','夫以因於閑暇採集巴句幸寄孔目五言二十韻伏惟不阻爲幸','釋道猷','宋','宋诗','song-poetry','','[]','多幸遭逢處，知交信有恩。',36,'全唐诗/poet.song.3000.json','["多幸遭逢處，知交信有恩。", "偏承相見重，頻沐厚光榮。", "眷戀常推許，人情每普平。"]'),
('4334b340-9e69-47f8-8d22-f74af32e3d04','濺玉亭','釋道常','宋','宋诗','song-poetry','','[]','我名濺玉亭，五字仍一掃。',120,'全唐诗/poet.song.3000.json','["我名濺玉亭，五字仍一掃。", "蒼崖立積鐵，懸瀑翻輕縞。", "霏霏冰奩傾，粲粲玉匣倒。", "殷勤點翠竹，散漫沾芳草。", "喧轟雷霆怒，澒洞金石考。", "直疑青山嚴，頓失趙盾杲。", "飛簾吹不斷，接影照逾皓。", "初非智巧成，端自神物造。", "凭欄熟自聽，歸來想懷抱。", "拂除朱絲絃，寫之流水操。"]'),
('45e71cf1-f476-4105-94af-ef6ad9e96f25','巖豅寺','釋道常','宋','宋诗','song-poetry','','[]','女媧補天天不疏，精衛填海海欲枯。',64,'全唐诗/poet.song.3000.json','["女媧補天天不疏，精衛填海海欲枯。", "留餘亂石龍下蟄，結茲古洞神中刳。", "三冬溫溫等氈帳，六月凜凜同冰壺。", "致身岩壑真勝地，寓目塵寰皆畏途。"]'),
('df880475-92e4-492a-a408-8a599359dc70','玉乳泉','李仲殊','宋','宋诗','song-poetry','','[]','玉液煎瓊甃，泓澄一脈泉。',48,'全唐诗/poet.song.3000.json','["玉液煎瓊甃，泓澄一脈泉。", "張生題品異，丞相與名傳。", "薦客流霞勝，煎茶掇乳鮮。", "祇園終古在，長對白衣仙。"]'),
('2aa455a3-9069-4c16-8984-c3a40c0e0529','贈安邑簿伍彬歸隠','路振','宋','宋诗','song-poetry','','[]','考終秋鬢白，歸隠舊峰前。',48,'全唐诗/poet.song.3000.json','["考終秋鬢白，歸隠舊峰前。", "庭樹鳥頻啄，山房人尚眠。", "寒巖落桂子，野水過茶煙。", "已結勞生念，虔心向竺乾。"]'),
('9ad8ee56-8311-4675-9f3c-20d1e4cf2478','題惠泉師壁','路振','宋','宋诗','song-poetry','','[]','漢公嘗說惠泉師，解講楞嚴解賦詩。',32,'全唐诗/poet.song.3000.json','["漢公嘗說惠泉師，解講楞嚴解賦詩。", "今日我來師已去，草堂風雨立多時。"]'),
('285ccf1b-f12b-4ffb-bcb2-bead7c550298','伐棘篇','路振','宋','宋诗','song-poetry','','[]','伐棘何所山之巔，秋風颾颾棘子丹。',216,'全唐诗/poet.song.3000.json','["伐棘何所山之巔，秋風颾颾棘子丹。", "折根破柢堅且頑，斸夫趦趄汗污顔。", "攢鋒束芒趨道還，𦽑之森森繚長藩。", "暮冬號風雪暗天，漏寒不鳴守犬眠。", "主人堂上多金錢，東陵暴客來窺垣。", "舉手觸鋒身隕顛，千矛萬戟爭後先。", "襟袖結裂不可揎，蹠破指傷流血殷。", "神離氣沮走蹁躚，數尺之牆弗復攀。", "索頭醜奴搔河壖，朔方屯師連七年。", "木波馬領沙填填，氣脈不絕如喉咽。", "官軍虎怒思吼軒，强弩一發山河穿。", "將不叶謀空即安，翫養小醜成隕顛。", "推芻挽粟徒喧喧，邊臣無心靖國艱。", "爲余諷此伐棘篇。"]'),
('6f15adfb-4d60-4b47-8a3c-07eda76de98a','句  其一','路振','宋','宋诗','song-poetry','','[]','瘴海千枝霧，驪山一騎塵。',12,'全唐诗/poet.song.3000.json','["瘴海千枝霧，驪山一騎塵。"]'),
('063d4049-e9f5-42a2-95f0-13e8bc4747f4','句  其二','路振','宋','宋诗','song-poetry','','[]','君恩來萬里，客路出千山。',12,'全唐诗/poet.song.3000.json','["君恩來萬里，客路出千山。"]'),
('3a810446-4811-49e1-9325-07b2c1b1932f','禁林讌會之什','王旦','宋','宋诗','song-poetry','','[]','喜綴真仙讌禁林，玉堂新事好供吟。',96,'全唐诗/poet.song.3000.json','["喜綴真仙讌禁林，玉堂新事好供吟。", "天章刻石興風雅，宸翰書牌耀古今。", "勢逸奪迴龍鳳跡，調高流入管弦音。", "光凝玉斝瓊漿潤，冷布花磚藥樹陰。", "地貴每朝金殿近，景清如到玉壺深。", "得陪嘉會榮觀大，虔效賡歌樂聖心。"]'),
('aec5268e-1fb8-4b6c-a34b-7a54d31e8752','十洲閣','王旦','宋','宋诗','song-poetry','','[]','山川如幻閣長秋，一島飛來伴九洲。',64,'全唐诗/poet.song.3000.json','["山川如幻閣長秋，一島飛來伴九洲。", "不礙漁樵雙槳過，何妨羅綺四時遊。", "雲疑泰華分張去，永憶蓬瀛散漫浮。", "禁苑未知湖海樂，生綃寫取獻九州。"]'),
('d7991e57-244a-423f-a500-c9d39895a416','贈淳于公歸養','王旦','宋','宋诗','song-poetry','','[]','年少復家貧，懸車去養親。',48,'全唐诗/poet.song.3000.json','["年少復家貧，懸車去養親。", "銅扉霑美命，綵服稱閒身。", "純孝敦時俗，高風似古人。", "禁林榮華者，羞見二毛新。"]'),
('cab51508-fd2b-4af3-a80a-2df164a13845','詩一首','王旦','宋','宋诗','song-poetry','','[]','逈與群芳異，含芳向暮春。',24,'全唐诗/poet.song.3000.json','["逈與群芳異，含芳向暮春。", "不如松柏木，常保歲寒新。"]'),
('edd69ee6-3d58-43ad-bea9-4987227a5ec7','丁家山訪李璨','凌策','宋','宋诗','song-poetry','','[]','江表遥思歲月賒，幽尋勝蹟對繁華。',64,'全唐诗/poet.song.3000.json','["江表遥思歲月賒，幽尋勝蹟對繁華。", "池塘瀲灧凌朱閣，樹木參差翳彩霞。", "玉斝滿傾千日酒，畫欄常勝四時花。", "當年劉阮應惆悵，不識桃源第一家。"]'),
('7942e1d0-889d-45f2-acd8-49191ed9c8d4','句','李瀆','宋','宋诗','song-poetry','','[]','行到水窮處，未知天盡時。',12,'全唐诗/poet.song.3000.json','["行到水窮處，未知天盡時。"]'),
('5dd9834c-1c27-43b8-b7af-e42f6d423401','止善堂','王旭','宋','宋诗','song-poetry','','[]','人心若江河，晝夜無停流。',180,'全唐诗/poet.song.3000.json','["人心若江河，晝夜無停流。", "東流未到海，滔滔詎能休。", "又如遠遊客，終年寄他州。", "不知歸其家，歲暮何所投。", "水流上滄海，人行止故丘。", "而況寰宇中，事物紛相酬。", "人欲盛其熾，天理微以幽。", "瞬息變化間，肝膽生戈矛。", "苟不知所止，定心終無由。", "所止非至善，此心猶可憂。", "卓哉陳使君，立志希前修。", "名堂以止善，善外俱無求。", "我德自此明，新民功亦優。", "還應有餘慶，永爲斯堂留。", "不愧大學篇，芳塵映千秋。"]'),
('549ba6fb-b0f8-46d5-b456-983add40aef3','送僧歸護國寺','丘雍','宋','宋诗','song-poetry','','[]','蕭昂矚餘輝，堯天命賜衣。',48,'全唐诗/poet.song.3000.json','["蕭昂矚餘輝，堯天命賜衣。", "石房雲外啟，金錫日邊歸。", "草腐螢光散，星中暑氣微。", "抽簪期晚歲，相許扣禪扉。"]'),
('2ba8439f-dcb2-431c-b328-d2beedae2a6d','句  其一','焦宗古','宋','宋诗','song-poetry','','[]','芳樹高低啼蜀魄，朝雲濃淡極巴天。',16,'全唐诗/poet.song.3000.json','["芳樹高低啼蜀魄，朝雲濃淡極巴天。"]'),
('03b9d2e6-a848-4256-b094-17f1bb20def8','句  其二','焦宗古','宋','宋诗','song-poetry','','[]','南陽客自稱龍卧，東魯人應嘆鳳衰。',16,'全唐诗/poet.song.3000.json','["南陽客自稱龍卧，東魯人應嘆鳳衰。"]'),
('76fadccf-6e36-49ef-be16-cd515f24587b','句  其三','焦宗古','宋','宋诗','song-poetry','','[]','釀成漢帝招王母，飲罷凉州拜孟池。',16,'全唐诗/poet.song.3000.json','["釀成漢帝招王母，飲罷凉州拜孟池。"]'),
('7233248a-1d4b-4b42-aa6f-ee3f57d0fcfb','句','趙復','宋','宋诗','song-poetry','','[]','船官風破浪，關吏鼓通晨。',12,'全唐诗/poet.song.3000.json','["船官風破浪，關吏鼓通晨。"]'),
('1b5d4cce-760a-44a5-84a8-9573c4a6a7ab','睢陽五老會詩','王渙','宋','宋诗','song-poetry','','[]','分曹歸政養耆年，李下何由更正冠。',64,'全唐诗/poet.song.3000.json','["分曹歸政養耆年，李下何由更正冠。", "賢相賦詩同嘯傲，聖君優詔去盤桓。", "龐眉老叟俱稱壽，凌雪喬松豈畏寒。", "屈指五人齊五福，鄉人須作二疏看。"]'),
('180164b7-e9f1-45e1-ab75-65db507fafcf','昭慶寺看芍藥','王渙','宋','宋诗','song-poetry','','[]','一半春光過牡丹，又開芍藥遍禪關。',64,'全唐诗/poet.song.3000.json','["一半春光過牡丹，又開芍藥遍禪關。", "久辜佳約違蓮社，今續清歡到寶藍。", "垂露幾團花面濕，東風一陣燕泥寒。", "酒邊何味呈奇供，綠笋朱櫻正滿盤。"]'),
('dc204417-32ae-4c77-86ba-8e928b1f7ba2','建茶呈使君學士','李虛己','宋','宋诗','song-poetry','','[]','石乳標奇品，瓊英碾細文。',48,'全唐诗/poet.song.3000.json','["石乳標奇品，瓊英碾細文。", "試將梁苑雪，煎勳建溪雲。", "清味通宵在，餘香隔坐聞。", "遥思摘山月，龍焙未春分。"]'),
('79103a5f-1ceb-4674-9813-551688a6f5ea','次韻和內翰楊大年見寄','李虛己','宋','宋诗','song-poetry','','[]','鼇冠三峰碧海寬，雲謠初下靄芝蘭。',64,'全唐诗/poet.song.3000.json','["鼇冠三峰碧海寬，雲謠初下靄芝蘭。", "采珠宮裏驪龍睡，織錦機中彩鳳盤。", "藥砌蒼苔錢作點，粉牆脩竹玉爲竿。", "閑從莊蜨親鳬舄，曾得安期九轉丹。"]'),
('00d05164-4c0c-46d0-872f-7cb13541f697','和汝南秀才遊浄土見寄','李虛己','宋','宋诗','song-poetry','','[]','長松繫馬駐吟鞭，水殿沈檀一樹煙。',64,'全唐诗/poet.song.3000.json','["長松繫馬駐吟鞭，水殿沈檀一樹煙。", "苔破閑階幽鳥立，草芳深院老僧眠。", "桃花欲放條風後，茶蘂新供穀雨前。", "衰會賞詩多狎客，我無岐路近神仙。"]'),
('c997d759-fdf9-413d-b3a4-da743aa470de','寄化城寺','李虛己','宋','宋诗','song-poetry','','[]','化城金地出人羣，瀑布峰前一徑分。',64,'全唐诗/poet.song.3000.json','["化城金地出人羣，瀑布峰前一徑分。", "寶塔香燈諸洞見，石樓鐘磬半天聞。", "子明丹竈封秋蘚，李白書堂鏁暮雲。", "欲去未能還結念，展圖時誦北山文。"]'),
('d6456f35-34c1-4349-bee4-878f9177341a','送何水部蒙出牧宜陽','李虛己','宋','宋诗','song-poetry','','[]','宜川三月水東流，秀出江南二十州。',64,'全唐诗/poet.song.3000.json','["宜川三月水東流，秀出江南二十州。", "紅旆使君今日去，白衣舉子昔年游。", "海潮賦就藏書府，競渡詩成在郡樓。", "國史待修循吏傳，政聲早晚達凝旒。"]'),
('08245598-da0e-4428-a24b-eab7e754a767','題義門胡氏華林書院  其一','李虛己','宋','宋诗','song-poetry','','[]','聚族逢修偃，垂紳偶會昌。',96,'全唐诗/poet.song.3000.json','["聚族逢修偃，垂紳偶會昌。", "里閭師重厚，門閥誡輕揚。", "木壠堆雲秀，書帷積雪光。", "清名傳異域，麗句出中堂。", "玉藴山還潤，蘭生谷更香。", "友朋敦布素，童稚味膏粱。", "鑄劍歸農器，休牛見服箱。", "齋心常拱極，端簡立秋霜。"]'),
('aa149119-27e2-4459-ab35-d4f5d2de87db','題義門胡氏華林書院  其二','李虛己','宋','宋诗','song-poetry','','[]','綠池寒竹繞書齋，鼓篋橫經任往迴。',64,'全唐诗/poet.song.3000.json','["綠池寒竹繞書齋，鼓篋橫經任往迴。", "積善原從千里應，表門恩自九天來。", "文章卷裏蟾枝秀，禮義鄉中棣萼開。", "記得浮雲深處景，巖深應長棟梁材。"]'),
('5961b2e8-4f97-43a9-a1ef-5f1fc11e9798','題義門胡氏華林書院  其三','李虛己','宋','宋诗','song-poetry','','[]','部符南粵轉軺車，三寶新題表義閭。',64,'全唐诗/poet.song.3000.json','["部符南粵轉軺車，三寶新題表義閭。", "藥石好携靈運句，素筠留得蔡邕書。", "平原架上衣無主，過客堂中食無魚。", "見說下帷多俊士，共瞻司馬慕相如。"]'),
('e7115576-5881-42be-bdd0-19dffe54c5b7','磨崖碑  其一','周繕','宋','宋诗','song-poetry','','[]','賢才思述作，崖石尚磨礱。',24,'全唐诗/poet.song.3000.json','["賢才思述作，崖石尚磨礱。", "元才詞華麗，顔公筆跡雄。"]'),
('ced6bf54-2b54-47a0-9df9-6c7d3502fa05','磨崖碑  其二','周繕','宋','宋诗','song-poetry','','[]','筆跡因難泯，詞華詎可磨。',24,'全唐诗/poet.song.3000.json','["筆跡因難泯，詞華詎可磨。", "二賢名不朽，千古著山阿。"]'),
('57d3631c-0905-4fc5-9dc5-0abf3467f9ef','題太湖','羅處約','宋','宋诗','song-poetry','','["\u592a\u6e56"]','三萬六千頃，湖侵海內田。',48,'全唐诗/poet.song.3000.json','["三萬六千頃，湖侵海內田。", "逢山方得地，見月始知天。", "南國吞將盡，東溟勢欲連。", "何當灑爲雨，無處不豐年。"]'),
('b768f52d-c4be-47db-b34d-cf647d647c1d','梁縣界虸蚄蟲生','羅處約','宋','宋诗','song-poetry','','[]','方喜雲油布，俄聞葉螣生。',48,'全唐诗/poet.song.3000.json','["方喜雲油布，俄聞葉螣生。", "田神何縱虐，稼政自非明。", "潁鳳那充食，吳牛已絕耕。", "黄堂厭粱肉，對爾自心驚。"]'),
('8ca96244-387d-4e51-b304-7e3085c393b9','吳江聖壽寺','羅處約','宋','宋诗','song-poetry','','[]','漁翁沙鳥傍迴塘，携杖閑吟繞寺廊。',64,'全唐诗/poet.song.3000.json','["漁翁沙鳥傍迴塘，携杖閑吟繞寺廊。", "遠岫不離青草渡，片帆時過綠苔牆。", "風狂林木生清籟，日暖漣漪動畫梁。", "張翰思鄉應有意，幾多屏障水爲鄉。"]'),
('0544d898-acac-49f5-8847-976456b28755','句  其一','羅處約','宋','宋诗','song-poetry','','[]','無風烟焰直。',6,'全唐诗/poet.song.3000.json','["無風烟焰直。"]'),
('3f3474da-3e60-4b03-bf28-332d2e8e63c9','句  其二','羅處約','宋','宋诗','song-poetry','','[]','日移竹影侵棋局。',8,'全唐诗/poet.song.3000.json','["日移竹影侵棋局。"]'),
('a65ff38e-e1c2-4af6-91da-fd9dbc1d7603','贈翰林學士宋公白','蘇易簡','宋','宋诗','song-poetry','','[]','天子昔取士，先俾分媸妍。',72,'全唐诗/poet.song.3000.json','["天子昔取士，先俾分媸妍。", "濟濟俊兼秀，師師麟與鸞。", "小子最承知，同輩尋改觀。", "甲第叨薦名，高飛便凌煙。", "遂使拜扆坐，果得超神仙。", "迄今才七歲，相接乘華軒。"]'),
('21e2814b-eebc-416a-af9d-3d618ea7f30c','禁林讌會之什','蘇易簡','宋','宋诗','song-poetry','','[]','雨晴禁署絕纖塵，讌會名賢四海聞。',96,'全唐诗/poet.song.3000.json','["雨晴禁署絕纖塵，讌會名賢四海聞。", "供職盡居清顯地，崇儒同感聖明君。", "翩然飛白璇題字，煥若丹青翠琰文。", "梓澤笙歌誠外物，蘭亭詩酒不同羣。", "少年已作瀛洲老，他日終棲太華雲。", "莫怪坐間全不飲，心中和氣自醺醺。"]'),
('a0eb0430-9f5e-4058-a2be-70c964ca99ca','題臨蘭亭序','蘇易簡','宋','宋诗','song-poetry','','[]','有若似夫子，尚興闕里門。',48,'全唐诗/poet.song.3000.json','["有若似夫子，尚興闕里門。", "虎賁狀蔡邕，猶旁文舉樽。", "昭陵自一閉，真蹟不復存。", "予今獲此本，亦可比璵璠。"]'),
('54054abb-6c08-487b-aebe-ef8b9495b006','特吟詩二首送英公大師  其一','蘇易簡','宋','宋诗','song-poetry','','[]','乘舟南去唯尋酒，上馬西行只詠詩。',32,'全唐诗/poet.song.3000.json','["乘舟南去唯尋酒，上馬西行只詠詩。", "醒醉去留皆遂意，如斯方信是男兒。"]'),
('ded5f072-0e33-41bd-baa7-ced10032d39a','特吟詩二首送英公大師  其二','蘇易簡','宋','宋诗','song-poetry','','[]','祝融峰上曾傳納，太一山前舊結廬。',32,'全唐诗/poet.song.3000.json','["祝融峰上曾傳納，太一山前舊結廬。", "兩地逍遥已三紀，爭教肯在帝城居。"]'),
('94e24c66-8b95-4a6b-9edd-47d0e3a8fbdb','句  其一','蘇易簡','宋','宋诗','song-poetry','','[]','玉堂臣老非仙骨，猶在丹臺望泰階。',16,'全唐诗/poet.song.3000.json','["玉堂臣老非仙骨，猶在丹臺望泰階。"]'),
('7b4fe9be-825e-421e-bcee-92cc91a3150b','句  其二','蘇易簡','宋','宋诗','song-poetry','','[]','天賦九華名狀別，岧嶢勝槩壓諸方。',16,'全唐诗/poet.song.3000.json','["天賦九華名狀別，岧嶢勝槩壓諸方。"]'),
('00c3527e-5d38-43b9-a3fa-fd5fe71a5d01','句  其三','蘇易簡','宋','宋诗','song-poetry','','[]','蝦鬚半卷天香散。',8,'全唐诗/poet.song.3000.json','["蝦鬚半卷天香散。"]'),
('b55a351f-38f4-4aa5-b841-df8c5f008e38','句  其四','蘇易簡','宋','宋诗','song-poetry','','[]','憔悴貳卿三十六，與師氣味不爭多。',16,'全唐诗/poet.song.3000.json','["憔悴貳卿三十六，與師氣味不爭多。"]'),
('903af81e-7f6a-4c4d-8096-40e2d1525acf','句  其五','蘇易簡','宋','宋诗','song-poetry','','[]','忠孝一生心。',6,'全唐诗/poet.song.3000.json','["忠孝一生心。"]'),
('d56d77bd-6f80-4d10-9146-c25bb917a710','存目  其一','蘇易簡','宋','宋诗','song-poetry','','[]','詩題：懷安官舍病起九日作首句：籬菊今年拆最繁。',23,'全唐诗/poet.song.3000.json','["詩題：懷安官舍病起九日作首句：籬菊今年拆最繁。"]'),
('cfbdc18f-7b90-4f32-9028-94d6b224750d','存目  其二','蘇易簡','宋','宋诗','song-poetry','','[]','詩題：十日菊首句：寂寞東籬下。',15,'全唐诗/poet.song.3000.json','["詩題：十日菊首句：寂寞東籬下。"]'),
('30629bbf-6d18-44b4-a602-607185fc3b02','存目  其三','蘇易簡','宋','宋诗','song-poetry','','[]','詩題：重陽述懷首句：屋頭寒雀作饑聲。',18,'全唐诗/poet.song.3000.json','["詩題：重陽述懷首句：屋頭寒雀作饑聲。"]'),
('dd28d208-7f44-4541-819d-49f2e847ff9f','登山頂','高輔堯','宋','宋诗','song-poetry','','[]','由徑尋山路，登臨步步疑。',48,'全唐诗/poet.song.3000.json','["由徑尋山路，登臨步步疑。", "縱高終带險，任達亦須危。", "況是多防地，那堪獨力時。", "荆榛方櫛比，直道擬奚爲。"]'),
('7df161f6-6568-4d21-b252-3b93bc62ca4a','送舒殿丞知荆州','趙安仁','宋','宋诗','song-poetry','','[]','建隼提封雲夢澤，臨民咫尺峴山碑。',32,'全唐诗/poet.song.3000.json','["建隼提封雲夢澤，臨民咫尺峴山碑。", "煙凝郊郭漳波浄，翠遶樓臺楚嶠奇。"]'),
('efffeebb-5d0f-4b54-8a0c-f0e2a7248537','題徐氏金湖書院','馮拯','宋','宋诗','song-poetry','','[]','古艾地多勝，修寧景最幽。',48,'全唐诗/poet.song.3000.json','["古艾地多勝，修寧景最幽。", "溪聲常到枕，山色正含秋。", "樹密苔封徑，庭虛月滿樓。", "清輝光累世，高義藉名流。"]'),
('e3b56e8d-c365-43ee-bf9f-44e845952754','旅舍述懷','程宿','宋','宋诗','song-poetry','','[]','北山之北寄柴扉，茅屋參差倚翠微。',64,'全唐诗/poet.song.3000.json','["北山之北寄柴扉，茅屋參差倚翠微。", "老罷那知還作客，春深無奈苦思歸。", "淹留恐復荒三徑，潦倒寧堪護六飛。", "乘鶴雙鳬成底事，不應容易裂荷衣。"]'),
('d11ff925-55e9-48a2-8400-1cb359557265','存目','程宿','宋','宋诗','song-poetry','','[]','詩題：送葉善卷致仕歸吳首句：衛尉新除蓋次公。',22,'全唐诗/poet.song.3000.json','["詩題：送葉善卷致仕歸吳首句：衛尉新除蓋次公。"]'),
('91eebe31-83dd-437e-b58e-9863c9321e6c','萬杉寺','俞獻可','宋','宋诗','song-poetry','','[]','栽培萬杉樹，延納五峰雲。',24,'全唐诗/poet.song.3000.json','["栽培萬杉樹，延納五峰雲。", "蓮社松門接，陶居柳徑分。"]'),
('64d82988-822f-47dd-960d-04d6bf9f5af8','詩一首','趙自然','宋','宋诗','song-poetry','','[]','常欲棲山島，閑眠玉洞寒。',24,'全唐诗/poet.song.3000.json','["常欲棲山島，閑眠玉洞寒。", "丹哥時引舞，來去跨雲鸞。"]'),
('ec9a5175-c4af-41ec-9deb-343ba3881f16','送僧歸護國寺','李及','宋','宋诗','song-poetry','','[]','高迹寧留得，禪心萬法空。',48,'全唐诗/poet.song.3000.json','["高迹寧留得，禪心萬法空。", "來從丹闕下，去返赤城中。", "入舫袈裟月，穿林錫杖風。", "何時結香社，宴寂與師同。"]'),
('b27620c4-fc5d-4029-bc38-bf5c66a07498','句','李及','宋','宋诗','song-poetry','','[]','夕霽巴城月，秋光峽樹春。',12,'全唐诗/poet.song.3000.json','["夕霽巴城月，秋光峽樹春。"]'),
('e33dcf6d-00c7-4fef-9733-f8f6ea3e5740','謝客巖','姚揆','宋','宋诗','song-poetry','','[]','不見古君子，空餘舊林巒。',36,'全唐诗/poet.song.3000.json','["不見古君子，空餘舊林巒。", "翠色媚車馬，爽氣嚴衣冠。", "天水交影碧，松竹聲相寒。"]'),
('fbcff4d7-4c22-44db-b902-bb3ee40d5d71','句','姚揆','宋','宋诗','song-poetry','','[]','獨上西樓四望賒。',8,'全唐诗/poet.song.3000.json','["獨上西樓四望賒。"]'),
('82e05515-47ff-4634-8df6-6e99bb150c2f','及第後寄宜春親友','許載','宋','宋诗','song-poetry','','[]','只把文章謁帝居，便從平地躡空虛。',32,'全唐诗/poet.song.3000.json','["只把文章謁帝居，便從平地躡空虛。", "分明有箇上天路，何事兒孫不讀書。"]'),
('b592eb72-fae7-4589-87c3-643337b539ff','題巫山神女廟','吳簡言','宋','宋诗','song-poetry','','[]','惆悵巫娥事不平，當時一夢是虛成。',32,'全唐诗/poet.song.3000.json','["惆悵巫娥事不平，當時一夢是虛成。", "只因宋玉閑唇吻，流盡巴江洗不清。"]'),
('44a97f71-0995-44c4-be14-af6316efd7ea','題白雲巖','宋濤','宋','宋诗','song-poetry','','[]','白雲巖在白雲間，巖下千山與萬山。',32,'全唐诗/poet.song.3000.json','["白雲巖在白雲間，巖下千山與萬山。", "莫向公卿容易道，恐伊來此一生閒。"]'),
('cb4019bd-0bd2-4136-a47f-9130c33be504','宿崇聖院','彭應求','宋','宋诗','song-poetry','','[]','公程無暇日，暫得宿清幽。',48,'全唐诗/poet.song.3000.json','["公程無暇日，暫得宿清幽。", "始覺空門客，不生浮世愁。", "溫泉喧古洞，寒磬度危樓。", "徹曉都忘寐，心疑在沃洲。"]'),
('fc7a9363-32aa-478e-aa3a-9dacda0eecc1','龍多山','彭應求','宋','宋诗','song-poetry','','[]','一望東川盡數州，依崖泉石更清幽。',32,'全唐诗/poet.song.3000.json','["一望東川盡數州，依崖泉石更清幽。", "不辭挹月披雲卧，攬取山房一夕秋。"]'),
('00fe3a4e-9bea-41f3-b02f-278e26b29aa3','句','彭應求','宋','宋诗','song-poetry','','[]','松陰轉處琴書潤，花片飛來枕簟凉。',16,'全唐诗/poet.song.3000.json','["松陰轉處琴書潤，花片飛來枕簟凉。"]'),
('b8ab12da-75a9-4e66-bb39-56d58031a336','送張無夢歸天台','黄震','宋','宋诗','song-poetry','','[]','想別岐周不記年，丹丘高卧好林泉。',64,'全唐诗/poet.song.3000.json','["想別岐周不記年，丹丘高卧好林泉。", "飛名已出紅塵外，放跡纔辭紫殿前。", "虛室先輸君靜坐，野雲終俟我閒眠。", "長歌宸翰真皇賜，袖去須知世世傳。"]'),
('57f752c9-4503-4575-b685-d096361ba26a','題法華山天衣寺','曾會','宋','宋诗','song-poetry','','[]','十里湖光十里松，松陰路到十高峰。',64,'全唐诗/poet.song.3000.json','["十里湖光十里松，松陰路到十高峰。", "窗看渡口隨湖月，樓聽雲門度嶺鐘。", "梁帝鉢含山雨潤，普賢臺鏁蘚花重。", "誰人的是忘機子，香稻寒蔬養瘦容。"]'),
('0c1f0182-8a7f-4247-8f51-9393ce1b970b','送張無夢歸天台','曾會','宋','宋诗','song-poetry','','[]','九重留不住，乘興返天台。',48,'全唐诗/poet.song.3000.json','["九重留不住，乘興返天台。", "青嶂未爲靜，彤庭應更來。", "御歌編隠訣，卧榻近丹臺。", "衣袂含香氣，蓬萊醉幾迴。"]'),
('ac17aa7f-77bc-4cf2-99b4-906a93a310c4','寄泉僧定諸','曾會','宋','宋诗','song-poetry','','[]','赤城山去刺桐城，還往都無一月程。',32,'全唐诗/poet.song.3000.json','["赤城山去刺桐城，還往都無一月程。", "日日焚香遥稽首，五更河露濕人衣。"]'),
('828c0807-1bc0-424e-9415-190f7cd1971f','題仙都山二首  其一','曾會','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','時常展畫圖，今喜到仙都。',192,'全唐诗/poet.song.3000.json','["時常展畫圖，今喜到仙都。", "盡得煙霞景，方知手筆粗。", "擎天成一柱，鎮地出三吳。", "苔片封車轍，蓮香泛鼎湖。", "占風來海國，迎日上雲衢。", "似筍千尋直，如藍四面鋪。", "秀能通造化，高豈礙摶扶。", "雷雨生巖竇，星辰遶藥爐。", "金華慚叱石，玉女望投壺。", "觀古壇尤在，碑荒字半無。", "未曾迷阮肇，何倦醉麻姑。", "塵外標名異，空中立影孤。", "笑秦銘泰嶽，嫌舜葬蒼梧。", "夏月風長滿，秋霜草不枯。", "步虛吟羽客，滴翠濕樵夫。", "獨稱瀛洲侶，吟看典郡符。"]'),
('202fe8f4-c9eb-42f2-a951-d3ad291a0004','題仙都山二首  其二','曾會','宋','宋诗','song-poetry','','[]','瀛洲風月十年餘，東出雲堂典郡符。',32,'全唐诗/poet.song.3000.json','["瀛洲風月十年餘，東出雲堂典郡符。", "更到煙霞最深處，分明景物是仙都。"]'),
('47bdd8ef-a00a-42a2-8fc1-d0f0b8eab46f','重登蕭相樓','曾會','宋','宋诗','song-poetry','','[]','不見當年李翰林，江天爲我結層陰。',64,'全唐诗/poet.song.3000.json','["不見當年李翰林，江天爲我結層陰。", "九華門外柳三尺，蕭相樓前松千尋。", "物在人亡空有淚，時殊事變獨傷心。", "隻雞斗酒江干市，白首風前楚些吟。"]'),
('76d7cef1-77cb-4c55-a48c-e1c878e90811','上齊山','曾會','宋','宋诗','song-poetry','','[]','秋日懸光八使來，笙歌十里郡筵開。',64,'全唐诗/poet.song.3000.json','["秋日懸光八使來，笙歌十里郡筵開。", "六朝草色鋪堤路，九日花香泛酒杯。", "紅袖歌長凝粉黛，紫微詩久蔽塵埃。", "賢人此會知無盡，不畏年華似箭催。"]'),
('c743b358-38bb-4c3b-82fb-552b027cec48','香積寺','曾會','宋','宋诗','song-poetry','','[]','松門石徑亂雲粘，四顧藍光冷射簷。',64,'全唐诗/poet.song.3000.json','["松門石徑亂雲粘，四顧藍光冷射簷。", "鏁霧樓臺陰自潤，嘯風猿鳥韻相兼。", "寒巖路僻憑僧指，古篆香殘待客添。", "須信苾蒭堪愛處，滿階芳草正纖纖。"]'),
('d34b1e83-c6d3-4ed3-a76e-3a9f0b324c17','題硯水','曾會','宋','宋诗','song-poetry','','[]','落筆重重見險津，不堪憑仗洗埃塵。',32,'全唐诗/poet.song.3000.json','["落筆重重見險津，不堪憑仗洗埃塵。", "無波浪處生波浪，愁殺孤帆過海人。"]'),
('0bd70dd7-e8d6-4566-b32f-21d259e6aad9','句','曾會','宋','宋诗','song-poetry','','[]','松間忽被青童指，金籙犀仙第二人。',16,'全唐诗/poet.song.3000.json','["松間忽被青童指，金籙犀仙第二人。"]'),
('cc3a98e5-3881-4d6a-9925-75a6445ae0e0','存目  其一','曾會','宋','宋诗','song-poetry','','[]','詩題：搗砧詞首句：星斿耿耿寒煙浮。',17,'全唐诗/poet.song.3000.json','["詩題：搗砧詞首句：星斿耿耿寒煙浮。"]'),
('9864acab-60c1-45d1-9848-1f2ad5fa297b','存目  其二','曾會','宋','宋诗','song-poetry','','[]','詩題：六月吟首句：曦輪獵野枯杉松。',17,'全唐诗/poet.song.3000.json','["詩題：六月吟首句：曦輪獵野枯杉松。"]'),
('f7d2c32b-2f27-44c3-a3e8-c2fd916b4bce','詠鸚鵡','釋定諸','宋','宋诗','song-poetry','','["\u548f\u7269", "\u5199\u9e1f", "\u548f\u7269\u8bd7", "\u529d\u8beb", "\u9e1f"]','罩在金籠好羽儀，分明喉舌似君稀。',32,'全唐诗/poet.song.3000.json','["罩在金籠好羽儀，分明喉舌似君稀。", "不須一向隨人語，須信人心有是非。"]'),
('b4f132ac-71a8-488d-be8e-8753be90a4c1','天封寺','劉丹','宋','宋诗','song-poetry','','[]','桂旗芝蓋翳濃陰，嚴宇崢嶸枕柰林。',64,'全唐诗/poet.song.3000.json','["桂旗芝蓋翳濃陰，嚴宇崢嶸枕柰林。", "蜺座有花和法雨，龍淵如鑑徹麩金。", "錫杖化去圓泉在，石誌文昏亂蘚侵。", "塵寰漸遥天路近，慈雲輝物已灰心。"]'),
('3a0d943c-1649-46d5-94dc-ce151526b59a','瞧陽五老會詩','朱貫','宋','宋诗','song-poetry','','[]','各還朝政遇堯年，鶴髮俱宜預道冠。',64,'全唐诗/poet.song.3000.json','["各還朝政遇堯年，鶴髮俱宜預道冠。", "乍到林泉能放曠，全拋簪紱尚盤桓。", "君恩至重如天覆，相坐時親畏地寒。", "九老且無元老貴，莫將西洛一般看。"]'),
('4f2c9528-64b3-4226-8a1a-36cb5d265735','聖號雅二篇  其一','趙湘','宋','宋诗','song-poetry','','[]','天監王德，莫如宋赫。',70,'全唐诗/poet.song.3000.json','["天監王德，莫如宋赫。", "宋道平平，莫如法天。", "皇法昊天，覆罔攸私。", "達乎鬼方，化被孔時。", "維戩維祿，維生維育。", "被彼蟲魚，及爾草木。", "惟命克遂，于其有俶。"]'),
('567a3cdd-55b2-4118-b97f-db7cc1f43a17','聖號雅二篇  其二','趙湘','宋','宋诗','song-poetry','','[]','皇振厥猷，法天以寧。',60,'全唐诗/poet.song.3000.json','["皇振厥猷，法天以寧。", "我法我度，我經我營。", "或風或雨，或雷或霆。", "日月昭然，奮皇之明。", "霜肅以平，露澤以清。", "左右百辟，爛兮敷星。"]'),
('3e77c30c-b3f4-4e6c-a80a-fdb43cbd0f00','聖號雅二篇  其三','趙湘','宋','宋诗','song-poetry','','[]','皇實法之，配道無作。',60,'全唐诗/poet.song.3000.json','["皇實法之，配道無作。", "始則以寬，終靡庸度。", "嗚呼下民，亦孔之莫。", "皇鑑下土，將安將樂。", "皇視四方，匪醜匪惡。", "法爾天永，民禱斯恪。"]'),
('70d66235-7a49-4977-a7ca-870d37fe1ec8','聖號雅二篇  其四','趙湘','宋','宋诗','song-poetry','','[]','赫赫君道，皇其崇之。',40,'全唐诗/poet.song.3000.json','["赫赫君道，皇其崇之。", "遹彼丕教，皇實基之。", "維基伊何，實以無爲。", "海隅蒼生，被服熙熙。"]'),
('0011aca1-825e-4ba8-a32a-7b9d5b039e67','聖號雅二篇  其五','趙湘','宋','宋诗','song-poetry','','[]','天下既平，狄人既庭。',40,'全唐诗/poet.song.3000.json','["天下既平，狄人既庭。", "其棘匪勞，神聖以寧。", "無亂斯聰，無惑斯明。", "衣裳自垂，冕旒是凝。"]'),
('b6df2ec3-cbfb-40ce-b9b9-93ed35335ed4','聖號雅二篇  其六','趙湘','宋','宋诗','song-poetry','','[]','烝哉皇極，道靡有息。',40,'全唐诗/poet.song.3000.json','["烝哉皇極，道靡有息。", "勤勤以謨，罔視其迹。", "鑿飲自鼓，耕食自績。", "維相以歌，勿荷後辟。"]'),
('f018b2e4-ffbe-48f8-b1fd-3ca86edbe642','聖號雅二篇  其七','趙湘','宋','宋诗','song-poetry','','[]','皇宅斯道，汗汗浩浩。',40,'全唐诗/poet.song.3000.json','["皇宅斯道，汗汗浩浩。", "賢俊茀茀，鐘鼓考考。", "爰煦爾赤，爰妥其老。", "樂只萬國，寧德攸寶。"]'),
('d8f9e79c-1584-424b-a463-bb25f2a5904e','聖號雅二篇  其八','趙湘','宋','宋诗','song-poetry','','[]','皇道靡徹，載昭載晰。',40,'全唐诗/poet.song.3000.json','["皇道靡徹，載昭載晰。", "克彼有截，萬國是悅。", "皇矣聖朝，綿爾瓜瓞。", "是崇是潔，萬世貽厥。"]'),
('6667227c-c071-4f99-8a6a-7e2aed4e3485','宋頌','趙湘','宋','宋诗','song-poetry','','[]','九區混茫，皇天錫皇。',245,'全唐诗/poet.song.3000.json','["九區混茫，皇天錫皇。", "羲教農化，勛紀華彰。", "繼華於禹，承禹於湯。", "比於文武，逮其成康。", "聖道攸傳，富壽無疆。", "隋之棄仁，天命不常。", "殱厥侈毒，祚歸巨唐。", "唐孫復昏，蕩於四方。", "民瘼其咨，逾於懷襄。", "草創中間，崩析滋章。", "割山裂川，國爲披猖。", "氓不堪命，神恫其殃。", "俾宋有圖，橫弛豎張。", "日月五辰，齊其啟光。", "實維太祖，肇基建邦。", "有若有苗，逆命弗祥。", "爰整其師，赫怒斯揚。", "荆舒既貢，南海趨蹌。", "庸蜀微盧，雖險無當。", "惟爾曰夏，毒靡有流，民始克昌。", "屢饑而饌，久渴而漿。", "冰極授衣，暑煩降凉。", "洎我聖君，傳葉振芳。", "聖神仁明，浩浩汪汪。"]'),
('1b5b15d4-6b00-48a3-85ad-1a3323eb5b86','送駕部劉侯赴闕詩','趙湘','宋','宋诗','song-poetry','','[]','帝有天命，四方是宣。',240,'全唐诗/poet.song.3000.json','["帝有天命，四方是宣。", "祥有時數，元極則傳。", "愛物在皇，惡盈在天。", "惟彼廬墟，安寧有年。", "土沃無蠹，民驕且專。", "窮侈勿度，宄猾相肩。", "彼孽既盈，厥兆斯綿。", "天子眷之，丞相竦然。", "僉曰疇當，劉侯其賢。", "帝命欽哉，布教甚玄。", "儉以示之，信以布之。", "侈焉猾焉，禁之制之。", "惟公拳拳，是民咨咨。", "惟民未知，其惡去遲。", "公恐公懼，吾知天時。", "將及弗度，明年果饑。", "雨師不顧，其歲莫支。", "回祿仍怒，公豫其知。", "雖凶雖燄，弗禱弗祈。", "厥民既羸，爰求其私。", "始惻天變，相議而辭。", "公始儉我，我莫肯隨。", "公始廉我，謂公啟威。", "公實愛我，而莫之知。"]'),
('d975bd91-86ba-4558-afca-a483eeb1a8d6','華頂峰','趙湘','宋','宋诗','song-poetry','','[]','連天含積翠，石路接危藤。',48,'全唐诗/poet.song.3000.json','["連天含積翠，石路接危藤。", "日近棲鵰樹，雲迎望海僧。", "狖傳幽谷響，泉落斷崖冰。", "中有仙人宅，知居第幾層。"]'),
('7112f37d-96a2-4bd2-b6ed-5b1b15681d14','黄鶑','趙湘','宋','宋诗','song-poetry','','[]','黄金類羽翰，飛出雪晴山。',48,'全唐诗/poet.song.3000.json','["黄金類羽翰，飛出雪晴山。", "語曉他禽默，啼花別樹閒。", "微陽疑獨照，急管偶相關。", "紅杏園林闊，經時得往還。"]'),
('feed9f97-37ca-4ac4-918f-e2a494af4041','登程主簿南亭','趙湘','宋','宋诗','song-poetry','','[]','南溪亭蔽月，主簿好看雲。',48,'全唐诗/poet.song.3000.json','["南溪亭蔽月，主簿好看雲。", "暇日曾移樹，炎風盡带薰。", "四窗山曲入，一徑草微分。", "買石清流底，名賢待贈君。"]'),
('0e481b21-aa83-4bd5-9b24-a4e0b4268944','蘭江仁智亭','趙湘','宋','宋诗','song-poetry','','[]','蘭江江上亭，仁智稱爲名。',48,'全唐诗/poet.song.3000.json','["蘭江江上亭，仁智稱爲名。", "山色曉爭出，水光秋更清。", "微風飄復斷，好鳥過還鳴。", "曾伴陶公醉，疊聞漁唱聲。"]'),
('1c2bea0b-abcc-4e57-8b03-b8c96737926a','題石橋寺山井','趙湘','宋','宋诗','song-poetry','','[]','何年鑿蘚紋，寒氣觸僧魂。',48,'全唐诗/poet.song.3000.json','["何年鑿蘚紋，寒氣觸僧魂。", "穴在青松底，泉通白石根。", "汲因嘗茗客，窺有斷腸猿。", "偶向秋來照，吟髭雪露痕。"]'),
('74ea19d2-784d-4d27-a640-aecb94767c06','書松門寺壁','趙湘','宋','宋诗','song-poetry','','[]','物外纖塵絕，堪聞樂道歌。',48,'全唐诗/poet.song.3000.json','["物外纖塵絕，堪聞樂道歌。", "好山光不盡，幽鳥語無多。", "樹影秋雲雜，泉聲晝磬和。", "高僧自禪定，時有野人過。"]'),
('e8c08604-8836-4bf2-af5e-a4c5715f248e','登揚州孝先寺佛閣','趙湘','宋','宋诗','song-poetry','','[]','勝寺登危閣，凭欄即近鵰。',48,'全唐诗/poet.song.3000.json','["勝寺登危閣，凭欄即近鵰。", "無雲生北固，看日下南朝。", "木落吳山迥，天晴楚水遥。", "從容萬慮息，目喜赴僧招。"]'),
('5fe318d2-d905-4706-8321-24567921f7ef','金山寺','趙湘','宋','宋诗','song-poetry','','[]','衆木皆穿石，名香自合焚。',48,'全唐诗/poet.song.3000.json','["衆木皆穿石，名香自合焚。", "兩廊吳分月，一閣楚天雲。", "雨過新燈露，潮平晚磬分。", "僧吟貝多偈，夜靜釣人聞。"]'),
('5b056442-eba7-4097-a997-8ada6e8d88eb','九日松林寺登高','趙湘','宋','宋诗','song-poetry','','[]','九日松林寺，登高過石橋。',48,'全唐诗/poet.song.3000.json','["九日松林寺，登高過石橋。", "野僧憐不醉，山菊笑無憀。", "屐齒憑泉漱，雲衣近樹飄。", "自知清靜意，應免俗人招。"]'),
('379f8631-eb40-4d1f-9a22-296a59033658','登天竺靈隠寺上方','趙湘','宋','宋诗','song-poetry','','[]','寺高傳絕頂，一到即忘機。',48,'全唐诗/poet.song.3000.json','["寺高傳絕頂，一到即忘機。", "夜月逢僧早，秋雲出樹微。", "磬邊巖狖過，窗外海鵰飛。", "欲下莓苔磴，題名却惜歸。"]'),
('4ecd8288-f3d3-4085-a064-b0965a54b7a3','題國清寺','趙湘','宋','宋诗','song-poetry','','[]','物外千年寺，人間四絕名。',48,'全唐诗/poet.song.3000.json','["物外千年寺，人間四絕名。", "兩廊諸嶽色，九里亂松聲。", "海氣飄僧院，秋鐘徹懸城。", "夜來疏磬斷，月影徧樓清。"]'),
('fa5a3a2d-b05b-4d7c-b452-8194dfd3ae5f','蘭汀晚泊','趙湘','宋','宋诗','song-poetry','','[]','孤舟愁晚泊，葭葦暫相鄰。',48,'全唐诗/poet.song.3000.json','["孤舟愁晚泊，葭葦暫相鄰。", "旅雁初棲雨，江花偶向人。", "强吟還自愛，忽語有誰親。", "倚棹煙將暝，秋風起白蘋。"]'),
('d0cabeae-4ebe-4046-8aad-8396b53e32b7','秦淮晚泊','趙湘','宋','宋诗','song-poetry','','[]','晚泊秦淮上，無人獨倚檣。',48,'全唐诗/poet.song.3000.json','["晚泊秦淮上，無人獨倚檣。", "遥峰平積水，別浦露殘陽。", "往事隨天望，新蟬聒樹黄。", "漁翁有深意，不語自鳴榔。"]'),
('d40f3d36-1fad-4cee-b1c2-b7eb01e124fc','書韓隠人壁','趙湘','宋','宋诗','song-poetry','','[]','雨黑徑垂莎，全家在薜蘿。',48,'全唐诗/poet.song.3000.json','["雨黑徑垂莎，全家在薜蘿。", "樹空穿井出，門掩燒痕過。", "寫易澌生硯，懸壺月上柯。", "近來山屐老，枯齒旋無多。"]'),
('a3ed0c1b-5137-4b70-b3c5-16ca552f6ce4','戊子歲東歸書事呈龐先輩','趙湘','宋','宋诗','song-poetry','','[]','上國有春榜，遠人無試期。',48,'全唐诗/poet.song.3000.json','["上國有春榜，遠人無試期。", "携琴出關早，聞雨到家遲。", "卧病鄰皆笑，嫌貧僕轉癡。", "高堂倚門久，此去尚多岐。"]'),
('69484695-fe7c-4d8f-9c38-513abcd42d4f','題張處士山庭落葉','趙湘','宋','宋诗','song-poetry','','[]','摇落拂殘棋，蕭騷傍菊籬。',48,'全唐诗/poet.song.3000.json','["摇落拂殘棋，蕭騷傍菊籬。", "硯浮窗外影，人拾樹中詩。", "掃綠粘苔冷，燒紅煮茗遲。", "巢烏還有意，猶在月明枝。"]'),
('b9e7a112-f9e0-40bd-b5e1-f684c5016b88','招阮山人宿','趙湘','宋','宋诗','song-poetry','','[]','初晴石路新，溪戶別無鄰。',48,'全唐诗/poet.song.3000.json','["初晴石路新，溪戶別無鄰。", "自夏評詩徧，經秋掃葉頻。", "拂琴堂有月，餐藥病離身。", "欲話因來宿，西軒只兩人。"]'),
('42666924-f468-4ef2-993e-6621047771ae','自題','趙湘','宋','宋诗','song-poetry','','[]','獨居顔子巷，還自種忘憂。',48,'全唐诗/poet.song.3000.json','["獨居顔子巷，還自種忘憂。", "偶病閒辜月，因吟瘦過秋。", "泣多曾憶阮，貧極尚師丘。", "散拙兼成癖，如何稱俗流。"]'),
('870b7f66-194f-4f6a-8c35-69aa4c3054da','江秀才新居','趙湘','宋','宋诗','song-poetry','','[]','營居知避俗，領鶴過秋郊。',48,'全唐诗/poet.song.3000.json','["營居知避俗，領鶴過秋郊。", "泉照書初架，窗移樹未巢。", "留題新墨濕，掩戶舊鄰敲。", "數本當簾竹，茶煙漸欲交。"]'),
('0a321010-9936-4eb1-bc16-43842f8ab750','剡中唐郎中所居','趙湘','宋','宋诗','song-poetry','','[]','古柳垂溪水，當門繫雪舟。',48,'全唐诗/poet.song.3000.json','["古柳垂溪水，當門繫雪舟。", "開樽延白鳥，掃樹带清秋。", "閣上看華頂，窗中見沃洲。", "尋常投刺少，來即是詩流。"]'),
('b7e2d0e3-4335-49f6-ac65-87f00ea6f686','秋夜集李式西齋','趙湘','宋','宋诗','song-poetry','','[]','澤國秋光淡，詩家夜會清。',48,'全唐诗/poet.song.3000.json','["澤國秋光淡，詩家夜會清。", "雨餘逢月色，風靜得琴聲。", "小徑幽蟲絕，寒階落葉并。", "嘗茶不擬睡，自起遶池行。"]'),
('9130b25a-1c0a-45c3-825f-b4849e232ced','別耶溪諸叔','趙湘','宋','宋诗','song-poetry','','[]','又散耶溪會，斜陽在古原。',48,'全唐诗/poet.song.3000.json','["又散耶溪會，斜陽在古原。", "出門逢落葉，去路有啼猿。", "短髮不堪照，新詩誰與論。", "如何爲遠別，風雪宿孤村。"]'),
('f71efb3e-c06c-459a-b22f-05d97f43af1f','遊爛柯山','趙湘','宋','宋诗','song-poetry','','[]','仙人與王質，相會偶多時。',48,'全唐诗/poet.song.3000.json','["仙人與王質，相會偶多時。", "落日千年事，空山一局棋。", "樹高明月在，風動白雲移。", "未得酬身計，閒來學採芝。"]'),
('22620b10-4f2f-45f8-a295-91c1248090d0','天台香柏峰會思上人','趙湘','宋','宋诗','song-poetry','','[]','孤峰連鳥道，幽會興難忘。',48,'全唐诗/poet.song.3000.json','["孤峰連鳥道，幽會興難忘。", "對坐無人到，空林盡日香。", "斷崖逢積雪，高木露微陽。", "靜話看晴曉，聯聯過晚岡。"]'),
('966fcb4c-65dd-4cc4-be7f-d4278e9c4729','送杜少府赴華陰','趙湘','宋','宋诗','song-poetry','','[]','行路華山前，之官髮黑年。',48,'全唐诗/poet.song.3000.json','["行路華山前，之官髮黑年。", "移家擬拔宅，作尉已呼仙。", "近縣雲隨鶴，當門樹著蟬。", "吟詩因夜坐，毛女落秋天。"]'),
('ea1019c7-5799-488b-b4e7-3e9a3af0dea3','送張用礪殿丞赴闕','趙湘','宋','宋诗','song-poetry','','[]','詔書徵入闕，數日醉離筵。',48,'全唐诗/poet.song.3000.json','["詔書徵入闕，數日醉離筵。", "野老衣多淚，山溪雨送船。", "郡齋閒月色，江鳥得詩篇。", "省閣人相待，供吟幾樹煙。"]'),
('cfb2513c-5fb3-4d29-b937-0aa677a7f41b','寄梁鼎殿丞','趙湘','宋','宋诗','song-poetry','','[]','登門長失約，千里阻關河。',48,'全唐诗/poet.song.3000.json','["登門長失約，千里阻關河。", "每爲秋風至，空令夜夢多。", "舊時曾見許，新諾復如何。", "想望臨荒徑，微微雨滴蓑。"]'),
('cf78d9f3-c158-47e2-ab98-7662a9978344','送韓嶼秀才南遊','趙湘','宋','宋诗','song-poetry','','[]','楊柳一蟬清，關河九日行。',48,'全唐诗/poet.song.3000.json','["楊柳一蟬清，關河九日行。", "却來時未熟，此去雨初晴。", "僕嬾嫌書重，馿幽喜骨輕。", "還因得新句，山寺徧題名。"]'),
('4bcc8fa6-212b-45ee-9c66-38bf3ce48383','送李先輩罷官之四明','趙湘','宋','宋诗','song-poetry','','[]','官滿鶴衣輕，全家在四明。',48,'全唐诗/poet.song.3000.json','["官滿鶴衣輕，全家在四明。", "上船秋月白，到岸海山青。", "藥妙初痊病，詩高舊振名。", "遥思落帆處，太守出郊迎。"]'),
('35602ac8-2a8e-4a9e-9eee-4c364d4a5699','送李著作赴四明','趙湘','宋','宋诗','song-poetry','','[]','暫辭芸閣伴，欲上海邊城。',48,'全唐诗/poet.song.3000.json','["暫辭芸閣伴，欲上海邊城。", "地近瀛洲見，山連越水迎。", "駐帆寒草動，移旆曉霞明。", "到日新題出，登高待雪晴。"]'),
('c4c1ff8b-4451-493e-83f0-10a8baa8b186','送沈天錫赴始興司戶','趙湘','宋','宋诗','song-poetry','','[]','落葉上青衫，携家赴嶺南。',48,'全唐诗/poet.song.3000.json','["落葉上青衫，携家赴嶺南。", "欲行猶買藥，侵早即衝嵐。", "久賤惟知事，長貧不解慚。", "山城騎病馬，吟句去庭參。"]'),
('d5a46770-914e-4512-8477-236e835a4a5a','送周洞之蜀','趙湘','宋','宋诗','song-poetry','','[]','劍閣衝秋去，迢迢動鬰陶。',48,'全唐诗/poet.song.3000.json','["劍閣衝秋去，迢迢動鬰陶。", "千山非故國，九日莫登高。", "峽樹參天碧，巴猿向夕號。", "當壚人不在，何以慰離騷。"]'),
('358fcb00-c77f-4f26-929b-6915c0f755f3','送丁鶚下第客遊','趙湘','宋','宋诗','song-poetry','','[]','尊前泣復歌，清淚酒相和。',48,'全唐诗/poet.song.3000.json','["尊前泣復歌，清淚酒相和。", "別岸春風靜，孤舟夜雨多。", "鳥鳴煙草露，花逐夕陽波。", "我亦無憀者，東西欲奈何。"]'),
('36fcbcd5-2cac-4495-a18f-33cc412abe4a','送周湜秀才之武川謁黄員外','趙湘','宋','宋诗','song-poetry','','[]','特地照青銅，行行謁謝公。',48,'全唐诗/poet.song.3000.json','["特地照青銅，行行謁謝公。", "山窗新入夢，池館舊聞鴻。", "岐路雲邊去，炎蒸雨後空。", "郡齋如伴話，滿座是清風。"]'),
('82d25933-d55d-4eef-8159-4926b070deb9','送羅權','趙湘','宋','宋诗','song-poetry','','[]','相逢從冷澹，此別復凄凉。',48,'全唐诗/poet.song.3000.json','["相逢從冷澹，此別復凄凉。", "去路迎秋色，行衣拂夕陽。", "酒濃心易感，詩好意難忘。", "莫作關山役，吟髭況漸長。"]'),
('2de81831-106b-4162-af31-6ef30cbf37e3','送韓起','趙湘','宋','宋诗','song-poetry','','[]','門外雨初晴，春深送客行。',48,'全唐诗/poet.song.3000.json','["門外雨初晴，春深送客行。", "離筵近流水，芳草向空城。", "遠鳥啼仍亂，殘花墜欲并。", "會須頻飲酒，莫遣白髭生。"]'),
('8c3690a8-fe7b-4575-b87b-e12495f9c4ec','送到逢吉','趙湘','宋','宋诗','song-poetry','','[]','獨去誰相待，全家寄舊林。',48,'全唐诗/poet.song.3000.json','["獨去誰相待，全家寄舊林。", "雨聲鄉外盡，秋色水邊深。", "別酒香和菊，新詩束傍琴。", "將行還共立，江上起孤砧。"]'),
('3baba007-d8d7-40eb-ba40-561312cb1fbe','輦下送沈天錫','趙湘','宋','宋诗','song-poetry','','[]','未第逢花盡，殘陽照渡頭。',48,'全唐诗/poet.song.3000.json','["未第逢花盡，殘陽照渡頭。", "入關頻值雨，歸棹獨隨鷗。", "樹暗藏鳴鳥，山空接漫流。", "琴書不同去，猶在酒家樓。"]'),
('8bf82a20-fe8d-4916-a5d6-257cf47039ac','送劉熙','趙湘','宋','宋诗','song-poetry','','[]','落日照行衣，鄉程隔翠微。',48,'全唐诗/poet.song.3000.json','["落日照行衣，鄉程隔翠微。", "聽蟬臨水別，聞雨抱琴歸。", "鬢髮各疑短，天涯相見稀。", "離歌一聲斷，江上有鴻飛。"]'),
('ad4d2cc6-1f47-4d3d-9f0f-d91fdec678b0','答徐本','趙湘','宋','宋诗','song-poetry','','[]','天遠草離離，秋霖寄信遲。',48,'全唐诗/poet.song.3000.json','["天遠草離離，秋霖寄信遲。", "相思逢葉盡，獨坐聽蟬悲。", "岳色寒前見，松心雪後知。", "頻招猶未至，時復檢清辭。"]'),
('2ebcd852-e9df-43b2-b55b-bda7deaf1bb2','別所知','趙湘','宋','宋诗','song-poetry','','[]','知音不可得，此去但消魂。',48,'全唐诗/poet.song.3000.json','["知音不可得，此去但消魂。", "別夜俱聞雨，殘秋自出門。", "水橫芳草渡，煙蔽夕陽村。", "應念千山外，明朝獨聽猿。"]'),
('213a74e0-fb40-4952-a5c3-fb14c89aef33','別楊塤','趙湘','宋','宋诗','song-poetry','','[]','此身偏似雁，南北但孤飛。',48,'全唐诗/poet.song.3000.json','["此身偏似雁，南北但孤飛。", "久客難爲別，窮秋況未歸。", "去程寒雨細，留話夕陽微。", "試共江邊立，疏砧又搗衣。"]'),
('535318f3-8395-46d4-922a-cb85dab1bc3c','及第東歸泗上遇孫穆之話別','趙湘','宋','宋诗','song-poetry','','[]','偶負同年約，知君先出京。',48,'全唐诗/poet.song.3000.json','["偶負同年約，知君先出京。", "相逢得酒病，欲別值蟬聲。", "共立山當眼，分題雨過城。", "東歸幾人問，爲子耻詩名。"]'),
('f9b71025-1455-4b2c-a70b-d01210f460e5','贈何明府','趙湘','宋','宋诗','song-poetry','','[]','陶家宜寂寞，多醉復多才。',48,'全唐诗/poet.song.3000.json','["陶家宜寂寞，多醉復多才。", "鎖印秋山入，移琴夜雨來。", "試茶還掃葉，買樹亦和苔。", "妙句鄰僧乞，仍聞得藥回。"]'),
('31d45357-b682-4747-aacc-9a80cd0f3462','寄東陽王明府','趙湘','宋','宋诗','song-poetry','','[]','經炎雖得信，旦夕夢兼思。',48,'全唐诗/poet.song.3000.json','["經炎雖得信，旦夕夢兼思。", "多暇知無事，新秋合有詩。", "樹凉看雨過，吏散見蟬移。", "誰共清宵坐，西軒月滿池。"]'),
('38ed09d3-9b69-4801-b23d-2609175ed055','聞蟬因寄東陽王穆明府','趙湘','宋','宋诗','song-poetry','','[]','孤蟬鳴水湄，獨立少人知。',48,'全唐诗/poet.song.3000.json','["孤蟬鳴水湄，獨立少人知。", "急恐移他樹，清還似舊時。", "曾同秋館聽，併起雨堂思。", "南望臨風久，經年不得詩。"]'),
('f1bc652e-7126-46d0-8623-46b228c1e0bf','別王穆明府','趙湘','宋','宋诗','song-poetry','','[]','又作殘秋役，陶公爲斷魂。',48,'全唐诗/poet.song.3000.json','["又作殘秋役，陶公爲斷魂。", "此行知入夢，欲去更登門。", "落葉堆霜徑，微陽隔雨村。", "預愁山館宿，相憶獨聞猿。"]'),
('2c463986-9c2b-45f5-8032-98dcb63fc13d','寄楊坦明府','趙湘','宋','宋诗','song-poetry','','[]','不語仍孤立，何人知此情。',48,'全唐诗/poet.song.3000.json','["不語仍孤立，何人知此情。", "春禽鳴別樹，夜雨入空城。", "望遠魂堪斷，思閒夢亦清。", "曾陪遊嶽寺，遶竹共題名。"]'),
('4a881e4a-d784-4166-a28f-9230d33b0c05','贈潛溪李明府','趙湘','宋','宋诗','song-poetry','','[]','縣幽多水石，栽竹亦成畦。',48,'全唐诗/poet.song.3000.json','["縣幽多水石，栽竹亦成畦。", "聽雨公田近，開窗月嶽齊。", "宿禽無別語，病馬立閒蹄。", "夜坐聞清唱，何人釣月溪。"]'),
('c5cb64c8-bffb-42b2-8a56-5c9abe4c02f4','寄楊塤','趙湘','宋','宋诗','song-poetry','','[]','閉門苔自長，春恨極天涯。',48,'全唐诗/poet.song.3000.json','["閉門苔自長，春恨極天涯。", "落日山橫水，空城雨過花。", "斷狂曾避蝶，多病更聞蛙。", "江上無消息，風吹渡柳斜。"]'),
('2c6b81f9-36f8-4156-8f71-96d2e204092f','旅中示所知','趙湘','宋','宋诗','song-poetry','','[]','無憀作客時，況逼入關期。',48,'全唐诗/poet.song.3000.json','["無憀作客時，況逼入關期。", "聽雨醒如醉，聞蟬坐欲移。", "病催新髮長，貧有故人知。", "應念將行計，出門多路岐。"]'),
('04767483-77ad-40e1-a54b-7fbd95887431','秋夕宿楊明府廳','趙湘','宋','宋诗','song-poetry','','[]','主人無俗緣，留客菊花邊。',48,'全唐诗/poet.song.3000.json','["主人無俗緣，留客菊花邊。", "雨氣寒并竹，秋聲夜雜蟬。", "爽知於酒稱，閒覺愛棋偏。", "不欲欹孤枕，更深却潄泉。"]'),
('516dca6e-c7e1-4ac7-853e-5256ae3e03c2','暮春郊園雨霽','趙湘','宋','宋诗','song-poetry','','[]','郊園春已暮，霽色射疏籬。',48,'全唐诗/poet.song.3000.json','["郊園春已暮，霽色射疏籬。", "地靜苔過竹，沙清樹入池。", "野人來盡日，山鳥話多時。", "偶傍松窗立，微風動七絲。"]'),
('56cda9a2-a6f8-496f-93b6-fca4a992c171','詠山屐','趙湘','宋','宋诗','song-poetry','','[]','鳥道人分去，同行只有筇。',48,'全唐诗/poet.song.3000.json','["鳥道人分去，同行只有筇。", "過橋泉照齒，穿竹蘚留蹤。", "夜閣吟登月，秋山醉掛松。", "自窺還憶謝，會著在諸峰。"]'),
('ea6c8128-1796-4518-9be8-8812328195c1','秋日過吳侃幽居','趙湘','宋','宋诗','song-poetry','','[]','掩門多徑草，凉氣動疏林。',48,'全唐诗/poet.song.3000.json','["掩門多徑草，凉氣動疏林。", "細雨經煙盡，微陽到菊深。", "話詩無鳥過，試茗有僧尋。", "欲去還留宿，窗邊月照琴。"]'),
('1d97e02d-c928-4193-ac95-4280eba39d62','登高','趙湘','宋','宋诗','song-poetry','','[]','天晴九月九，秋思攪騰騰。',48,'全唐诗/poet.song.3000.json','["天晴九月九，秋思攪騰騰。", "大醉無人會，高山獨自登。", "看鴻時背水，採菊阻尋僧。", "往事還堪憶，狂吟罷未能。"]'),
('b91dae5d-a1f0-40cf-a980-4b5dccda20d7','自樂','趙湘','宋','宋诗','song-poetry','','[]','自樂原西趣，疏林入戶清。',48,'全唐诗/poet.song.3000.json','["自樂原西趣，疏林入戶清。", "洗池秋得月，移菊夜棲螢。", "古意憐琴淡，新題喜病醒。", "時聞岳僧至，閒講煮茶經。"]'),
('733c4cac-3d87-4dca-ac55-99f1598e6a5a','官舍偶書','趙湘','宋','宋诗','song-poetry','','[]','病枕方行藥，公門似隠居。',48,'全唐诗/poet.song.3000.json','["病枕方行藥，公門似隠居。", "孤煙寄庭木，微雨長秋蔬。", "宦薄慚騎馬，山高夢結廬。", "期僧仍未至，慵寫與人書。"]'),
('26690a99-1440-4c2b-8c2a-72afa23d2f25','野步','趙湘','宋','宋诗','song-poetry','','[]','原野宜秋步，支筇日欲斜。',48,'全唐诗/poet.song.3000.json','["原野宜秋步，支筇日欲斜。", "斷橋時立鳥，疏草露行蛇。", "細雨霑梨葉，微風過稻花。", "坡西又吹笛，煙火兩三家。"]'),
('60439d42-7d80-4c04-83e4-989cfeccdd39','贈省安上人','趙湘','宋','宋诗','song-poetry','','[]','閉門棲古寺，塵路杳無蹤。',48,'全唐诗/poet.song.3000.json','["閉門棲古寺，塵路杳無蹤。", "夜講香飄月，晨齋磬入松。", "石屏泉氣冷，山屐蘚痕濃。", "自說秋來興，時時夢遠峰。"]'),
('2c4e7469-4bd7-4200-b38f-d8537f56da95','僧院苔','趙湘','宋','宋诗','song-poetry','','[]','香銷人寂寂，鋪碧斷塵埃。',48,'全唐诗/poet.song.3000.json','["香銷人寂寂，鋪碧斷塵埃。", "積雨聲初盡，高僧定未開。", "冷痕穿竹去，秋陣隔泉回。", "此處應長在，閒人況不來。"]'),
('74d94941-5237-45f9-a0be-2339b234b5ae','會平上人夜話','趙湘','宋','宋诗','song-poetry','','[]','秋燈照岳客，深夜坐前軒。',48,'全唐诗/poet.song.3000.json','["秋燈照岳客，深夜坐前軒。", "白髮新聞雨，青山舊聽猿。", "病多添藥債，吟苦避蟲喧。", "不寐還相對，高梧葉自翻。"]'),
('6b4524b5-b195-45ed-bf43-d55793ae2b72','照上人山房庭樹','趙湘','宋','宋诗','song-poetry','','[]','惹雲非手植，自與薜蘿交。',48,'全唐诗/poet.song.3000.json','["惹雲非手植，自與薜蘿交。", "雨過苔侵影，秋來月照巢。", "錫寒枝上掛，偈好葉中抄。", "誰見僧行遶，煙凉夜磬敲。"]'),
('86e7eb85-32cc-4d1f-82e5-070259b67d8d','贈水墨巒上人','趙湘','宋','宋诗','song-poetry','','[]','講餘精小筆，深院竹脩脩。',48,'全唐诗/poet.song.3000.json','["講餘精小筆，深院竹脩脩。", "試墨因磨雨，思山忽寫秋。", "靜曾窮鶴趣，高亦近詩流。", "更擬緣清思，和雲狀沃洲。"]'),
('1abfaa10-4e09-4a3a-8e15-6cb39865784e','送僧歸終南','趙湘','宋','宋诗','song-poetry','','[]','夏滿辭京寺，終南路有松。',48,'全唐诗/poet.song.3000.json','["夏滿辭京寺，終南路有松。", "月高緣白閣，葉盡到中峰。", "漱齒泉飄錫，冥心露滴鐘。", "長安如不去，期與鹿相逢。"]'),
('0cd846ff-0020-44ec-9e26-11a1318f52a0','夏夜山中喜雨','趙湘','宋','宋诗','song-poetry','','[]','何峰雲共出，一夜灑山簷。',48,'全唐诗/poet.song.3000.json','["何峰雲共出，一夜灑山簷。", "爽氣連燈濕，凉聲得樹兼。", "醉吟還有意，卧聽似無厭。", "已約凌晨起，泉聲自捲簾。"]'),
('80414c43-5d17-4c6a-a711-d579a40aaf26','飲茶','趙湘','宋','宋诗','song-poetry','','[]','晝夢回窗下，秋聲碾樹邊。',48,'全唐诗/poet.song.3000.json','["晝夢回窗下，秋聲碾樹邊。", "僧敲石裏火，瓶汲竹根泉。", "影照吟髭碧，香醫酒病痊。", "坐餘重有味，猶見半牆煙。"]'),
('a3fbcf21-1eb5-4eb1-a512-c2f7306397fd','方廣寺石橋','趙湘','宋','宋诗','song-poetry','','[]','白石峰猶在，橋橫一徑微。',48,'全唐诗/poet.song.3000.json','["白石峰猶在，橋橫一徑微。", "多年無客過，落日有雲歸。", "水浄苔生髮，山寒樹著枝。", "如何方廣寺，千古去人稀。"]'),
('be5f08ef-2268-47ac-8a6c-e1d619d3fdf1','上穀川尹殿丞','趙湘','宋','宋诗','song-poetry','','[]','瑣闥題詩送赴官，郡齋瀟灑謝公閒。',64,'全唐诗/poet.song.3000.json','["瑣闥題詩送赴官，郡齋瀟灑謝公閒。", "樹邊棋閣開秋鎖，池上吟窗見晝山。", "吏散獨行紅葉外，酒醒時望白雲間。", "郊原漸有新烟火，知是逋民鳥道還。"]'),
('8a34b728-1155-4922-8ff0-ef3256f2fc86','寄新安梁殿丞','趙湘','宋','宋诗','song-poetry','','[]','郡孤詩句許秋供，見說多閒却似慵。',64,'全唐诗/poet.song.3000.json','["郡孤詩句許秋供，見說多閒却似慵。", "移樹好禽來獨院，上樓高雪在諸峰。", "泉當月際摇吟影，蘚自雲邊得屣蹤。", "此興未尋頻挂夢，阮公池館舊相容。"]'),
('ef1bf10d-9ac6-4bed-8d70-4fed41b3db05','寄湖州刁殿丞','趙湘','宋','宋诗','song-poetry','','[]','白蘋溪湛五亭寒，物象全宜謝守閒。',64,'全唐诗/poet.song.3000.json','["白蘋溪湛五亭寒，物象全宜謝守閒。", "秋盡棋聲過竹寺，雨餘詩思落茶山。", "鳥依高樹和煙宿，人釣清流带月還。", "池館有情多入夢，近來誰在笛聲間。"]'),
('9685dfc2-6a7f-40ce-a12a-51287c45a427','秋日過韓原隠居','趙湘','宋','宋诗','song-poetry','','[]','霜落門前石齒清，靜中曾聽咽泉聲。',64,'全唐诗/poet.song.3000.json','["霜落門前石齒清，靜中曾聽咽泉聲。", "分題會客多無說，抱疾迎僧忽强行。", "窗外葉隨蟬影過，井邊苔趁雨痕生。", "紗巾任側衣從破，二十年來不到城。"]'),
('0cb10e45-2a05-42bd-8ec5-5fdbdb004f33','贈蘭江鞠明府','趙湘','宋','宋诗','song-poetry','','[]','笛裏聲飄柳色寒，縣齋深在白雲間。',64,'全唐诗/poet.song.3000.json','["笛裏聲飄柳色寒，縣齋深在白雲間。", "孤吟夜倚琴邊月，半醉秋登宅後山。", "煙徑樹清苔蘚長，雨塘人散鷺鷥還。", "蘭舟有客題詩望，溪上家家晚唱闌。"]'),
('628b95bc-4dc8-4b72-9570-98b480ee03fd','寄蘭江鞠評事','趙湘','宋','宋诗','song-poetry','','[]','東望堪思捧刺時，姓名相齒有人知。',64,'全唐诗/poet.song.3000.json','["東望堪思捧刺時，姓名相齒有人知。", "公堂伴語山光入，秋閣嘗茶樹影移。", "石上琴尊容賞月，水邊臺榭許題詩。", "重因送客留連甚，長記還家不敢辭。"]'),
('02bce403-a6aa-40f6-bb29-46ba8db04b9c','送春','趙湘','宋','宋诗','song-poetry','','[]','留客强歌還强醉，送春多雨又多風。',64,'全唐诗/poet.song.3000.json','["留客强歌還强醉，送春多雨又多風。", "五更池館孤燈盡，三月江城一夜空。", "青鑑照髭疑有白，子規啼樹已無紅。", "相逢頼得明年約，應向花前慰斷蓬。"]'),
('bfd3f66c-0f56-44c8-aac6-6fa9d854fa27','春日宿信安張明府廳','趙湘','宋','宋诗','song-poetry','','[]','夕景含鐘露欲零，幽人醉宿長官廳。',64,'全唐诗/poet.song.3000.json','["夕景含鐘露欲零，幽人醉宿長官廳。", "牀頭蘚色雖連月，池底花陰更雜星。", "梧葉乍題無物汙，蜀琴微響有風經。", "陶公伴客不思睡，門外數峰山曉青。"]'),
('48f7e4d7-9edf-4c57-9c94-25bd41ed3a47','秋日江亭','趙湘','宋','宋诗','song-poetry','','[]','遠岸鳴蟬未擬休，蟬邊風葉動颼飀。',64,'全唐诗/poet.song.3000.json','["遠岸鳴蟬未擬休，蟬邊風葉動颼飀。", "平沙露白聊宜鶴，孤島分青獨映秋。", "野色半侵凉氣濕，水光低引夕陽流。", "題詩盡日無人伴，空憶瀟湘有釣舟。"]'),
('46e52058-ecc5-46a6-a7d1-49fe6af13970','秋夜舟中作','趙湘','宋','宋诗','song-poetry','','[]','酒醒身計正悠悠，澤國如萍信水流。',64,'全唐诗/poet.song.3000.json','["酒醒身計正悠悠，澤國如萍信水流。", "獨夜聽鴻深浦宿，壞篷連雨一燈秋。", "年來自覺新詩澹，江上誰憐舊業優。", "腸斷山家數聲笛，不知孤客在孤舟。"]'),
('b26c3a54-5f9a-4e8f-95aa-fe55d9e0e466','秋夕旅館言事','趙湘','宋','宋诗','song-poetry','','[]','一點孤燈萬里身，離腸曾攪九回頻。',64,'全唐诗/poet.song.3000.json','["一點孤燈萬里身，離腸曾攪九回頻。", "梧桐自管秋來雨，蟋蟀誰妨夜後人。", "枕上夢將衣共短，卷中詩與髮同新。", "江邊但厭携琴去，明月西風滿路塵。"]'),
('4a08e9cd-b340-43d3-95ce-f161d80a7f06','郊居言事','趙湘','宋','宋诗','song-poetry','','[]','斷徑危橋積蘚痕，閉關終與俗塵分。',64,'全唐诗/poet.song.3000.json','["斷徑危橋積蘚痕，閉關終與俗塵分。", "深秋鶴影臨池見，靜夜棋聲隔水聞。", "山榻病來誰寄藥，石牀僧去獨看雲。", "閒吟閒醉慵開眼，門外寒蟲叫日曛。"]'),
('1e4eb40a-585f-4d4a-b1bb-5f838557cb23','早秋言事','趙湘','宋','宋诗','song-poetry','','[]','苔染衡門綠有錢，不堪風月漸凄然。',64,'全唐诗/poet.song.3000.json','["苔染衡門綠有錢，不堪風月漸凄然。", "蛩聲乍出斜陽外，山色初來落木邊。", "掃葉偶窺栽菊地，卷簾因作擣衣篇。", "故人南北新髭長，昨夜高懷雨滴蟬。"]'),
('9dcd8a32-160f-4a90-a9b7-a7480b3a8340','暮秋過沈齊別業','趙湘','宋','宋诗','song-poetry','','[]','暮蟬頻響勝聞歌，白石牀清蘚色和。',64,'全唐诗/poet.song.3000.json','["暮蟬頻響勝聞歌，白石牀清蘚色和。", "徑冷獨留寒菊在，樹疏分得夕陽多。", "沙泉月澹曾棲雁，籬落烟微半著莎。", "誰問寂寥詩景趣，竹扉時有野僧過。"]'),
('158fe616-01c9-4f5a-a638-85c9094c0727','宿成秀才水閣','趙湘','宋','宋诗','song-poetry','','[]','卷箔無應永夜虛，凭欄還似釣魚師。',64,'全唐诗/poet.song.3000.json','["卷箔無應永夜虛，凭欄還似釣魚師。", "牀頭雨細飄蘆葦，池上燈寒照鷺鷥。", "孤枕聽泉隨斷夢，好風吹竹隔殘棋。", "主人不寐客魂爽，曉色欲來猶賦詩。"]'),
('0e3e3448-18bb-42b1-aa20-6d91c4c0367a','雨中寄所思','趙湘','宋','宋诗','song-poetry','','[]','寒氣蕭蕭瘦骨驚，自知分得四愁平。',64,'全唐诗/poet.song.3000.json','["寒氣蕭蕭瘦骨驚，自知分得四愁平。", "秋堂病起莓苔色，池閣夢回蘆葦聲。", "幽滴冷痕連樹影，暗驅浮氣入詩情。", "衡門獨掩還無語，一日相思萬縷并。"]'),
('01d21311-2e8f-4a43-86cf-4cd6dd462e26','登杭州冷泉亭','趙湘','宋','宋诗','song-poetry','','[]','天竺峰西月幾層，亭孤應忌俗人登。',64,'全唐诗/poet.song.3000.json','["天竺峰西月幾層，亭孤應忌俗人登。", "山光曉射聞猿客，泉影秋摇倚樹僧。", "微雨洒臺青有點，片雲生石冷多稜。", "斜陽更起題詩興，還喜重來或未能。"]'),
('98c5feb7-992a-4f9d-a661-155949c5403e','題包山人拄杖','趙湘','宋','宋诗','song-poetry','','[]','倚雲生處絕塵埃，見說嵩高客寄來。',64,'全唐诗/poet.song.3000.json','["倚雲生處絕塵埃，見說嵩高客寄來。", "扶醉未聞和屐到，伴吟曾是探山迴。", "尋僧過竹青敲月，看鶴沿池冷卓苔。", "知渡寒溪偏得力，夕陽風緊打冰開。"]'),
('cd528405-ddc3-48f5-b355-20043215d90a','蕭山李宰君北亭即事','趙湘','宋','宋诗','song-poetry','','[]','掃灑仍聞屬意勞，遶池生蘚不生蒿。',64,'全唐诗/poet.song.3000.json','["掃灑仍聞屬意勞，遶池生蘚不生蒿。", "敲花雨過琴絃潤，吹竹風來鶴語高。", "窗裏樹光清著枕，硯中山色冷趨毫。", "何人可作題詩伴，試茗應思謝法曹。"]'),
('54370934-c27c-49cc-ba55-82bf7e0d4c57','留連李寺丞吟詩閣','趙湘','宋','宋诗','song-poetry','','[]','靜閣採詩人罕到，棲棲樹石盡當簷。',64,'全唐诗/poet.song.3000.json','["靜閣採詩人罕到，棲棲樹石盡當簷。", "長因夜月全開戶，獨爲南山不下簾。", "得句硯中秋水減，覓題池上晚花添。", "炎天幾度相留宿，曾值風凉雨氣兼。"]'),
('813b1085-f5ff-4b65-8ac0-07860d1711e7','遊石橋寺','趙湘','宋','宋诗','song-poetry','','[]','陶令尋山勝境開，偶陪清賞憶天台。',64,'全唐诗/poet.song.3000.json','["陶令尋山勝境開，偶陪清賞憶天台。", "秋雲盡放諸峰出，野水時聞獨鳥來。", "巖畔坐宜窺蟋蟀，樹邊行亦避莓苔。", "斜陽石上題詩去，更向松陰遶一迴。"]'),
('43c10ab0-3d52-4b1d-b7b1-3d5254cabcde','秋日宿楚江西寺','趙湘','宋','宋诗','song-poetry','','[]','滄浪生計任西東，人向蕭園寄斷蓬。',64,'全唐诗/poet.song.3000.json','["滄浪生計任西東，人向蕭園寄斷蓬。", "燈影半軒無夢寐，雨聲長夜在梧桐。", "閒僧正笑吟髭白，故國那堪水樹紅。", "志業未知誰念我，明朝江上葦花風。"]'),
('9b1f98cc-1e21-4bec-a757-5ce0c93523ab','聞曉角','趙湘','宋','宋诗','song-poetry','','[]','一聲初起曉光浮，吟笛啼猿亦暗羞。',64,'全唐诗/poet.song.3000.json','["一聲初起曉光浮，吟笛啼猿亦暗羞。", "清動月華猶滿樹，冷呼山色欲歸棲。", "時縈別館侵燈過，偶带凉颸入夢流。", "誰會酒醒傾耳聽，近來沙塞不吹秋。"]'),
('9c15a134-6b8e-4b86-8f3b-b350cb74c05f','觀楚上人陳處士夜棋','趙湘','宋','宋诗','song-poetry','','[]','對局清宵解客醺，坐窺玄妙杳難羣。',64,'全唐诗/poet.song.3000.json','["對局清宵解客醺，坐窺玄妙杳難羣。", "勢侵孤燭和秋冷，聲隔高梧带雨分。", "關外散飛星出漢，水邊斜起雁穿雲。", "無人得見爭先意，時被西林宿鳥聞。"]'),
('5eaf261d-0617-493d-9ae0-36dfeb9525e6','山居引泉','趙湘','宋','宋诗','song-poetry','','[]','自引靈泉勝取冰，入雲窮穴始因僧。',64,'全唐诗/poet.song.3000.json','["自引靈泉勝取冰，入雲窮穴始因僧。", "閒疏咽處秋無際，靜聽時來月有層。", "乍覺疏林多爽氣，漸疑幽石減寒棱。", "雨餘終夜西風起，流過吟窗濺著燈。"]'),
('7e5b5b62-752a-469e-b9c3-b40c17d3d3c7','九日幽居書懷','趙湘','宋','宋诗','song-poetry','','[]','九月蟬稀九日催，年光如逐水聲回。',64,'全唐诗/poet.song.3000.json','["九月蟬稀九日催，年光如逐水聲回。", "人思往事凄凉在，菊倚荒庭寂寞開。", "落葉偶從池上過，夕陽初傍酒邊來。", "白衣去後無消息，雨濕東離欲長苔。"]'),
('f54cc988-924f-4035-9ad6-683d636efb33','山行','趙湘','宋','宋诗','song-poetry','','[]','翠滿衣裳遠徑分，漸供幽興入詩門。',64,'全唐诗/poet.song.3000.json','["翠滿衣裳遠徑分，漸供幽興入詩門。", "臨泉自愛窺筇影，過蘚何妨駐屐痕。", "因惹斷雲還倚石，偶看殘照學呼猿。", "行行却喜無人到，曾爲秋來挂夢魂。"]'),
('2fe69a35-ab71-490c-8b59-919537ea3475','憶別','趙湘','宋','宋诗','song-poetry','','[]','何處籬筵酒欲空，夜凉橫玉自吹風。',64,'全唐诗/poet.song.3000.json','["何處籬筵酒欲空，夜凉橫玉自吹風。", "人當木落關山外，秋在月明池館中。", "隔水不堪驚遠夢，入雲猶擬觸孤鴻。", "憑欄寂寂還多感，誰會無言憶馬融。"]'),
('17ec37f2-acc1-4611-a79f-9951c9390c30','書韓山人壁','趙湘','宋','宋诗','song-poetry','','[]','山木爭高葉盡深，山人半醉在庭陰。',64,'全唐诗/poet.song.3000.json','["山木爭高葉盡深，山人半醉在庭陰。", "常時具饌多餐藥，偶夜聽松不弄琴。", "雨後看苔連井口，秋來見月到池心。", "近聞牆外諸峰賣，只向茶鐺便煮金。"]'),
('4f73478c-6a56-45ef-81c6-fe3f72706f54','閒居書事寄逸人平上人','趙湘','宋','宋诗','song-poetry','','[]','雨驅寒蘚入衡門，顔子簞瓢近水濆。',64,'全唐诗/poet.song.3000.json','["雨驅寒蘚入衡門，顔子簞瓢近水濆。", "靜話忽容幽鳥聽，好詩長忌俗人聞。", "半簾松影和秋卷，一檻棋聲與竹分。", "野客有情僧有意，相思時望過溪雲。"]'),
('1db0ff59-c59f-451d-856f-1fa19c976988','春夕偶作','趙湘','宋','宋诗','song-poetry','','[]','一夕衡門獨自開，雨陰深巷少塵埃。',64,'全唐诗/poet.song.3000.json','["一夕衡門獨自開，雨陰深巷少塵埃。", "酒醒風傍池邊起，坐久月從花上來。", "何處夜歌初欲斷，四鄰春夢未知回。", "因思此興無人共，時復孤吟步綠苔。"]'),
('983513bc-a802-4c14-8610-678ccb97997b','贈張處士','趙湘','宋','宋诗','song-poetry','','[]','應問秋雲學得閒，飄然如不在人間。',64,'全唐诗/poet.song.3000.json','["應問秋雲學得閒，飄然如不在人間。", "青籐篋裏詩多怪，紫栗枝邊藥更瘢。", "江客對棋曾賭鶴，野僧分屐借登山。", "仍聞昨日來城市，又抱孤琴踏月還。"]'),
('1c5660b7-b32d-4da1-beb1-ee5d9c537234','寄霅川刁殿丞十二韻','趙湘','宋','宋诗','song-poetry','','[]','柳渾曾吟郡，中間遇牧之。',144,'全唐诗/poet.song.3000.json','["柳渾曾吟郡，中間遇牧之。", "留連皆往日，寂寞偶多時。", "物象應無改，軒車自有期。", "憶山辭闕早，採藥上官遲。", "澤國閒堪賞，公堂靜好窺。", "掃苔紅葉過，臨水白蘋移。", "樹石秋供畫，汀洲曉入詩。", "謳謠漁父得，孤潔鷺鷥知。", "笛外風含酒，樓中月照棋。", "野田耕带雨，寒井汲和澌。", "城郭煙霞近，人家橘柚垂。", "會須尋此景，況與二公宜。"]'),
('301188f0-c86b-41a8-8d86-fccfa13a7a56','寄梁鼎殿丞十二韻','趙湘','宋','宋诗','song-poetry','','[]','憶昔初投刺，秋風八詠邊。',144,'全唐诗/poet.song.3000.json','["憶昔初投刺，秋風八詠邊。", "偶參知好日，一見自多年。", "吏散公堂雨，簾垂館樹煙。", "共吟曾試茗，同坐或聞蟬。", "渡水尋支遁，登山學地仙。", "獻酬多奧妙，談笑屢遷延。", "夜月侵詩卷，寒燈落酒船。", "醉容韋带去，卧許石床連。", "池館今何遠，汀洲思倍牽。", "庾樓知有約，顔巷奈多緣。", "病眼隨蓬斷，愁心逐旆懸。", "高臺聊一望，芳草夕陽天。"]'),
('1790f8d4-6b83-45fd-bf74-95a3f9e14ced','答聖俞設膾示客','趙湘','宋','宋诗','song-poetry','','[]','梅侯三年江上居，盤羞慣飽鮆與鱸。',112,'全唐诗/poet.song.3000.json','["梅侯三年江上居，盤羞慣飽鮆與鱸。", "客居京城厭粗糲，買魚斫鱠邀朋徒。", "孰親刀匕擅精巧，閨中麗人家本吳。", "縷裁長絲葉剪藿，餖飣自與尋常殊。", "霜橙擣虀飯香稻，一飽豈顧家有無。", "我雖日病興不淺，坐想落紙霏紅腴。", "雕盤雋味儻可再，贈子佳酒隨長魚。"]'),
('df888553-1bb7-4a74-bf37-01f8df1dfc52','皇帝閤春帖子  其一','趙湘','宋','宋诗','song-poetry','','[]','和氣生金殿，微風轉畫旗。',24,'全唐诗/poet.song.3000.json','["和氣生金殿，微風轉畫旗。", "年年好春色，先是帝先知。"]'),
('00937ca6-50a1-4d29-bd4a-679b9342b9fb','皇帝閤春帖子  其二','趙湘','宋','宋诗','song-poetry','','[]','迎氣來歸祚，宜春祝降祥。',24,'全唐诗/poet.song.3000.json','["迎氣來歸祚，宜春祝降祥。", "皇心勤治切，應喜寸陰長。"]'),
('f5332bff-021c-44e0-aed2-1809c9b5df29','皇帝閤春帖子  其三','趙湘','宋','宋诗','song-poetry','','[]','醇醴浮金斝，柔蔬飣玉盤。',24,'全唐诗/poet.song.3000.json','["醇醴浮金斝，柔蔬飣玉盤。", "嘗新兼介壽，齊奉兩宮歡。"]'),
('380b252e-59fd-444b-a798-40b137137963','皇帝閤春帖子  其四','趙湘','宋','宋诗','song-poetry','','[]','晝漏新添刻，春寒早放班。',24,'全唐诗/poet.song.3000.json','["晝漏新添刻，春寒早放班。", "恩隨寬大詔，一日徧人間。"]'),
