('248b7842-3f94-4316-aa71-a9954eea7438','乙巳歲郊天後作','魏野','宋','宋诗','song-poetry','','[]','萬物盡熙熙，郊天禮畢時。',48,'全唐诗/poet.song.3000.json','["萬物盡熙熙，郊天禮畢時。", "安邊文教遠，過海赦書遲。", "南牧雖無也，東封合有之。", "茅堂自歌詠，何必向丹墀。"]'),
('eb512e32-43a4-4369-924a-2996ddab9c36','秋日懷王專','魏野','宋','宋诗','song-poetry','','[]','菊花原上立，村落雨晴初。',48,'全唐诗/poet.song.3000.json','["菊花原上立，村落雨晴初。", "晚吹清羣物，秋光澹太虛。", "空看新鴈字，不得故人書。", "猶頼華亭鶴，林閒伴索居。"]'),
('2a5476ab-b5de-4bb9-b16d-3836e9af0906','新晴書事上知府宋諫議','魏野','宋','宋诗','song-poetry','','[]','美化何因見，民歌處處同。',48,'全唐诗/poet.song.3000.json','["美化何因見，民歌處處同。", "雨申諸縣足，獄奏半年空。", "郡閣煙光裏，人家霽色中。", "偶吟知淺拙，將獻愧明公。"]'),
('da2ff63b-48bd-4562-8b38-451b36aef600','贈岐賁推官','魏野','宋','宋诗','song-poetry','','[]','動靜不違書，如君始是儒。',48,'全唐诗/poet.song.3000.json','["動靜不違書，如君始是儒。", "婢閑猶畫卦，兒戲亦投壺。", "門冷僧長往，官清道更孤。", "吾君能大用，皇宋即唐虞。"]'),
('724b7e9b-4860-44c9-8edc-8c36a88a1079','閑居書事','魏野','宋','宋诗','song-poetry','','[]','無才動聖君，養拙住山村。',48,'全唐诗/poet.song.3000.json','["無才動聖君，養拙住山村。", "臨事知閑貴，澄心覺道尊。", "成家書滿屋，添口鶴生孫。", "仍喜多時雨，經春免灌園。"]'),
('1633b185-c43e-45ea-a8d7-93ee57884147','寄贈華山致仕韓見素','魏野','宋','宋诗','song-poetry','','[]','盡垂華髮戀金門，獨乞懸車未五旬。',256,'全唐诗/poet.song.3000.json','["盡垂華髮戀金門，獨乞懸車未五旬。", "清世一般爲隠逸，碧霄兩處應星辰。", "繡衣脫下寧妨貴，錦帳眠來不稱貧。", "瀟灑易添新道氣，光陰難改舊風神。", "老輕白傅方歸洛，亂鄙黄公始避秦。", "象簡豈同青竹杖，廌冠爭勝白綸巾。", "世間名繫昌朝客，物外銜稱太華人。", "醉指鼇頭爲別業，吟誇仙掌是比鄰。", "劍生塵土揩磨懶，書带煙嵐曬曝頻。", "石鼓曉聽殊待漏，玉潭時看異迷津。", "琴憐徽外聲彌澹，酒愛篘中味更醇。", "精細處方因療鶴，等閑開食爲迎賓。", "芝田女僕皆能採，蘭佩兒童亦解紉。", "丹訣有靈還似性，詩篇無病恰如身。", "要君計想嫌弘景，棄室翻應笑子真。", "預祝全家上昇日，願停絳節許相親。"]'),
('572e236d-4f26-4e2b-913b-b6c42abf3f1a','和呈寇相公見贈','魏野','宋','宋诗','song-poetry','','[]','深嚴相府絕纖埃，宴會尋常召不才。',64,'全唐诗/poet.song.3000.json','["深嚴相府絕纖埃，宴會尋常召不才。", "孫閤有歌凝翠黛，召棠無訟鎖青苔。", "鳳池即看三迴入，蝸舍曾蒙數度來。", "仍賜雅章慚繼和，朱門將獻又徘徊。"]'),
('e231c71b-2617-4893-b6c5-28a59888e6b5','謝呈寇相公召宴','魏野','宋','宋诗','song-poetry','','[]','兩度爲霖六鎮臨，春殘公暇宴棠陰。',64,'全唐诗/poet.song.3000.json','["兩度爲霖六鎮臨，春殘公暇宴棠陰。", "周瑜辯樂寧妨醉，裴度論兵不廢吟。", "五色詔書丹鳳降，十香御酒翠娥斟。", "野人每喜陪樽俎，三入唯愁阻訪尋。"]'),
('1b9aa0b3-232c-405e-bea2-a54b90d84e2e','上知府寇相公','魏野','宋','宋诗','song-poetry','','[]','文武稟全才，何人更可陪。',96,'全唐诗/poet.song.3000.json','["文武稟全才，何人更可陪。", "有官居鼎鼐，無宅起樓臺。", "聖主詩方和，親王狀始迴。", "鎮臨求二陝，調燮輟三台。", "鳳閣須重去，龍旌暫擁來。", "下車三度雨，上事數聲雷。", "未暇瞻珪璧，先蒙訪草萊。", "幾思趨相府，恐懼復徘徊。"]'),
('f00b9490-436f-435e-9d55-9d03a8e947be','寇相公生辰二首  其一','魏野','宋','宋诗','song-poetry','','[]','嶽瀆精英氣，來鍾積慶門。',48,'全唐诗/poet.song.3000.json','["嶽瀆精英氣，來鍾積慶門。", "何時生上相，明日是中元。", "仙藥寧無種，靈椿別有根。", "佇期三入後，一品見玄孫。"]'),
('1307b56c-a331-4df3-9c1f-b6a3a3c56680','寇相公生辰二首  其二','魏野','宋','宋诗','song-poetry','','[]','弈世英髦命世賢，懸弧時節早秋天。',64,'全唐诗/poet.song.3000.json','["弈世英髦命世賢，懸弧時節早秋天。", "蟾光望處將三五，鳳曆推來恰半千。", "功向清朝終突兀，壽同皇祚合連延。", "預愁來歲逢今日，不得中書獻此篇。"]'),
('d8f2028b-2660-4090-9ddb-958f3bad580c','謝知府寇相公降訪  其一','魏野','宋','宋诗','song-poetry','','[]','晝睡方濃向竹齋，柴門日午尚慵開。',32,'全唐诗/poet.song.3000.json','["晝睡方濃向竹齋，柴門日午尚慵開。", "驚迴一覺遊仙夢，村巷傳呼宰相來。"]'),
('aef05eaf-961a-4623-b332-383b8feb9c6c','謝知府寇相公降訪  其二','魏野','宋','宋诗','song-poetry','','[]','中書兩入寇尚書，出鎮雄藩半載餘。',32,'全唐诗/poet.song.3000.json','["中書兩入寇尚書，出鎮雄藩半載餘。", "棠樹陰中無訟聽，閑騎寶馬到茅廬。"]'),
('3a9973d1-9941-4aa1-a0b9-5e65d035d7de','寇相公生辰因有寄獻','魏野','宋','宋诗','song-poetry','','[]','宋朝元老更誰先，已詠功成二十年。',64,'全唐诗/poet.song.3000.json','["宋朝元老更誰先，已詠功成二十年。", "好去上天辭將相，歸來平地作神仙。", "坐看雲岫資閑興，卧聽霓裳引醉眠。", "多少年辰獻詩者，應無真禱似狂篇。"]'),
('711f8e21-a96d-4d8a-90cb-e8a637adbd23','和臧奎秋夜書懷','魏野','宋','宋诗','song-poetry','','[]','林中獨坐欲中宵，落葉紛紛觸壞袍。',64,'全唐诗/poet.song.3000.json','["林中獨坐欲中宵，落葉紛紛觸壞袍。", "月影漸移蛩韻急，露華初上鶴聲高。", "四時催老秋偏感，萬事縈心夜更勞。", "猶頼清風知我意，頻吹庭竹助蕭騷。"]'),
('30a05cbd-8673-40da-8bad-f79c3e7cf326','上知府袁刑部','魏野','宋','宋诗','song-poetry','','[]','星辰雖應碧虛中，富貴情疏道氣融。',64,'全唐诗/poet.song.3000.json','["星辰雖應碧虛中，富貴情疏道氣融。", "遶野雲煙陪淡薄，入衙山水學清通。", "申湖靜泛孤舟月，棠樹凉生一扇風。", "却有祖先難似處，獻詩民住樂郊東。"]'),
('05933a81-0f79-4d3e-82d7-bad4a81eb5a2','謝薛端公寄惠素紗','魏野','宋','宋诗','song-poetry','','[]','鶴色紗蒙烏府寄，裁衣不稱著林中。',32,'全唐诗/poet.song.3000.json','["鶴色紗蒙烏府寄，裁衣不稱著林中。", "水亭君有親題處，留待他時染碧籠。"]'),
('2e64b22d-6923-48bf-bc1d-4fee26483fcd','寄俞太中山人','魏野','宋','宋诗','song-poetry','','[]','太白空來數百年，貫之今稱隠其閒。',32,'全唐诗/poet.song.3000.json','["太白空來數百年，貫之今稱隠其閒。", "靜應笑我藏名拙，惹得人多到竹關。"]'),
('de450e1a-0516-4b38-90ff-221251e5f94c','上知府趙侍郎二首  其一','魏野','宋','宋诗','song-poetry','','[]','往哲英靈在，重生出鎮初。',168,'全唐诗/poet.song.3000.json','["往哲英靈在，重生出鎮初。", "傅巖存舊跡，棠樹認前居。", "美化民歌實，流言帝覺虛。", "暫來淹外郡，再入老中書。", "善欲皆昇舉，奸思盡剪除。", "登科嗤負鼎，避事鄙懸車。", "權助天生殺，才隨道卷舒。", "百官憑整肅，萬物待吹噓。", "接士殊龍板，尋僧却隼旟。", "嘉謀常啟沃，諫草旋焚如。", "赤子方安枕，黄巾亦荷鋤。", "囚無經宿禁，農有數年儲。", "山勢朝衙署，河聲貫里閭。", "野人携此詠，將獻幾躊躇。"]'),
('5bbb5176-0f74-4ff0-aec9-3621d3908a3f','上知府趙侍郎二首  其二','魏野','宋','宋诗','song-poetry','','[]','坐棠虛廟堂，俗亦似身康。',48,'全唐诗/poet.song.3000.json','["坐棠虛廟堂，俗亦似身康。", "藥按仙方鍊，茶開御印嘗。", "吏因呈案懼，民爲立碑忙。", "公退無餘事，逍遥只道裝。"]'),
('c03b82ff-9861-4e23-8ef3-510d5a0789f4','冬日書事','魏野','宋','宋诗','song-poetry','','[]','一月天不暖，前村到豈能。',48,'全唐诗/poet.song.3000.json','["一月天不暖，前村到豈能。", "閑聞啄木鳥，疑是打門僧。", "松色濃經雪，溪聲澀带冰。", "吟餘還默坐，稚子問慵應。"]'),
('8316f85f-2357-48c1-8c23-ab6fdb439858','盆池萍','魏野','宋','宋诗','song-poetry','','[]','乍認庭前青蘚合，深疑鑑裏翠鈿稠。',32,'全唐诗/poet.song.3000.json','["乍認庭前青蘚合，深疑鑑裏翠鈿稠。", "莫嫌生處波瀾小，免得漂然逐衆流。"]'),
('0c410780-faec-4727-9b79-e3fb2102d706','留題敷水李先生隠居','魏野','宋','宋诗','song-poetry','','[]','棠樹陰中來得得，蓮花峰下去遲遲。',32,'全唐诗/poet.song.3000.json','["棠樹陰中來得得，蓮花峰下去遲遲。", "好將門外巖磨取，爲刻西巡御賜詩。"]'),
('f42dd139-2703-4a2d-bffa-da55c7493400','送趙侍郎移鎮長安','魏野','宋','宋诗','song-poetry','','[]','千騎蕭蕭曉發時，雨先一夜洒長岐。',64,'全唐诗/poet.song.3000.json','["千騎蕭蕭曉發時，雨先一夜洒長岐。", "盡知暫去臨鶉野，即看重來向鳳池。", "函谷亂花明劍珮，灞橋垂柳拂旌旗。", "不同調鼎民皆樂，秦甸歡呼陝服悲。"]'),
('f6fedb98-d5f8-4b3d-9819-dbca6c359947','送王專推官赴任河中','魏野','宋','宋诗','song-poetry','','[]','聲華籍籍祖風存，況佐風流謝使君。',64,'全唐诗/poet.song.3000.json','["聲華籍籍祖風存，況佐風流謝使君。", "健筆想無詩債負，漏巵應少酒知聞。", "趣裝劍懶從人借，謁廟香非爲己焚。", "好對前山思節儉，夷齊餓死舜耕耘。"]'),
('5593cd4b-3d2d-4ed8-a1bd-9878b1fe1ad6','酬薛田推官見贈','魏野','宋','宋诗','song-poetry','','[]','紅蓮客惠碧雲篇，未及他山買石鎸。',32,'全唐诗/poet.song.3000.json','["紅蓮客惠碧雲篇，未及他山買石鎸。", "且選眼前麄竹上，和煙大刻兩三聯。"]'),
('79725c6f-2a40-43b6-a725-d49e6554797d','别長安','司馬光','宋','宋诗','song-poetry','','[]','暫來還復去，夢裏到長安。',24,'全唐诗/poet.song.30000.json','["暫來還復去，夢裏到長安。", "可惜終南色，臨行子細看。"]'),
('024ff31f-8ba9-4eba-a152-895455ef4364','初到洛中書懷','司馬光','宋','宋诗','song-poetry','','[]','三十餘年西復東，勞生薄宦等飛蓬。',64,'全唐诗/poet.song.30000.json','["三十餘年西復東，勞生薄宦等飛蓬。", "所存舊業惟清白，不負明君有樸忠。", "早避喧煩真得策，未逢危辱好收功。", "太平觸處農桑滿，贏取閭閻鶴髪翁。"]'),
('2f2c5634-c623-41ee-b8f6-ea7e3433db49','和景仁題崇福宮  其一','司馬光','宋','宋诗','song-poetry','','[]','歷歷山頭雪，冷冷松下風。',24,'全唐诗/poet.song.30000.json','["歷歷山頭雪，冷冷松下風。", "樽中亦有酒，恨不與君同。"]'),
('1d8dd0f5-75c0-4afd-a428-16b464519a51','和景仁題崇福宮  其二','司馬光','宋','宋诗','song-poetry','','[]','不獨山頭白，人頭亦垂素。',24,'全唐诗/poet.song.30000.json','["不獨山頭白，人頭亦垂素。", "積雪有時消，青山色如故。"]'),
('95a55535-799f-4a9a-8398-53b203b95350','寄題傅欽之濟源别業','司馬光','宋','宋诗','song-poetry','','[]','縣郭遙相望，脩篁百畝餘。',48,'全唐诗/poet.song.30000.json','["縣郭遙相望，脩篁百畝餘。", "林間清濟水，門外太行車。", "道勝隨宜足，身閑與世疏。", "何時容命駕，采蕨釣肥魚。"]'),
('ff76124c-5ef5-498d-82c8-13f384c12a3b','遊李衛公平泉莊','司馬光','宋','宋诗','song-poetry','','[]','相國已何在，空山餘故林。',48,'全唐诗/poet.song.30000.json','["相國已何在，空山餘故林。", "曏時堪炙手，今日但傷心。", "陵谷尚未改，門闌不可尋。", "誰知荆棘地，鶴蓋舊成陰。"]'),
('e480d932-c43f-42a2-841c-f7b1d409c42e','贈河中通判朱郎中','司馬光','宋','宋诗','song-poetry','','[]','陟屺今將老，扶牀昔未行。',48,'全唐诗/poet.song.30000.json','["陟屺今將老，扶牀昔未行。", "旨甘無所展，朱紫不爲榮。", "里巷傳呼入，比鄰失涕驚。", "方知貫金石，何以易精誠。"]'),
('c678934c-02e6-4521-ac46-2d68c86d0b99','寄題李水部滻水别業','司馬光','宋','宋诗','song-poetry','','[]','茅茨臨素滻，沃野带長林。',48,'全唐诗/poet.song.30000.json','["茅茨臨素滻，沃野带長林。", "日永一堂静，草生三逕深。", "消憂何用酒，爲樂不須琴。", "擾擾市朝客，無人知此心。"]'),
('359ddc00-9a1f-45a7-90ef-a2c19a5b28cb','泉水詩送吳都官分司歸和州','司馬光','宋','宋诗','song-poetry','','[]','泉水出幽谷，原流本自清。',48,'全唐诗/poet.song.30000.json','["泉水出幽谷，原流本自清。", "縈回徧中國，浩蕩入東瀛。", "峽口春雷怒，潭心曉鑑平。", "悠悠隨所值，行止兩無情。"]'),
('bf674e1c-ef09-4ee8-9d6e-1f8f43afab38','遊瀍上劉氏園','司馬光','宋','宋诗','song-poetry','','[]','日暖孤臺迥，露濃幽逕微。',48,'全唐诗/poet.song.30000.json','["日暖孤臺迥，露濃幽逕微。", "茅齋舉白飲，沙溆踏青歸。", "照水清滿眼，穿林香濕衣。", "莫言春尚淺，已有杏花飛。"]'),
('7f3fe675-f388-4b47-8d48-236eccb1110a','題致仕李太傅園亭','司馬光','宋','宋诗','song-poetry','','[]','漢家飛將種，氣概耿清秋。',48,'全唐诗/poet.song.30000.json','["漢家飛將種，氣概耿清秋。", "解去金貂貴，來從洛社遊。", "清商擁高宴，華館带長流。", "可笑班超老，崎嶇萬里侯。"]'),
('a91caf38-6d41-467f-8dba-15b2aea803d6','早行','司馬光','宋','宋诗','song-poetry','','[]','寒犬吠柴門，荒雞鳴遠村。',48,'全唐诗/poet.song.30000.json','["寒犬吠柴門，荒雞鳴遠村。", "河聲空自急，月影不曾渾。", "木末星猶白，榛中露已繁。", "客心獨惆悵，四顧與誰言。"]'),
('42d4220c-96c4-4bac-ab05-46125b662810','送羅郎中管勾玉局觀','司馬光','宋','宋诗','song-poetry','','[]','官名爲玉局，已與俗塵疏。',48,'全唐诗/poet.song.30000.json','["官名爲玉局，已與俗塵疏。", "鐘出寒松迥，香疑古殿虚。", "鄉閭非甚遠，俸祿豈無餘。", "誰道神仙樂，神仙恐不如。"]'),
('99ca811b-e54c-48f5-87b0-599c429e9729','酬終南閻諫議見寄','司馬光','宋','宋诗','song-poetry','','[]','齒衰心力耗，揣分乞西臺。',48,'全唐诗/poet.song.30000.json','["齒衰心力耗，揣分乞西臺。", "微祿供多病，閑官養不才。", "弊廬容嘯傲，清洛伴歸來。", "故友猶相念，寒光生死灰。"]'),
('7807514d-3b18-4d48-9da6-d589f72d4cf8','寄成都吴龍圖同年','司馬光','宋','宋诗','song-poetry','','[]','照席燭花暖，隨車劍騎寒。',48,'全唐诗/poet.song.30000.json','["照席燭花暖，隨車劍騎寒。", "江山資秀句，風月助清歡。", "政簡坤維静，仁深井絡安。", "行歌與獨酌，豈得並閑官。"]'),
('f0c0f06d-80f8-4d90-bff1-3ef03b821563','花庵獨坐','司馬光','宋','宋诗','song-poetry','','[]','荒園才一畝，意足已爲多。',48,'全唐诗/poet.song.30000.json','["荒園才一畝，意足已爲多。", "雖不居丘壑，常如隱薜蘿。", "忘機林鳥下，極目塞鴻過。", "爲問市朝客，紅塵深幾何。"]'),
('abc26fd3-770f-48e6-9ad8-cac5c683ec82','秋夜','司馬光','宋','宋诗','song-poetry','','[]','浮雲一消散，星斗粲長天。',48,'全唐诗/poet.song.30000.json','["浮雲一消散，星斗粲長天。", "浩露灑翠柏，清香生白蓮。", "體涼猶衣葛，耳静已無蟬。", "坐久羣動息，秋空唯寂然。"]'),
('1b3cebce-8bd5-491f-b22a-bbe59b0b09da','平日遊園常策筇杖秋来發篋復出貂褥二物皆景仁所貺覩物思人斐然成詩','司馬光','宋','宋诗','song-poetry','','[]','筇杖攜已久，貂褥展猶新。',48,'全唐诗/poet.song.30000.json','["筇杖攜已久，貂褥展猶新。", "漸染岷山雪，拂除京國塵。", "危扶醉歸路，穩稱病來身。", "賴此齋中物，時如見故人。"]'),
('90a044d1-b810-4953-b683-cdb4f15d8ead','雲','司馬光','宋','宋诗','song-poetry','','[]','晴空碧於水，那得片雲飛。',48,'全唐诗/poet.song.30000.json','["晴空碧於水，那得片雲飛。", "映日成丹凰，隨風變白衣。", "去來皆絕迹，隱顯兩忘機。", "天理誰能測，終然何所歸。"]'),
('530c0d98-d63d-4330-99f4-6ce1ed9f07be','閑来','司馬光','宋','宋诗','song-poetry','','[]','閑來觀萬物，在處可逍遙。',48,'全唐诗/poet.song.30000.json','["閑來觀萬物，在處可逍遙。", "魚爲貪鈎得，蛾因赴火焦。", "碧梧饑鸑鷟，白粒飽鷦鷯。", "带索誰家子，行歌復採樵。"]'),
('44da813b-b229-4495-8f30-57a5b56d70cb','贈邵堯夫','司馬光','宋','宋诗','song-poetry','','[]','家雖在城闕，蕭瑟似荒郊。',48,'全唐诗/poet.song.30000.json','["家雖在城闕，蕭瑟似荒郊。", "遠去名利窟，自稱安樂巢。", "雲歸白石洞，鶴立碧松梢。", "得喪非吾事，何須更解嘲。"]'),
('29f18f2f-bc1e-4076-996f-029b2e504d75','花庵多牽牛清晨始開日出已瘁花雖甚美而不堪留賞','司馬光','宋','宋诗','song-poetry','','[]','望遠雲凝岫，粧餘黛散鈿。',48,'全唐诗/poet.song.30000.json','["望遠雲凝岫，粧餘黛散鈿。", "縹囊承曉露，翠蓋拂秋煙。", "響慕非葵比，彫零在槿先。", "才供少頃玩，空廢日高眠。"]'),
('ce292863-be50-4aaa-aebc-79ed5a6e82ea','送劉仲通赴京師','司馬光','宋','宋诗','song-poetry','','[]','聖朝方考牧，蕃育寄才能。',48,'全唐诗/poet.song.30000.json','["聖朝方考牧，蕃育寄才能。", "屢别良可嘆，閑遊不復曾。", "行塵遵洛汭，朝騎對觚稜。", "瀍上秋臺迥，歸来正好登。"]'),
('58f0baaa-e62e-451d-b0eb-a931b1e39e8f','送稻醴與子才','司馬光','宋','宋诗','song-poetry','','[]','昔賢尊道誼，置醴待嘉賓。',48,'全唐诗/poet.song.30000.json','["昔賢尊道誼，置醴待嘉賓。", "今我樂閑放，提壺餉故人。", "螘浮杯面白，味撇甕頭醇。", "何以助高興，籬邊菊蘂新。"]'),
('31c246f6-2ebf-4e19-903d-b4c644b8462a','花庵二首  其一','司馬光','宋','宋诗','song-poetry','','[]','誰謂花庵小，纔容三兩人。',24,'全唐诗/poet.song.30000.json','["誰謂花庵小，纔容三兩人。", "君看賓席上，經月有凝塵。"]'),
('f3ee2d59-3c78-43a4-8247-f16ba9525a9b','花庵二首  其二','司馬光','宋','宋诗','song-poetry','','[]','誰謂花庵陋，徒爲見者嗤。',24,'全唐诗/poet.song.30000.json','["誰謂花庵陋，徒爲見者嗤。", "此中勝廣廈，人自不能知。"]'),
('157bad13-6ad7-4154-b35f-0afc69a6ffcc','和楊卿中秋月','司馬光','宋','宋诗','song-poetry','','[]','秋氣平分夜，沈陰乍散天。',48,'全唐诗/poet.song.30000.json','["秋氣平分夜，沈陰乍散天。", "窺林初淡薄，照席忽孤圓。", "泠入詩毫健，光浮醉弁偏。", "嘉賓勿輕去，桂影正姢姢。"]'),
('0664fe56-649d-4181-8aef-873187bc674d','樂','司馬光','宋','宋诗','song-poetry','','[]','吾心自有樂，世俗豈能知。',48,'全唐诗/poet.song.30000.json','["吾心自有樂，世俗豈能知。", "不及老萊子，多於榮啓期。", "緼袍寛稱體，脫粟飽隨宜。", "乘興輙獨往，攜筇任所之。"]'),
('be337607-3a98-48df-8e8c-b38abba7b049','和邵堯夫秋霽登石閣','司馬光','宋','宋诗','song-poetry','','[]','飛簷危檻出林端，王屋嵩丘咫尺間。',64,'全唐诗/poet.song.30000.json','["飛簷危檻出林端，王屋嵩丘咫尺間。", "獨愛高明遊佛閣，豈知憂喜滿塵寰。", "目窮莽蒼纖毫盡，身得逍遙萬象閑。", "暇日登臨無厭數，悲風殘葉已珊珊。"]'),
('1aa5a25b-5946-440d-9f74-97c339e8b669','和河陽王宣徽九日平嵩閣宴集','司馬光','宋','宋诗','song-poetry','','[]','九日英僚集，千秋勝賞同。',96,'全唐诗/poet.song.30000.json','["九日英僚集，千秋勝賞同。", "飛橋貫河渚，危閣壓霜風。", "金散黄花泛，雷驚疊鼓通。", "百峰高鳥外，萬里寸眸中。", "檻底臨丹葉，杯中倒碧嵩。", "來雲低拂座，去鴈遠沈空。", "吹帽陪遊阻，搖旌結想叢。", "風流免堙滅，鄒湛倚羊公。"]'),
('379216c6-5711-4774-9654-7a8a885b6624','和任開叔觀福嚴院舊題名','司馬光','宋','宋诗','song-poetry','','[]','墨蹤塵淡鬢華新，猶喜重來值故人。',32,'全唐诗/poet.song.30000.json','["墨蹤塵淡鬢華新，猶喜重來值故人。", "二十二年如轉目，洛陽不改舊時春。"]'),
('96841a37-e4cf-4d0c-8fd6-28ebbbff7c53','柏梯寺','司馬光','宋','宋诗','song-poetry','','[]','鑿石開蹊峻，登崖置閣危。',48,'全唐诗/poet.song.30000.json','["鑿石開蹊峻，登崖置閣危。", "笑談空谷應，步武白雲隨。", "衆壑如翻浪，鄰州若布棋。", "何當遂棲隱，身世兩相遺。"]'),
('1fb4a0cd-fe8a-4651-bbb8-52a3384a7f80','重過華下','司馬光','宋','宋诗','song-poetry','','[]','昔辭蓮幕去，三十四炎凉。',48,'全唐诗/poet.song.30000.json','["昔辭蓮幕去，三十四炎凉。", "舊物三峰雪，新悲一鑷霜。", "雲低秦野闊，木落渭川長。", "欲問當時事，無人獨嘆傷。"]'),
('b46903ee-84a0-4c32-88e7-909e132441a9','和李君錫惠書及詩勉以早歸','司馬光','宋','宋诗','song-poetry','','[]','書意勤渠詩意新，清如白雪暖如春。',32,'全唐诗/poet.song.30000.json','["書意勤渠詩意新，清如白雪暖如春。", "西遊不盡谿山樂，策馬歸來就故人。"]'),
('598f5991-aea2-43e3-a9c1-38cead108e15','和君錫雪後招探春  其一','司馬光','宋','宋诗','song-poetry','','[]','莫嫌微雪壓梅芽，已有歸鴻泊浦沙。',32,'全唐诗/poet.song.30000.json','["莫嫌微雪壓梅芽，已有歸鴻泊浦沙。", "天上詔來難久駐，直須早看洛陽花。"]'),
('20613dcd-9378-44ed-b46d-db30541141cf','和君錫雪後招探春  其二','司馬光','宋','宋诗','song-poetry','','[]','繁霙回夜色，凌亂落春雲。',48,'全唐诗/poet.song.30000.json','["繁霙回夜色，凌亂落春雲。", "虛幌寒相襲，華堂静不聞。", "玉卮深可敵，銀燭近微分。", "誰念牛衣客，窮經白髪紛。"]'),
('5d0c41ae-f072-4816-842b-c6d19c49ba96','送祖擇之','司馬光','宋','宋诗','song-poetry','','[]','人生榮與辱，百變似浮雲。',48,'全唐诗/poet.song.30000.json','["人生榮與辱，百變似浮雲。", "自有窮通定，徒勞得喪分。", "消愁唯有酒，娛意莫如文。", "方寸常蕭散，其餘何足云。"]'),
('115d5a03-105a-4dc7-8eb1-556bc58a2eae','和宋子才致仕後歳旦見贈','司馬光','宋','宋诗','song-poetry','','[]','閑官逢獻歳，拜揖亦紛然。',48,'全唐诗/poet.song.30000.json','["閑官逢獻歳，拜揖亦紛然。", "須信家居日，方爲已有年。", "劬勞中外徧，名迹始終全。", "伯玉空搔首，蹉跎愧在前。"]'),
('a7a905b1-fdf5-4ee4-9440-787f09b48293','上元書懷','司馬光','宋','宋诗','song-poetry','','[]','老去春無味，年年覺病添。',48,'全唐诗/poet.song.30000.json','["老去春無味，年年覺病添。", "酒因脾積斷，燈爲目阿嫌。", "勢位非其好，紛華已久厭。", "唯餘讀書樂，暖日坐前簷。"]'),
('4ada41f7-845c-4d54-8bdc-4e5175607dca','喜才元過洛小詩招飲','司馬光','宋','宋诗','song-poetry','','[]','素髪各垂領，舊交相見稀。',48,'全唐诗/poet.song.30000.json','["素髪各垂領，舊交相見稀。", "不唯春物好，况是錦衣歸。", "洛社凍醪熟，伊魴絲鱠肥。", "南軒已灑掃，命駕不須違。"]'),
('51d8f4a0-6421-4e26-8527-cdb74bef187e','仲庶同年兄自成都移長安以詩寄賀','司馬光','宋','宋诗','song-poetry','','[]','蠶叢龜印解，鶉野隼旟新。',48,'全唐诗/poet.song.30000.json','["蠶叢龜印解，鶉野隼旟新。", "借問錦江樂，何如興慶春。", "驪歌遮去轍，竹馬望行塵。", "惠政如膏雨，遙知彼此均。"]'),
('f86f7631-1025-4a62-bb1b-5a4eab315979','西臺詩二十四韻','司馬光','宋','宋诗','song-poetry','','[]','翰苑昔陪侍，天光辱顧瞻。',288,'全唐诗/poet.song.30000.json','["翰苑昔陪侍，天光辱顧瞻。", "寵雖承渙汗，功不立毫纖。", "山鹿纓頻頓，鉛刀礪不銛。", "拭花眸子缺，撚雪頷髭添。", "跼影慚尸素，胡顔處禁嚴。", "辭盈雖免戾，取少詎因廉。", "定鼎分都異，張官執法兼。", "剡章愚懇盡，出綍茂恩霑。", "原憲非無粟，胡威尚有縑。", "求田近瀍洛，買宅混閭閻。", "地僻宜花卉，兒勤付米鹽。", "倦遊良足悔，居吉不煩占。", "裘葛膚無見，囷倉飯屬饜。", "僧居閑可借，野步静無嫌。", "行樂筇枝瘦，延賓稻醴甜。", "麥田泥試屐，桑蔭帽低簷。", "愛竹忙猶種，貪書老未厭。", "松煙溪石潤，檀燼博山尖。", "牋啓來慵拆，衣冠脫怕拈。", "紫毫斜倚架，黄卷密垂籖。", "涸轍猶蒙潤，寒灰免附炎。", "所憂資秩滿，但願歳時淹。", "自是散無用，非爲智養恬。", "聖朝英彦富，幸許一夫潛。"]'),
('18fb6ea7-b491-4882-bac1-9d79f11cc456','和邵堯夫年老逢春','司馬光','宋','宋诗','song-poetry','','[]','年老逢春春莫咍，朱顔不肯似春回。',64,'全唐诗/poet.song.30000.json','["年老逢春春莫咍，朱顔不肯似春回。", "酒因多病無心醉，花不解愁隨意開。", "荒徑倦遊從碧草，空庭慵掃自蒼苔。", "相逢談笑猶能在，坐待牽車陌上來。"]'),
('cbf6de8b-23c2-4902-8ee1-1bbf66c22ec6','和范景仁謝寄西遊行記  其一','司馬光','宋','宋诗','song-poetry','','[]','洛川秦野鬰相望，風物山河舊帝鄉。',64,'全唐诗/poet.song.30000.json','["洛川秦野鬰相望，風物山河舊帝鄉。", "澗底逢人問樵徑，松間繫馬宿僧房。", "恨無同好攜三雅，共講前聞醉百場。", "歷徧勝遊翻悵望，日邊回首遠煙蒼。"]'),
('06dcd2bb-f4e1-4e98-8508-c13171110689','和范景仁謝寄西遊行記  其二','司馬光','宋','宋诗','song-poetry','','[]','八水三川路渺茫，翠微深處白雲鄉。',64,'全唐诗/poet.song.30000.json','["八水三川路渺茫，翠微深處白雲鄉。", "目𥉍懶拭如松液，領髪頻抓似栗房。", "林壑不嫌無用物，形骸難入少年場。", "緣苔躡蔓知多少，千里歸來屐齒蒼。"]'),
('34a7a35d-5abb-4d88-8e75-228e98f517a1','獨步至洛濱  其一','司馬光','宋','宋诗','song-poetry','','[]','拜表歸來抵寺居，解鞍縱馬罷傳呼。',32,'全唐诗/poet.song.30000.json','["拜表歸來抵寺居，解鞍縱馬罷傳呼。", "紫衣金带盡脫去，便是林間一野夫。"]'),
('ba70340f-54f9-4421-b10c-260556bdaf63','獨步至洛濱  其二','司馬光','宋','宋诗','song-poetry','','[]','草軟波清沙徑微，手攜筇竹著深衣。',32,'全唐诗/poet.song.30000.json','["草軟波清沙徑微，手攜筇竹著深衣。", "白鷗不信忘機久，見我猶穿岸柳飛。"]'),
('10acc8bc-37d7-4729-8834-730d8823565a','送酒與邵堯夫','司馬光','宋','宋诗','song-poetry','','[]','紅櫻零落杏花開，春物相催次第來。',32,'全唐诗/poet.song.30000.json','["紅櫻零落杏花開，春物相催次第來。", "莫作林間獨醒客，任從花笑玉山頽。"]'),
('ebc73d70-7f8d-4007-a58b-c3c2958f59f3','再和邵堯夫年老逢春','司馬光','宋','宋诗','song-poetry','','[]','年老逢春猶解狂，行歌南陌上東岡。',64,'全唐诗/poet.song.30000.json','["年老逢春猶解狂，行歌南陌上東岡。", "晴雲高鳥各自得，白日遊絲相與長。", "草色無情盡眼綠，花林多思襲人香。", "吾儕幸免簪裾累，痛飲閑吟樂未央。"]'),
('ef78ad24-9541-47ec-9206-8d26eb33e269','又和來韻','司馬光','宋','宋诗','song-poetry','','[]','年老逢春無用驚，對花弄筆眼猶明。',64,'全唐诗/poet.song.30000.json','["年老逢春無用驚，對花弄筆眼猶明。", "不嫌貧舍舊來燕，喚起醉眠何處鸎。", "一僕相隨幅巾出，羣童聚看小車行。", "人間萬事都損去，莫遣胸中氣不平。"]'),
('87d6c6a8-9a88-425c-90b5-a959ffda7afe','邵堯夫許來石閣久待不至','司馬光','宋','宋诗','song-poetry','','[]','淡日濃雲合復開，碧嵩清洛遠縈迴。',32,'全唐诗/poet.song.30000.json','["淡日濃雲合復開，碧嵩清洛遠縈迴。", "林間高閣望己久，花外小車猶未來。"]'),
('9d2c50ed-cdfd-4796-8145-4bdf8243f71f','石閣春望','司馬光','宋','宋诗','song-poetry','','[]','極目千里外，川原繡畫新。',24,'全唐诗/poet.song.30000.json','["極目千里外，川原繡畫新。", "方知平地上，見不盡青春。"]'),
('d0545977-d227-4955-bdba-37e93dfbc376','和邵堯夫安樂窩中職事吟','司馬光','宋','宋诗','song-poetry','','[]','靈臺無事日休休，安樂由來不外求。',64,'全唐诗/poet.song.30000.json','["靈臺無事日休休，安樂由來不外求。", "細雨寒風宜獨坐，暖天佳景即閑遊。", "松篁亦足開青眼，桃李何妨插白頭。", "我以著書爲職業，爲君偷暇上高樓。"]'),
('994cd2c0-ba20-4afa-a2f2-a5aa1b579714','和景仁聞蟬','司馬光','宋','宋诗','song-poetry','','[]','春林滿巖綠，誰信已鳴蟬。',48,'全唐诗/poet.song.30000.json','["春林滿巖綠，誰信已鳴蟬。", "葉上正多露，山中别有天。", "心閑寧感物，道合况忘年。", "坐聽生秋思，何須膝上絃。"]'),
('ce94e4eb-da6e-4251-b348-fd9249a37f19','和范景仁宿憩鶴寺','司馬光','宋','宋诗','song-poetry','','[]','回廊複閣勢縈紆，四嶺中涵一氣虛。',32,'全唐诗/poet.song.30000.json','["回廊複閣勢縈紆，四嶺中涵一氣虛。", "最愛欣欣向榮木，毎來相見不相疏。"]'),
('baef568f-a97a-4b0b-8631-79b9e4be8410','遊噴玉潭  其一','司馬光','宋','宋诗','song-poetry','','[]','驚風動地起，遊客望山行。',24,'全唐诗/poet.song.30000.json','["驚風動地起，遊客望山行。", "若待佳辰去，應無好事名。"]'),
('2d1a4c25-52c2-48b3-a461-dafe2d55b708','遊噴玉潭  其二','司馬光','宋','宋诗','song-poetry','','[]','萬木吼穹谷，駑駘屹不前。',24,'全唐诗/poet.song.30000.json','["萬木吼穹谷，駑駘屹不前。", "猶勝望塵客，佇立九衢邊。"]'),
('539d792b-466e-45f9-9469-feb5d9762f06','和景仁噴玉潭','司馬光','宋','宋诗','song-poetry','','[]','昨朝景氣如暑天，僮僕流汗衣裘單。',112,'全唐诗/poet.song.30000.json','["昨朝景氣如暑天，僮僕流汗衣裘單。", "安知向晚暴風作，一變陽春成大寒。", "此時結友尋名山，伶俜徒步水石間。", "棘刺罥衣行路難，枯藤壽柏同攀援。", "驚沙擊眼百箭攢，時得閉爍窺林巒。", "景仁年長力更孱，牽衣執手幸不顛。", "仍聞旁谷有伏虎，賴得與君俱早還。"]'),
('b3e769d5-3c56-42dc-8b70-266a5b70e775','遊山呈景仁','司馬光','宋','宋诗','song-poetry','','[]','我祿多龔舍，君年少孔戣。',48,'全唐诗/poet.song.30000.json','["我祿多龔舍，君年少孔戣。", "道心閑始見，世路老方知。", "山水不相厭，風光難豫期。", "嬉遊不可緩，花卉即離披。"]'),
('167b87c2-048c-47af-a178-cb9543ca6c16','和景仁遊壽安','司馬光','宋','宋诗','song-poetry','','[]','宜陽城下作遊人，都爲衣冠不繫身。',32,'全唐诗/poet.song.30000.json','["宜陽城下作遊人，都爲衣冠不繫身。", "衆竅怒號成地籟，也勝終日在紅塵。"]'),
('0ef2ebe0-bb93-4efd-98ad-26631b396951','噴玉潭','司馬光','宋','宋诗','song-poetry','','[]','千尺崖頭一派清，古今不絕墜峥嶸。',32,'全唐诗/poet.song.30000.json','["千尺崖頭一派清，古今不絕墜峥嶸。", "長風卷起散巖壑，此日方知噴玉名。"]'),
('d46eab6a-2bae-4ef7-8115-4f79a396985f','疊石溪  其一','司馬光','宋','宋诗','song-poetry','','[]','道傍行采藥，石底卧題名。',24,'全唐诗/poet.song.30000.json','["道傍行采藥，石底卧題名。", "野老相迎拜，谿童乍見驚。"]'),
('d42dc01c-446c-42ad-8df9-bb022c0f5c3f','疊石溪  其二','司馬光','宋','宋诗','song-poetry','','[]','山鳥勸人飲，山蟬笑我狂。',24,'全唐诗/poet.song.30000.json','["山鳥勸人飲，山蟬笑我狂。", "歸時興未盡，不得看斜陽。"]'),
('fd4045bb-1580-4909-82ce-798c7794e8a2','和景仁疊石溪','司馬光','宋','宋诗','song-poetry','','[]','溪邊有村落，未始識紛華。',168,'全唐诗/poet.song.30000.json','["溪邊有村落，未始識紛華。", "去縣只數里，居民踰百家。", "山腰荒徑轉，谷口翠微遮。", "老木紛無際，重巒浩莫涯。", "力窮纔到頂，勢盡復成窪。", "不定雲煙色，難名藥草芽。", "泥鈞羅比屋，澗石載連車。", "宛有淳風在，誰云太古遐。", "梁隨木性曲，簷逐地形斜。", "榛路牛呼犢，叢祠雀噪蛇。", "倚崖松偃蓋，落石浪翻花。", "安用遊青嶠，何須躡紫霞。", "好將詩筆寫，還入帝城誇。", "已買漁樵舍，毋令後約差。"]'),
('02953196-7c99-480a-ab08-0437d69f4667','應天院朝拜回呈景仁','司馬光','宋','宋诗','song-poetry','','[]','鷄鳴上馬過河橋，何異東都赴早朝。',32,'全唐诗/poet.song.30000.json','["鷄鳴上馬過河橋，何異東都赴早朝。", "紅日已高猶熟寢，比君殊未得逍遙。"]'),
('785b2cba-f512-4fbe-8ca8-9f0643651a3a','和景仁卜居許下','司馬光','宋','宋诗','song-poetry','','[]','壯齒相知約歳寒，索居今日鬢俱斑。',64,'全唐诗/poet.song.30000.json','["壯齒相知約歳寒，索居今日鬢俱斑。", "拂衣已解虞卿印，築室何須謝傅山。", "許下田園雖有素，洛中花卉足供閑。", "他年决意歸何處，便見交情厚薄間。"]'),
('659c8824-6046-4293-ac32-3c086c9b624e','喜雨三首呈景仁侍郎兼獻大尹宣徽  其一','司馬光','宋','宋诗','song-poetry','','[]','累日增煩暑，通宵結薄陰。',48,'全唐诗/poet.song.30000.json','["累日增煩暑，通宵結薄陰。", "蒼茫變風色，散漫作春霖。", "野店垂楊重，僧房綠篠深。", "疏慵尤得趣，閉戶擁重衾。"]'),
('1e635a0f-30ee-47d0-b141-b7d05f07f0d2','喜雨三首呈景仁侍郎兼獻大尹宣徽  其二','司馬光','宋','宋诗','song-poetry','','[]','漠漠春雲合，爞爞旱氣收。',48,'全唐诗/poet.song.30000.json','["漠漠春雲合，爞爞旱氣收。", "人心方有望，時雨不須求。", "豈獨老農喜，仍令惡客留。", "洛城花未謝，作意更同遊。"]'),
('3fce68e9-7392-4a31-96fd-b97f67c0f9e8','喜雨三首呈景仁侍郎兼獻大尹宣徽  其三','司馬光','宋','宋诗','song-poetry','','[]','麥田正塵坌，桑徑忽滂沱。',48,'全唐诗/poet.song.30000.json','["麥田正塵坌，桑徑忽滂沱。", "比屋起相吿，荷鋤行且歌。", "園林半扃鎻，車馬絕經過。", "大尹愛民物，何妨喜更多。"]'),
('1d10e298-1131-43a1-87ad-0fc4e6ad45fe','亨杞下第作詩示之','司馬光','宋','宋诗','song-poetry','','[]','清白君家舊，文章時態新。',72,'全唐诗/poet.song.30000.json','["清白君家舊，文章時態新。", "何妨偶蹉跌，未必遂沈淪。", "莫歎科名晚，惟憂道誼貧。", "進修專在已，得失盡由人。", "孝友亦爲政，簞瓢足養親。", "那將少年淚，容易輙傷春。"]'),
('b1b2a2e4-715b-4e47-958c-5df016912a90','景仁思歸雨未克行以詩留之','司馬光','宋','宋诗','song-poetry','','[]','嘉客念歸程，泥深未可行。',24,'全唐诗/poet.song.30000.json','["嘉客念歸程，泥深未可行。", "今朝陰又重，春雨亦多情。"]'),
('ff18bfad-a4d2-4638-b5c8-4f653fdeaa0b','送景仁至丁正臣園寄主人','司馬光','宋','宋诗','song-poetry','','[]','客到暫開扃，春蕪生滿庭。',24,'全唐诗/poet.song.30000.json','["客到暫開扃，春蕪生滿庭。", "主人殊不顧，修竹爲誰青。"]'),
('6003b453-e268-406f-995f-38d5350c1ea5','和君貺老君廟姚黄牡丹','司馬光','宋','宋诗','song-poetry','','[]','芳菲觸目已蕭然，獨著金衣奉老仙。',32,'全唐诗/poet.song.30000.json','["芳菲觸目已蕭然，獨著金衣奉老仙。", "若占上春先秀發，千花萬卉不成妍。"]'),
('f209e49d-b073-4237-9f94-a636027bd417','又和董氏東園檜屏石牀','司馬光','宋','宋诗','song-poetry','','[]','密葉蕭森翠幕紆，暫來猶恨不長居。',32,'全唐诗/poet.song.30000.json','["密葉蕭森翠幕紆，暫來猶恨不長居。", "脫冠解带坐終日，花落石牀春自如。"]'),
('3b889699-b15e-4c5c-ad02-438969e2acc2','奉同運使陳殿丞惜洛陽牡丹爲霜風所損','司馬光','宋','宋诗','song-poetry','','[]','名花多種欲紛敷，一夕霜風非所虞。',64,'全唐诗/poet.song.30000.json','["名花多種欲紛敷，一夕霜風非所虞。", "節物偶然何足道，人情遺恨不能無。", "飄颻健筆詩千首，惆悵東風酒百壺。", "縱使前春滿朱檻，使車那復滯西都。"]'),
('2e3db9b7-dd35-481b-85df-66d5212c77dc','又和惜春謠','司馬光','宋','宋诗','song-poetry','','[]','朝來風雨歇，春意漠然收。',96,'全唐诗/poet.song.30000.json','["朝來風雨歇，春意漠然收。", "去我不辭訣，憑誰能借留。", "杓星漸西轉，洛水自東流。", "曲渚撤華幄，芳園罷彩毬。", "雉鳴坵麥秀，蠶起野桑柔。", "亂絮天涯滿，晴陽草際浮。", "已嗟心緒減，况復鬢絲稠。", "賴聽新翻曲，非爲負勝遊。"]'),
('8a50ea6a-81fe-4a86-8bf5-60fc70249755','還陳殿丞原人論','司馬光','宋','宋诗','song-poetry','','[]','品物芸芸遊太虚，不知誰氏宰洪爐。',64,'全唐诗/poet.song.30000.json','["品物芸芸遊太虚，不知誰氏宰洪爐。", "一株花落分榮辱，萬竅風號見有無。", "覺後共占猶是夢，衣中所得亦非珠。", "何如鼓瑟浴沂水，春服成時詠舞雩。"]'),
('8ecbaec7-7cb0-431e-ad41-22b60df22e70','和王秀才以光始自陜右遊山歸復將登少室爲詩見寄','司馬光','宋','宋诗','song-poetry','','[]','瘦馬飄颻屢往還，疲勞專爲訪名山。',64,'全唐诗/poet.song.30000.json','["瘦馬飄颻屢往還，疲勞專爲訪名山。", "須知筋力行將老，漸恐峰巒不可攀。", "蠟屐早能尋勝概，彈冠悔更落塵寰。", "幸依賢者爲東道，大得逍遙水石間。"]'),
('b2c26fc3-f673-485b-bd9f-0a5b54ee610e','和景仁西湖泛舟','司馬光','宋','宋诗','song-poetry','','["\u897f\u6e56"]','滿船歌吹拂春灣，天外晴霞水底斑。',64,'全唐诗/poet.song.30000.json','["滿船歌吹拂春灣，天外晴霞水底斑。", "誰信飛觴臨綺席，獨能回首望青山。", "東門車馬匆匆别，西洛風煙寂寂閑。", "疊石溪頭應更好，却輸野叟坐林間。"]'),
('dde73e0b-e492-4a4f-a5ad-83d2d8477131','新買疊石溪莊再用前韻招景仁','司馬光','宋','宋诗','song-poetry','','[]','一溪清水珮聲寒，兩岸莓苔錦繡斑。',64,'全唐诗/poet.song.30000.json','["一溪清水珮聲寒，兩岸莓苔錦繡斑。", "三徑誰來卜鄰舍，千峰我已作家山。", "鹿裘藜杖偏宜老，紫陌紅塵不稱閑。", "早挈琴書遠相就，放歌爛醉白雲間。"]'),
('51d9ecef-b259-4bb5-a961-33377beaa81a','戲書宋子才止足堂','司馬光','宋','宋诗','song-poetry','','[]','舉世戀榮祿，夜行無乃勞。',48,'全唐诗/poet.song.30000.json','["舉世戀榮祿，夜行無乃勞。", "獨君年未至，止足一何高。", "矮製烏紗帽，寛裁白氎袍。", "華榱坐終日，閑按紫檀槽。"]'),
('bd2ff130-752c-48c0-96ff-8049620d685c','寄題宇文中允所居','司馬光','宋','宋诗','song-poetry','','[]','孤宦行直道，栖栖良可悲。',48,'全唐诗/poet.song.30000.json','["孤宦行直道，栖栖良可悲。", "誰能拂衣去，不待掛冠期。", "經史乃吾友，雲山爲已知。", "世間青紫貴，盡付兩佳兒。"]'),
('80895d63-02ad-4707-95e2-9f5c24cff5fd','貽夸者','司馬光','宋','宋诗','song-poetry','','[]','我樂非君樂，君憂非我憂。',24,'全唐诗/poet.song.30000.json','["我樂非君樂，君憂非我憂。", "蓬蒿與溟渤，終老不同遊。"]'),
('02c1825c-e62d-41e6-9793-cdecabdd169d','春遊','司馬光','宋','宋诗','song-poetry','','[]','人物競紛華，驪駒逐鈿車。',24,'全唐诗/poet.song.30000.json','["人物競紛華，驪駒逐鈿車。", "此時松與柏，不及道傍花。"]'),
('e1e53b0f-0cc2-4293-a2eb-a2e8e5842c6d','和潞公遊天章楚諫議園宅','司馬光','宋','宋诗','song-poetry','','[]','名卿新治第，上宰舊連墻。',96,'全唐诗/poet.song.30000.json','["名卿新治第，上宰舊連墻。", "槐蔭青青葉，星鄰兩兩光。", "林花裂錦狹，門路築沙長。", "共引庭間水，交生壁外篁。", "魚窺薦琴石，螢散讀書牀。", "玉帳方懷遠，松齋欲就荒。", "旌幢今少憩，蘭蕙不徒芳。", "早晚平狼望，同來舉壽觴。"]'),
('339dabf9-bf0d-4958-9ea0-eac53710527f','還張景昱景昌秀才兄弟詩卷','司馬光','宋','宋诗','song-poetry','','[]','韡韡新詩卷，青春映棣華。',48,'全唐诗/poet.song.30000.json','["韡韡新詩卷，青春映棣華。", "機雲今繼美，載協舊承家。", "幸託仁人里，時回長者車。", "白虹光亂眼，何敢議瑜瑕。"]'),
('df3c4cbc-9f61-4e86-bf77-75b53d02b75b','寄題張著作善頌堂','司馬光','宋','宋诗','song-poetry','','[]','玉壘老先生，逍遙樂太平。',72,'全唐诗/poet.song.30000.json','["玉壘老先生，逍遙樂太平。", "門闌百客盛，冠蓋一鄉榮。", "國族招邀近，堂皇指顧成。", "江山對平遠，圖史散縱横。", "止水中心適，秋毫物外輕。", "鯉庭新露冕，閭巷不須驚。"]'),
('f450b941-398d-4538-a7b1-44c13d16230a','和宇文公南塗中見寄','司馬光','宋','宋诗','song-poetry','','[]','騘馬烏紗遊洛塵，未能全得自由身。',64,'全唐诗/poet.song.30000.json','["騘馬烏紗遊洛塵，未能全得自由身。", "深慚白首戀微祿，不向青山爲散人。", "斥鷃卑飛聊取適，冥鴻高舉益難親。", "蜀都迢遞千餘里，徒誦新詩妙入神。"]'),
('7566e140-2842-4f0e-b3d7-7f2b9f0519b1','酬張二十五秀才南園遣意','司馬光','宋','宋诗','song-poetry','','[]','花卉日相續，朝昏興寄新。',48,'全唐诗/poet.song.30000.json','["花卉日相續，朝昏興寄新。", "露荷香入坐，風竹净無塵。", "嘯詠皆羣從，喧囂遠四鄰。", "須知軒冕客，富貴不關身。"]'),
('492d5e3f-98bd-43f0-8795-933dcf0314d2','酬張三十秀才見贈','司馬光','宋','宋诗','song-poetry','','[]','樸學居人後，清塗忝衆先。',48,'全唐诗/poet.song.30000.json','["樸學居人後，清塗忝衆先。", "瓠因無用棄，木爲不才全。", "比得林泉趣，仍依邑里賢。", "自慚頭半白，方解賦歸田。"]'),
('1e96a076-4145-4fd6-84a2-f0af9f696498','八月十五日夜陪留守宣徽登西樓值雨待月久不見','司馬光','宋','宋诗','song-poetry','','[]','經歳侍佳節，無如陰靄何。',48,'全唐诗/poet.song.30000.json','["經歳侍佳節，無如陰靄何。", "果然時雨足，安用月華多。", "未免銀缸進，空聞玉漏過。", "庾公興不淺，久爲駐鳴珂。"]'),
('4f63d7f1-1889-4d33-aebd-71f430911897','秋雨新霽遊水北馬上偶成','司馬光','宋','宋诗','song-poetry','','[]','秋色與秋聲，蕭然滿洛城。',48,'全唐诗/poet.song.30000.json','["秋色與秋聲，蕭然滿洛城。", "未霜林葉赤，新雨野風清。", "水氣侵肌冷，嵐光刮眼明。", "誰云景如畫，但恐畫難成。"]'),
('49f9bf8c-a370-461c-9294-878230b21efa','運使虞部按行洛西諸縣因遊所過名山有詩百餘首合爲一編蒙賜寵示俾之繼作一首','司馬光','宋','宋诗','song-poetry','','[]','屬城窮僻地，攬轡徧周流。',48,'全唐诗/poet.song.30000.json','["屬城窮僻地，攬轡徧周流。", "弊政已更化，名山不廢遊。", "鳴騶留谷口，輕屐歷巖幽。", "聚看官儀者，相扶半白頭。"]'),
('56137fe3-1c2b-499b-9a2d-242019c9c5d9','呂宣徽挽歌二首  其一','司馬光','宋','宋诗','song-poetry','','[]','奕世台衡貴，盈門紱冕榮。',48,'全唐诗/poet.song.30000.json','["奕世台衡貴，盈門紱冕榮。", "遐方流惠化，殊俗讋威聲。", "宥密資忠力，安平寄老成。", "遽騎箕尾去，何以慰蒼生。"]'),
('8af179ec-743d-4098-8987-ea92e2f63b5e','呂宣徽挽歌二首  其二','司馬光','宋','宋诗','song-poetry','','[]','維嶽人皆仰，長城衆所依。',48,'全唐诗/poet.song.30000.json','["維嶽人皆仰，長城衆所依。", "遠猷方克壯，昭世忽長違。", "象設儼如在，英靈窅不歸。", "唯應令名久，竹素藹餘輝。"]'),
('064f9f3e-a491-4f05-8d68-53ebf7b19368','和君貺暮秋四日登石家寺閣曉泛洛舟 登閣','司馬光','宋','宋诗','song-poetry','','[]','嬉遊乘曉霽，登覽犯秋寒。',48,'全唐诗/poet.song.30000.json','["嬉遊乘曉霽，登覽犯秋寒。", "不出埃塵外，安知在壤寛。", "宮前斷山碧，林表落霞丹。", "欲下惜佳趣，相留更倚欄。"]'),
('b82a1dc1-4696-45f0-ac64-abc37b2124fd','和君貺暮秋四日登石家寺閣曉泛洛舟 泛舟','司馬光','宋','宋诗','song-poetry','','[]','葉下宮槐老，雲飛洛浦秋。',96,'全唐诗/poet.song.30000.json','["葉下宮槐老，雲飛洛浦秋。", "復陪元禮棹，却望仲宣樓。", "曲岸迷頻轉，遙山碎不流。", "夷猶聊寓賞，浩蕩得忘憂。", "晨出露漸徑，昏歸月滿舟。", "星河散寥廓，珠貝映汀洲。", "林館回車入，壺觴秉燭遊。", "山公興未盡，徒御且番休。"]'),
('a8f67dbd-a21f-41fc-a10b-49f95bcedf2c','又和六日四老會','司馬光','宋','宋诗','song-poetry','','[]','萸房迎令節，菊蘂入芳筵。',48,'全唐诗/poet.song.30000.json','["萸房迎令節，菊蘂入芳筵。", "華燭初長夜，清霜未冷天。", "悲風咽横吹，驟雨送繁絃。", "聊附鄒枚客，敢希園綺賢。"]'),
('7492413c-8e07-44d8-a882-3f4ab9633f50','和王少卿十日與留臺國子監崇福宮諸官赴王尹賞菊之會','司馬光','宋','宋诗','song-poetry','','[]','儒衣武弁聚華軒，盡是西都冷落官。',64,'全唐诗/poet.song.30000.json','["儒衣武弁聚華軒，盡是西都冷落官。", "莫歎黄花過佳節，且將素髪共清歡。", "紅牙板急絃聲咽，白玉舟横酒量寛。", "青眼主公情不薄，一如省闥要人看。"]'),
('a72e7b41-6cf6-42c0-a3d3-d9d3a6ba401d','和白都官見贈','司馬光','宋','宋诗','song-poetry','','[]','齒疏鬢白兩眸昏，萬事無堪老病身。',64,'全唐诗/poet.song.30000.json','["齒疏鬢白兩眸昏，萬事無堪老病身。", "脫粟猶霑太倉祿，法官仍忝外臺臣。", "直緣迂僻求閑地，豈是孤高慕古人。", "英俊滿朝皆稷契，太山何少一飛塵。"]'),
('7543760c-483f-4b89-a31e-4fddc62b16a7','送白都官歸長安','司馬光','宋','宋诗','song-poetry','','[]','丈夫那肯浪低眉，薄宦空添鬢裏絲。',64,'全唐诗/poet.song.30000.json','["丈夫那肯浪低眉，薄宦空添鬢裏絲。", "瀘水歸来山浩蕩，都門辭去菊離披。", "黄雞白酒五陵樂，杜曲樊川九糓宜。", "復見夫君行直道，崆峒氣俗未應衰。"]'),
('bc43e51f-d78a-47de-a377-295b6deae9d2','送雷章秘丞知芮城','司馬光','宋','宋诗','song-poetry','','[]','西伯昔斷訟，令名存迄今。',48,'全唐诗/poet.song.30000.json','["西伯昔斷訟，令名存迄今。", "南臨大河曲，北倚首陽岑。", "俗被聖賢化，人多禮讓心。", "夫君老經術，終日想鳴琴。"]'),
('0a8c5441-ff21-4740-880f-746862066436','酬邵堯夫見示安樂窩中打乖吟','司馬光','宋','宋诗','song-poetry','','[]','安樂窩中自在身，猶嫌名字落紅塵。',64,'全唐诗/poet.song.30000.json','["安樂窩中自在身，猶嫌名字落紅塵。", "醉吟終日不知老，經史滿堂誰道貧。", "長掩柴荆避寒暑，只將花卉記冬春。", "料非空處打乖客，乃是清朝避世人。"]'),
('9a2f75e5-0d6d-4bfc-816b-b29cfddd915e','和邠守宋度支來卜居與南園爲鄰','司馬光','宋','宋诗','song-poetry','','[]','弱冠交遊鬢髪蒼，飽諳官况好深藏。',64,'全唐诗/poet.song.30000.json','["弱冠交遊鬢髪蒼，飽諳官况好深藏。", "閑居共買一壥地，盡老常依數仞墻。", "雖喜卜鄰同晏子，尚慚推宅異周郎。", "何時税此憑熊駕，倚仗相迎立路傍。"]'),
('51cbe46d-0a56-405f-b9cc-ba53e903618c','和張文裕初寒十首  其一','司馬光','宋','宋诗','song-poetry','','[]','何處初寒好，初寒郟鄏城。',48,'全唐诗/poet.song.30000.json','["何處初寒好，初寒郟鄏城。", "垂紳多俊彦，列第盡公卿。", "裘馬過從盛，門闌灑掃清。", "誰家擁獸炭，盡日管絃聲。"]'),
('55638285-eaf3-4f0a-8dc4-b3862c4a7a28','和張文裕初寒十首  其二','司馬光','宋','宋诗','song-poetry','','[]','何處初寒好，初寒洛汭宮。',48,'全唐诗/poet.song.30000.json','["何處初寒好，初寒洛汭宮。", "翠華雖脉脉，佳氣自葱葱。", "闕角月華白，苑墻霜葉紅。", "都人心望幸，注目不離東。"]'),
('f13d992e-2cdc-48f6-a2d6-6b06cde53c7e','和張文裕初寒十首  其三','司馬光','宋','宋诗','song-poetry','','[]','何處初寒好，初寒洛水橋。',48,'全唐诗/poet.song.30000.json','["何處初寒好，初寒洛水橋。", "沙痕水清淺，風葉柳蕭條。", "關塞長塗直，嵩丘倒影遙。", "鳳樓雖在北，車馬不塵囂。"]'),
('1cd44250-742e-4553-b3bc-730aeab28d6e','和張文裕初寒十首  其四','司馬光','宋','宋诗','song-poetry','','[]','何處初寒好，初寒太室山。',48,'全唐诗/poet.song.30000.json','["何處初寒好，初寒太室山。", "晴空煙澹泊，返照雪孱顔。", "極目鴈稍沒，無心雲自還。", "猶餘拜表累，不得坐松間。"]'),
('697d1195-4c83-46a8-aa2c-ee7e40536d55','和張文裕初寒十首  其五','司馬光','宋','宋诗','song-poetry','','[]','何處初寒好，初寒禹鑿門。',48,'全唐诗/poet.song.30000.json','["何處初寒好，初寒禹鑿門。", "遙天露崖口，輕浪漱山根。", "萬佛龕苔老，一燈林靄昏。", "漁梁杳相望，石瀨夜聲喧。"]'),
('965c1bf0-5426-45f2-a964-c381feb4054e','和張文裕初寒十首  其六','司馬光','宋','宋诗','song-poetry','','[]','何處初寒好，初寒噴玉泉。',48,'全唐诗/poet.song.30000.json','["何處初寒好，初寒噴玉泉。", "折冰流谷口，飛溜落雲邊。", "雀噪聚林杪，樵歌下石巔。", "尋幽不思返，坐嘯夕陽偏。"]'),
('0b7256cc-3efa-4920-95ec-8f2f43b05e47','和張文裕初寒十首  其七','司馬光','宋','宋诗','song-poetry','','[]','何處初寒好，初寒疊石溪。',48,'全唐诗/poet.song.30000.json','["何處初寒好，初寒疊石溪。", "山斜改昏曉，路曲失東西。", "拾栗走村稚，鑿垣巢乳雞。", "我來閑擁褐，曝背草簷低。"]'),
('5d654381-68c4-462a-94d6-a644bd98d557','和張文裕初寒十首  其八','司馬光','宋','宋诗','song-poetry','','[]','何處初寒好，初寒肅政臺。',48,'全唐诗/poet.song.30000.json','["何處初寒好，初寒肅政臺。", "官閑免簿領，門静少塵埃。", "天借風霜氣，人無鷹隼猜。", "庭荒餘老柏，尚有夕烏來。"]'),
('49e47845-91ca-463a-b39d-a31dfa459869','和張文裕初寒十首  其九','司馬光','宋','宋诗','song-poetry','','[]','何處初寒好，初寒遊弈園。',48,'全唐诗/poet.song.30000.json','["何處初寒好，初寒遊弈園。", "林間葉未盡，籬底菊猶存。", "結竹爲庵小，開爐構火温。", "誰言處城市，岑寂似丘樊。"]'),
('cde1c310-778d-4a2a-a0da-aa1b01658947','和張文裕初寒十首  其一○','司馬光','宋','宋诗','song-poetry','','[]','何處初寒好，初寒福善居。',48,'全唐诗/poet.song.30000.json','["何處初寒好，初寒福善居。", "長宵對燈火，滿室聚詩書。", "暫息登山屐，休脂下澤車。", "所安容膝地，何必更多餘。"]'),
('f847cc58-1a7e-4a3d-823a-8416567db59a','寄題刁景純藏春塢','司馬光','宋','宋诗','song-poetry','','[]','藏春在何許，鬰鬰萬松林。',48,'全唐诗/poet.song.30000.json','["藏春在何許，鬰鬰萬松林。", "永日門闌静，東風花木深。", "主公今素髪，野服遂初心。", "時與鄉人醉，高歌散百金。"]'),
('8f62bfa0-2569-47d2-aac6-354fdf2e2db9','和君貺少林寺','司馬光','宋','宋诗','song-poetry','','[]','達磨自云傳佛心，緒言迷世到於今。',64,'全唐诗/poet.song.30000.json','["達磨自云傳佛心，緒言迷世到於今。", "既攜隻履歸西域，安得遺靈在少林。", "孤月正明高殿冷，清風不斷老松深。", "謝公自愛山泉美，肯爲幽禪此訪尋。"]'),
('3bae48fc-15eb-4411-9750-2916c5b201a4','又和嶽祠謝雪題嶽寺平法華庵','司馬光','宋','宋诗','song-poetry','','[]','宴坐幾何年，庭蕪與砌連。',48,'全唐诗/poet.song.30000.json','["宴坐幾何年，庭蕪與砌連。", "焚修真諦苦，功行得無圓。", "闕里詩三百，賴鄉文五千。", "厭煩猶不讀，何况淤泥蓮。"]'),
('7c3e9591-64a5-4946-aff1-02368e6176ed','望日示康廣宏','司馬光','宋','宋诗','song-poetry','','[]','清晨三綠袍，羅拜北堂高。',48,'全唐诗/poet.song.30000.json','["清晨三綠袍，羅拜北堂高。", "積善因先烈，餘光及爾曹。", "勿矜從事早，當念起家勞。", "修立皆由已，何人可佩刀。"]'),
('daab84ed-bf23-4614-a84e-a3cf367296e8','和君貺題潞公東莊','司馬光','宋','宋诗','song-poetry','','[]','嵩峰遠疊千重雪，伊浦低臨一片天。',64,'全唐诗/poet.song.30000.json','["嵩峰遠疊千重雪，伊浦低臨一片天。", "百頃平皋連别館，兩行疏柳拂清泉。", "國須柱石扶丕構，人待樓航濟巨川。", "蕭相方如左右手，且於窮僻置閑田。"]'),
('06adc8c2-adf9-4631-82f4-0e8f33d0bda2','和君貺任少師園賞梅','司馬光','宋','宋诗','song-poetry','','[]','寒壓春頭草未芽，喜聞置酒賞新葩。',64,'全唐诗/poet.song.30000.json','["寒壓春頭草未芽，喜聞置酒賞新葩。", "官儀赫奕三川守，野意蕭疏四皓家。", "不用管絃妨淡泊，豈容桃李競繁華。", "昏鴉散亂傳呼出，歸路林間燭影斜。"]'),
('d8689def-fcd5-472a-92a1-4857010ac456','別韻一首','司馬光','宋','宋诗','song-poetry','','[]','風日雖寒晝景長，探春遠訪白蓮莊。',64,'全唐诗/poet.song.30000.json','["風日雖寒晝景長，探春遠訪白蓮莊。", "岸冰猶在水先綠，柳葉未生條已黄。", "老木根侵苔徑窄，新梅花入酒卮香。", "天真不必人修飾，得趣勿嫌臺館荒。"]'),
('8c7657bb-4130-476d-a30e-aa340486e653','又和開叔','司馬光','宋','宋诗','song-poetry','','[]','寒梅犯雪榮，大隱久專名。',48,'全唐诗/poet.song.30000.json','["寒梅犯雪榮，大隱久專名。", "異種生江渚，何年到洛城。", "色如虛室白，香似主人清。", "響使吳兒見，不思菰菜羮。"]'),
('5f61c379-0444-450c-8524-89594072bcc7','和公廙喜雪','司馬光','宋','宋诗','song-poetry','','[]','曏來河洛久愆陽，禱祀徒勞罄肅莊。',64,'全唐诗/poet.song.30000.json','["曏來河洛久愆陽，禱祀徒勞罄肅莊。", "林雪飛花欣暫白，麥田濡葉未全黄。", "城中稍覺桑薪貴，村外時聞社甕香。", "八使孜孜憫惸獨，斯民那復畏凶荒。"]'),
('e77a4240-b3a8-4491-b52f-4d2cc83f9833','和史誠之謝送張明叔梅臺三種梅花','司馬光','宋','宋诗','song-poetry','','[]','别後相驚兩鬢霜，可憐梅蘂爲誰芳。',64,'全唐诗/poet.song.30000.json','["别後相驚兩鬢霜，可憐梅蘂爲誰芳。", "臺頭日暖分三色，林下風清共一香。", "正爛漫時遊不足，忽離披去樂難常。", "慇懃手折遙相贈，不欲花前獨舉觴。"]'),
('1984c1bc-7942-448f-a74a-faa56829f875','早春寄景仁  其一','司馬光','宋','宋诗','song-poetry','','[]','辛夷花爛開，故人殊未來。',24,'全唐诗/poet.song.30000.json','["辛夷花爛開，故人殊未來。", "愁看柳漸綠，忍更折殘梅。"]'),
('a1a84db5-21bf-4fc1-a5af-aa7f7915f982','早春寄景仁  其二','司馬光','宋','宋诗','song-poetry','','[]','疊石溪上春，茅茨卜築新。',24,'全唐诗/poet.song.30000.json','["疊石溪上春，茅茨卜築新。", "前言如不踐，山蟬又笑人。"]'),
('ebd1aa99-6ae2-401d-a3aa-d57b33525b80','和君貺宴張氏梅臺','司馬光','宋','宋诗','song-poetry','','[]','京洛春何早，憑高種嶺梅。',120,'全唐诗/poet.song.30000.json','["京洛春何早，憑高種嶺梅。", "紛披百株密，爛漫一朝開。", "青女工黏綴，霜娥巧剪裁。", "崑山雲滿谷，蓬堵浪成堆。", "勢擁樽前合，香從席下來。", "蜺旌羾天起，練甲洗兵回。", "不使光風散，曾無夜色催。", "人稠衣馥郁，地狹舞徘徊。", "民服召公化，時推何遜才。", "淹留文酒樂，璧月上瑤臺。"]'),
('e96ded91-1497-43c5-af97-8e63330958ae','看花四絕句  其一','司馬光','宋','宋诗','song-poetry','','[]','洛陽相望盡名園，牆外花勝牆裏看。',32,'全唐诗/poet.song.30000.json','["洛陽相望盡名園，牆外花勝牆裏看。", "手摘青梅共挼酒，何須一一具杯盤。"]'),
('da26e7d8-64ba-42eb-9bc6-607ccd459aa1','看花四絕句  其二','司馬光','宋','宋诗','song-poetry','','[]','洛陽相識盡名流，騎馬遊勝下馬遊。',32,'全唐诗/poet.song.30000.json','["洛陽相識盡名流，騎馬遊勝下馬遊。", "乘興東西無不到，但逢青眼即淹留。"]'),
('357a3b1d-30b2-43ae-ac2b-cd9dca5f1a12','看花四絕句  其三','司馬光','宋','宋诗','song-poetry','','[]','洛陽春日最繁華，紅綠陰中十萬家。',32,'全唐诗/poet.song.30000.json','["洛陽春日最繁華，紅綠陰中十萬家。", "誰道羣花如錦繡，人將錦繡學羣花。"]'),
('aaf53b8f-d567-46e5-adfc-3cc480ce0253','看花四絕句  其四','司馬光','宋','宋诗','song-poetry','','[]','南園桃李近方栽，澆水未乾花已開。',32,'全唐诗/poet.song.30000.json','["南園桃李近方栽，澆水未乾花已開。", "山果野蔬随分有，交遊不厭但頻來。"]'),
('8dacb72b-656b-41cd-a391-2b62efb717b3','和君貺清明與上巳同日泛舟洛川十韻','司馬光','宋','宋诗','song-poetry','','[]','繁華兩佳節，邂逅適同時。',120,'全唐诗/poet.song.30000.json','["繁華兩佳節，邂逅適同時。", "雅俗共爲樂，風光如有期。", "曉煙新里巷，春服滿津涯。", "已散漢宮燭，仍浮洛水卮。", "占花分設席，愛柳就張帷。", "華轂爭門去，輕簾夾路垂。", "三川雲錦爛，四座玉山欹。", "疊鼓傳遙吹，輕橈破直漪。", "清談何衮衮，和氣益熙熙。", "想見周南俗，當年播逸詩。"]'),
('b849d93f-d4e5-4088-90df-9906acf46523','和君貺寄河陽侍中牡丹','司馬光','宋','宋诗','song-poetry','','[]','真宰無私嫗煦同，洛花何事占全功。',64,'全唐诗/poet.song.30000.json','["真宰無私嫗煦同，洛花何事占全功。", "山河勢勝帝王宅，寒暑氣和天地中。", "盡日玉盤堆秀色，滿城繡轂走香風。", "謝公高興看春物，倍憶清伊與碧嵩。"]'),
('3c2ebc64-ff52-4c89-abed-2e984609fc3a','又和安國寺及諸園賞牡丹','司馬光','宋','宋诗','song-poetry','','[]','洛邑牡丹天下最，西南土沃得春多。',64,'全唐诗/poet.song.30000.json','["洛邑牡丹天下最，西南土沃得春多。", "一城奇品推安國，四面名園接月波。", "山相著書稱上藥，翰林弄筆作新歌。", "人間朱粉無因學，浪把菱花百徧磨。"]'),
('ce173b2b-b06d-4b3b-901c-3b65b2c62701','送酒與邵堯夫因戲之','司馬光','宋','宋诗','song-poetry','','[]','林下雖無憂可消，許由聞說掛空瓢。',32,'全唐诗/poet.song.30000.json','["林下雖無憂可消，許由聞說掛空瓢。", "請君呼取孟光飲，共插花枝煮藥苗。"]'),
('c2d1aa50-f783-419c-8763-d8439a58efbf','酬仲通初提舉崇福宮見寄','司馬光','宋','宋诗','song-poetry','','[]','富壽安民舊學違，符移擁筆素心非。',64,'全唐诗/poet.song.30000.json','["富壽安民舊學違，符移擁筆素心非。", "青雲有路那足顧，白髪滿頭胡不歸。", "永日杜門無俗客，臨風隱几得天機。", "西山爽氣秋應好，恨不相從上翠微。"]'),
('75d14449-1aed-4991-bfae-01c4b6be53fd','魏忠獻公挽歌辭三首  其一','司馬光','宋','宋诗','song-poetry','','[]','瀛海訏謨定，宗祧指顧安。',48,'全唐诗/poet.song.30000.json','["瀛海訏謨定，宗祧指顧安。", "鴻勛柱石壯，勁節雪霜寒。", "翼亮三朝久，初終一德完。", "如何未黄髪，壟栢已丸丸。"]'),
('509bbc62-d81c-43c9-b0da-2bd2392f2e44','魏忠獻公挽歌辭三首  其二','司馬光','宋','宋诗','song-poetry','','[]','愛物威容悴，憂公宿疹加。',48,'全唐诗/poet.song.30000.json','["愛物威容悴，憂公宿疹加。", "孤忠貫白日，美志掩丹霞。", "行路皆惆悵，聞風悉嘆嗟。", "英靈覲宗祖，猶想佑皇家。"]'),
('46bec292-c29f-42ac-b538-c73835f01a06','魏忠獻公挽歌辭三首  其三','司馬光','宋','宋诗','song-poetry','','[]','惻怛動旒扆，鴻臚葬老臣。',48,'全唐诗/poet.song.30000.json','["惻怛動旒扆，鴻臚葬老臣。", "簫鐃震淦口，紼翣隘漳濱。", "久大英名在，哀榮異禮陳。", "豐碑紀遺烈，長泣鄴城人。"]'),
('15b1e6e6-e4dc-4f93-8ea6-8470b7b0db2d','酬君貺和景仁對酒見寄三首 上宣徽 其一','司馬光','宋','宋诗','song-poetry','','[]','懶拙無時用，耆朋獨我思。',48,'全唐诗/poet.song.30000.json','["懶拙無時用，耆朋獨我思。", "乘閑同把酒，道舊各成詩。", "高義刮眼膜，清風生鬢絲。", "方將激衰俗，賤子實何爲。"]'),
('21e9ea2b-2684-47a7-babb-79c0e9f603c0','酬君貺和景仁對酒見寄三首 上宣徽 其二','司馬光','宋','宋诗','song-poetry','','[]','北闕黄金印，西山白髪翁。',48,'全唐诗/poet.song.30000.json','["北闕黄金印，西山白髪翁。", "訏謨帝廷異，小築洛川同。", "晴野峰峰碧，霜林葉葉紅。", "無因侍樽席，惆悵又秋風。"]'),
('fc0c9b06-0561-4849-8778-f07939896037','酬君貺和景仁對酒見寄三首 上侍中','司馬光','宋','宋诗','song-poetry','','[]','何事掛冠客，至今留帝臺。',48,'全唐诗/poet.song.30000.json','["何事掛冠客，至今留帝臺。", "紅塵終可厭，青眼不長開。", "春路半消雪，寒枝初破梅。", "南園虚客席，灑掃望公來。"]'),
('d0b1129f-019d-4796-bdcc-38293bb8d48d','野軒','司馬光','宋','宋诗','song-poetry','','[]','黄雞白酒田間樂，藜杖葛巾林下風。',32,'全唐诗/poet.song.30000.json','["黄雞白酒田間樂，藜杖葛巾林下風。", "更若食芹仍暴背，野懷併在一軒中。"]'),
('e883822d-026e-49d8-befd-1aeba33f93dd','汙亭','司馬光','宋','宋诗','song-poetry','','[]','雜花亂種盤渦底，小屋深居鑑燧心。',32,'全唐诗/poet.song.30000.json','["雜花亂種盤渦底，小屋深居鑑燧心。", "朝市囂聲那得到，晨昏暑氣不能侵。"]'),
('8eebe1ef-5d10-4b17-9e96-40a294aaf486','藥軒','司馬光','宋','宋诗','song-poetry','','[]','雨餘條甲繞階生，往往桐君昔未名。',32,'全唐诗/poet.song.30000.json','["雨餘條甲繞階生，往往桐君昔未名。", "采貯不須勤暴篲，秋陽日日滿簷楹。"]'),
('fb016414-519e-4fc5-885c-3cde6f369ef8','晚暉亭','司馬光','宋','宋诗','song-poetry','','[]','俯臨城市厭諠譁，回顧園林景更加。',32,'全唐诗/poet.song.30000.json','["俯臨城市厭諠譁，回顧園林景更加。", "醉立斜陽頭似雪，往來誤認白公家。"]'),
('de420164-9aae-444f-b1e3-1f3ec49e5fa0','喜雨八韻呈明叔','司馬光','宋','宋诗','song-poetry','','[]','藴隆亦太甚，薈蔚不朝隮。',96,'全唐诗/poet.song.30000.json','["藴隆亦太甚，薈蔚不朝隮。", "直可憂秋廪，非徒病夏畦。", "民心或能徹，天造固難稽。", "黯淡雲纔蔟，滂沱日未西。", "衣襟坐來冷，城闕望中迷。", "園筍新梢活，庭蕉濕葉低。", "響從窗破紙，行喜屐生泥。", "昨旦煩相報，憑君謝竹雞。"]'),
('30444b34-f335-4047-b47c-276c27ac430b','六月十八日夜大暑','司馬光','宋','宋诗','song-poetry','','[]','老柳蜩螗噪，荒庭熠燿流。',48,'全唐诗/poet.song.30000.json','["老柳蜩螗噪，荒庭熠燿流。", "人情正苦暑，物怎已驚秋。", "月下濯寒水，風前梳白頭。", "如何夜半客，束带謁公侯。"]'),
('e65fc924-1163-4e47-8ef0-43183e5a6d0e','閑中有富貴','司馬光','宋','宋诗','song-poetry','','[]','閑中有富貴，迥與俗塵殊。',48,'全唐诗/poet.song.30000.json','["閑中有富貴，迥與俗塵殊。", "水浄齊紈展，花繁蜀錦紆。", "竹風寒扣玉，荷雨急跳珠。", "可笑公孫衍，酣歌誇丈夫。"]'),
('a0738d46-2ade-4b2c-8c37-509169036b2d','寄唐州吳辨叔二兄','司馬光','宋','宋诗','song-poetry','','[]','方城古稱險，遠在豫州南。',48,'全唐诗/poet.song.30000.json','["方城古稱險，遠在豫州南。", "近歳汙莱闢，新民秦晉參。", "當官誠近厚，獲譴亦無慚。", "但惜牆陰竹，歸轅幾日驂。"]'),
('1db4fddb-e692-4738-b6bf-14a0212d3844','自題寫真','司馬光','宋','宋诗','song-poetry','','[]','黄面霜鬚細瘦身，從来未識漫相親。',32,'全唐诗/poet.song.30000.json','["黄面霜鬚細瘦身，從来未識漫相親。", "居然不可市朝住，骨相天生林野人。"]'),
('4ff8280a-560a-4c84-8ee7-348ebe8d1f14','和安之久雨','司馬光','宋','宋诗','song-poetry','','[]','秋霖逢甲子，禾耳恐須生。',48,'全唐诗/poet.song.30000.json','["秋霖逢甲子，禾耳恐須生。", "流俗幸無驗，高田猶有成。", "潤唯藜莠得，爛與蕙蘭并。", "早晚浮雲豁，逍遙賦晚晴。"]'),
('b104b09b-0cad-4e06-a72e-8fa04a37b2b1','和復古小園書事','司馬光','宋','宋诗','song-poetry','','[]','飽食復閑眠，風清雨霽天。',48,'全唐诗/poet.song.30000.json','["飽食復閑眠，風清雨霽天。", "葉深時墜果，岸曲乍藏蓮。", "波面秋光浄，林梢夕照鮮。", "東家近亦富，滿地布苔錢。"]'),
('be8366e7-268d-4480-af61-631f277796ba','復古詩首句云獨步復静坐輙繼二章 獨步','司馬光','宋','宋诗','song-poetry','','[]','踽踽出東軒，徐徐步小園。',48,'全唐诗/poet.song.30000.json','["踽踽出東軒，徐徐步小園。", "何須從吏卒，亦不引兒孫。", "躡屐尋莎徑，攜筇撥水源。", "愁聞俗客到，唯說市朝喧。"]'),
('873bbc68-6f7e-4ab5-8800-afb866a40296','復古詩首句云獨步復静坐輙繼二章 靜坐','司馬光','宋','宋诗','song-poetry','','[]','一榻僅容膝，身心俱寂然。',48,'全唐诗/poet.song.30000.json','["一榻僅容膝，身心俱寂然。", "直緣知樂內，亦不爲安禪。", "棐几陳編掩，竹窗殘局捐。", "尚餘喧噪在，野鳥與林蟬。"]'),
('27a7ab0c-1569-42c9-9ebf-dd8905f9cb02','光詩首句云飽食復閑眠又成二章 飽食','司馬光','宋','宋诗','song-poetry','','[]','錢少何須萬，杯多不過三。',48,'全唐诗/poet.song.30000.json','["錢少何須萬，杯多不過三。", "龜腸本易足，熊掌詎宜貪。", "散步竹齋外，高吟柳徑南。", "此心無所用，脫粟亦深慚。"]'),
('1d2880e5-1c6f-4da6-a848-714e823cc5ed','光詩首句云飽食復閑眠又成二章 閑眠','司馬光','宋','宋诗','song-poetry','','[]','秋懷一事無，暑盡晝凉初。',48,'全唐诗/poet.song.30000.json','["秋懷一事無，暑盡晝凉初。", "竹戶静長閉，藜牀安有餘。", "逍遙化胡蝶，容易入華胥。", "天上多官府，神仙恐不如。"]'),
('59c25d04-46ce-4dfc-93fa-fa680caf0b38','寄題濟源李少卿園亭','司馬光','宋','宋诗','song-poetry','','[]','縣僻人事少，土肥風物殊。',48,'全唐诗/poet.song.30000.json','["縣僻人事少，土肥風物殊。", "杖刊靈壽木，輪裹溴梁蒲。", "竹不減淇水，花仍似洛都。", "主公眉雪白，遊覽未嘗扶。"]'),
('b18cbb0b-3e8f-4817-b718-9460d69b32a3','和明叔九日','司馬光','宋','宋诗','song-poetry','','[]','不奈衰鬚白，羞看朝鑑明。',48,'全唐诗/poet.song.30000.json','["不奈衰鬚白，羞看朝鑑明。", "聊憑佳節酒，強作少年情。", "雨冷弊裘薄，風高醉帽傾。", "如何不行樂，况復值秋成。"]'),
('0617df4a-ecf6-4063-ba77-d98fe27cf407','邵堯夫先生哀辭二首  其一','司馬光','宋','宋诗','song-poetry','','[]','菽藿一簞樂，蒿莱三畝寛。',48,'全唐诗/poet.song.30000.json','["菽藿一簞樂，蒿莱三畝寛。", "蒲輪不能起，甕牖有餘安。", "高節去圭角，久要敦歲寒。", "今朝郊外客，誰免涕汍瀾。"]'),
('ad763840-3d39-48de-ba13-89cf95fcd8d1','邵堯夫先生哀辭二首  其二','司馬光','宋','宋诗','song-poetry','','[]','慕德聞風久，論交傾蓋新。',48,'全唐诗/poet.song.30000.json','["慕德聞風久，論交傾蓋新。", "何須半面舊，不待一言親。", "講道切磋直，忘懷笑語真。", "重言蒙蹠實，佩服敢書紳。"]'),
('1446fb06-6d70-4d79-b160-6c2a71d7b405','閑居呈復古','司馬光','宋','宋诗','song-poetry','','[]','閑居雖懶放，未得便無營。',48,'全唐诗/poet.song.30000.json','["閑居雖懶放，未得便無營。", "伐木添山色，穿渠擘水聲。", "經霜收芋美，带雨接花成。", "前日鄰翁至，柴門掃葉迎。"]'),
('268a484e-4a5e-4926-ad1f-643d56be721f','和明叔遊白龍溪','司馬光','宋','宋诗','song-poetry','','[]','溪深荒徑微，尋勝不知疲。',48,'全唐诗/poet.song.30000.json','["溪深荒徑微，尋勝不知疲。", "寒月影隨馬，曉風冰滿髭。", "行歌被褐叟，聚戲拾薪兒。", "外野饒真趣，令人懷抱夷。"]'),
('d9bb486e-55b3-4195-9513-21604fdaac19','和景仁七十一偶成','司馬光','宋','宋诗','song-poetry','','[]','心地長閑爲己物，年華不住是天時。',32,'全唐诗/poet.song.30000.json','["心地長閑爲己物，年華不住是天時。", "當時海上乘槎客，維楫都無任所之。"]'),
('a6351c1d-1c4b-4801-9333-49dc4b23d74b','六十寄景仁','司馬光','宋','宋诗','song-poetry','','[]','從来好與天爭力，困竭方慚已力微。',32,'全唐诗/poet.song.30000.json','["從来好與天爭力，困竭方慚已力微。", "見事晚于蘧伯玉，今知五十九年非。"]'),
('3af2b10b-3211-4507-abbc-20ba15788dae','去春與景仁同至河陽謁晦叔館於府之後園既去晦叔名其館曰禮賢夢得作詩以紀其事光雖愧其名亦作詩以繼之','司馬光','宋','宋诗','song-poetry','','[]','蓬飛匏繫十餘年，並蔭華榱出偶然。',64,'全唐诗/poet.song.30000.json','["蓬飛匏繫十餘年，並蔭華榱出偶然。", "郭隗金臺雖見禮，華歆龍尾豈能賢。", "浮雲世味閑先薄，寒柏交情老更堅。", "明日河梁即分首，人生樂事信難全。"]'),
('afb6340c-c8b4-40d5-b1b6-1edbc4e1cd77','與樂道約會超化寺比至樂道以疾先歸塗中有詩見寄','司馬光','宋','宋诗','song-poetry','','[]','顛毛種種齒浮搖，屈指交遊漸寂寥。',64,'全唐诗/poet.song.30000.json','["顛毛種種齒浮搖，屈指交遊漸寂寥。", "時較半朝非是晚，路無數里不爲遙。", "子猷垂到復歸去，安道雖知未易邀。", "古寺徘徊久東望，青春雲日冷蕭蕭。"]'),
('f237046d-5fb6-4ca0-b098-ec95276d896a','和樂道再以詩見寄','司馬光','宋','宋诗','song-poetry','','[]','諫垣簪筆接英遊，今日華顛昔日憂。',64,'全唐诗/poet.song.30000.json','["諫垣簪筆接英遊，今日華顛昔日憂。", "邂逅升沈皆是命，逍遙出處本無愁。", "衡門不羡金門貴，藿食焉知肉食謀。", "溟海榆枋各安分，蓬莱未必勝嵩丘。"]'),
('47427bf9-54cd-4b53-adc8-d7db1e7461de','晚春病起呈擇之治臣','司馬光','宋','宋诗','song-poetry','','[]','風日正和柔，身輕喜病瘳。',48,'全唐诗/poet.song.30000.json','["風日正和柔，身輕喜病瘳。", "懶抛殘蠧簡，暖脫弊貂裘。", "值客開青眼，逢花忘白頭。", "家家好春色，何處可同遊。"]'),
('d904bb79-c49f-4944-b9b9-057d3123480e','次韻和復古春日五絕句  其一','司馬光','宋','宋诗','song-poetry','','[]','雪霜哀鬢拔還生，桃李新園長未成。',32,'全唐诗/poet.song.30000.json','["雪霜哀鬢拔還生，桃李新園長未成。", "五十尚能勝六十，今年又滅去年情。"]'),
('99121589-36e4-4834-9df7-140baaa815b3','次韻和復古春日五絕句  其二','司馬光','宋','宋诗','song-poetry','','[]','車如流水馬如龍，花市相逢咽不通。',32,'全唐诗/poet.song.30000.json','["車如流水馬如龍，花市相逢咽不通。", "獨閉柴荆老春色，任他陌上暮塵紅。"]'),
('87f9b2a0-8bab-41d0-9a66-59b9d1c0b324','次韻和復古春日五絕句  其三','司馬光','宋','宋诗','song-poetry','','[]','東城絲網蹴紅毬，北里瓊樓唱石州。',32,'全唐诗/poet.song.30000.json','["東城絲網蹴紅毬，北里瓊樓唱石州。", "堪笑迂儒竹齋裏，眼昏逼紙看蠅頭。"]'),
('4ed6601b-e752-4e53-bd6a-93595ff005bd','次韻和復古春日五絕句  其四','司馬光','宋','宋诗','song-poetry','','[]','家藏歌吹只西鄰，吹落梅花歌落塵。',32,'全唐诗/poet.song.30000.json','["家藏歌吹只西鄰，吹落梅花歌落塵。", "百葉桃開深院裏，輸他白髪有情人。"]'),
('697f109e-62c4-4b2c-b69f-2281a29dd5d9','次韻和復古春日五絕句  其五','司馬光','宋','宋诗','song-poetry','','[]','燕拂人衣絮撲頭，紅英滿地綠陰稠。',32,'全唐诗/poet.song.30000.json','["燕拂人衣絮撲頭，紅英滿地綠陰稠。", "殘春舉目多愁思，休上迢迢百尺樓。"]'),
('134c9d22-174d-4943-8868-d32f5385dac0','酬宋叔達卜居洛城見寄','司馬光','宋','宋诗','song-poetry','','[]','離羣四十一春風，縱有相逢似夢中。',64,'全唐诗/poet.song.30000.json','["離羣四十一春風，縱有相逢似夢中。", "幸得相逢作鄰舍，但嗟彼此是衰翁。", "漢文前席人將去，庾信誅茅橐未充。", "悵望金堤碧蕪闊，杖藜攜手幾時同。"]'),
('ac9d3fab-f68e-486f-8ea0-dda650c100c1','和王安之題獨樂園','司馬光','宋','宋诗','song-poetry','','[]','草濃初過雨，林静遠含煙。',48,'全唐诗/poet.song.30000.json','["草濃初過雨，林静遠含煙。", "燕引新飛鷇，荷承半墜蓮。", "朋來惟有月，山見不須錢。", "誰與同其樂，壺中濁酒賢。"]');
